INSERT INTO verb_details (verb, label, particles, sections) VALUES
  ('act', 'Act', '["on / upon","up","out","for","against"]'::jsonb, '[{"particle":"on / upon","storageKeyPrefix":"actOn","meanings":[{"definition":"To take action because of information, advice, or instructions.","example":"The manager decided to act on the feedback she received from the team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager acting on team feedback"},{"definition":"To have an effect on something (often used in medicine or science).","example":"This type of medication acts on the nervous system to reduce pain.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Medication affecting the nervous system"}]},{"particle":"up","storageKeyPrefix":"actUp","meanings":[{"definition":"To misbehave or cause trouble (usually referring to children).","example":"The children were bored, so they started acting up in the classroom.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Children misbehaving in a classroom"},{"definition":"To malfunction, stop working properly, or cause physical pain (referring to machines or body parts).","example":"My old laptop is acting up again; the screen keeps freezing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A laptop with a frozen screen"}]},{"particle":"out","storageKeyPrefix":"actOut","meanings":[{"definition":"To perform a story, scene, or situation using actions and words.","example":"During the workshop, the developers acted out the user''s journey to understand the software requirements better.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers acting out a user journey in a workshop"},{"definition":"To express negative emotions or stress through disruptive or bad behavior, often because the person cannot talk about their feelings.","example":"The teenager was acting out at school because of his parents'' divorce.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A teenager acting out due to emotional distress"}]},{"particle":"for","storageKeyPrefix":"actFor","meanings":[{"definition":"To represent someone else or do something on their behalf (especially in legal or business situations).","example":"The lawyer was hired to act for the CEO during the contract negotiations.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A lawyer representing a CEO in negotiations"}]},{"particle":"against","storageKeyPrefix":"actAgainst","meanings":[{"definition":"To do something that opposes, harms, or violates a person, rule, or interest.","example":"By sharing confidential data, the employee acted against the company''s core policies.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An employee acting against company policies"}]}]'::jsonb),
  ('ask', 'Ask', '["about","after","around / round","away","back","down","for","in","into","off","out","over","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"askAbout","meanings":[{"definition":"To try to get information about a subject or a person.","example":"I need to call the hotel to ask about their parking rules.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking about hotel parking rules"}]},{"particle":"after","storageKeyPrefix":"askAfter","meanings":[{"definition":"To ask for news about someone, usually concerning their health or how their life is going.","example":"I saw your old manager yesterday, and he asked after you.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking after someone"}]},{"particle":"around / round","storageKeyPrefix":"askAround","meanings":[{"definition":"To ask many different people the same question, usually to find information or get help.","example":"I don''t know a good plumber, but I will ask around the office for you.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking around the office"},{"definition":"To invite someone to your home (British English — usually \"ask round\").","example":"We should ask the new neighbors round for a cup of coffee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Inviting neighbors for coffee"}]},{"particle":"away","storageKeyPrefix":"askAway","meanings":[{"definition":"An expression used to tell someone that they can start asking their questions.","example":"If anyone has questions about the new software update, ask away!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Encouraging someone to ask questions"}]},{"particle":"back","storageKeyPrefix":"askBack","meanings":[{"definition":"To invite someone to return to a place (like your house or an event).","example":"We had a great time with them, so we will definitely ask them back soon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Inviting someone to return"},{"definition":"To invite someone to return for a second job interview.","example":"The first interview went very well, so they asked her back for a second one.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being invited back for a second interview"}]},{"particle":"down","storageKeyPrefix":"askDown","meanings":[{"definition":"To invite someone to come downstairs from a higher floor.","example":"His mother asked him down for breakfast.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone to come downstairs for breakfast"}]},{"particle":"for","storageKeyPrefix":"askFor","meanings":[{"definition":"To request something to be given to you.","example":"I am going to the boss''s office to ask for a pay rise.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking for a pay rise"},{"definition":"To say that you want to speak to a specific person.","example":"When you arrive at the reception desk, ask for Mr. Smith.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking for a specific person at reception"},{"definition":"To behave in a way that will clearly cause trouble or problems (usually \"asking for it\" or \"asking for trouble\").","example":"Driving that fast in the rain is just asking for trouble.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driving fast in the rain — asking for trouble"}]},{"particle":"in","storageKeyPrefix":"askIn","meanings":[{"definition":"To invite someone to come inside a building, house, or room.","example":"It was raining heavily outside, so I asked her in to wait.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Inviting someone inside out of the rain"}]},{"particle":"into","storageKeyPrefix":"askInto","meanings":[{"definition":"Similar to \"ask in,\" but used when specifying the exact room someone is invited into.","example":"The manager asked me into his office to discuss the new project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being asked into a manager''s office"}]},{"particle":"off","storageKeyPrefix":"askOff","meanings":[{"definition":"To request permission to not go to work for a specific period of time.","example":"I need to ask Friday off so I can attend my sister''s wedding.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking for a day off work"}]},{"particle":"out","storageKeyPrefix":"askOut","meanings":[{"definition":"To invite someone to go to a movie, restaurant, etc., because you want to start a romantic relationship with them.","example":"He finally found the courage to ask her out on a date.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone out on a date"}]},{"particle":"over","storageKeyPrefix":"askOver","meanings":[{"definition":"To invite someone to your home, usually for a short visit or a meal.","example":"Let''s ask Tom and Sarah over for dinner this Saturday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Inviting friends over for dinner"}]},{"particle":"up","storageKeyPrefix":"askUp","meanings":[{"definition":"To invite someone to come upstairs to a higher floor.","example":"I asked him up to my apartment to show him my new computer setup.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone to come upstairs"}]}]'::jsonb),
  ('back', 'Back', '["away","down","in","into","off","onto","out / out of","over","up"]'::jsonb, '[{"particle":"away","storageKeyPrefix":"backAway","meanings":[{"definition":"To move backwards to get away from someone or something frightening.","example":"The developer backed away from the hot server rack.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Backing away from a hot server rack"},{"definition":"To show that you do not support a plan or idea anymore, or to avoid a difficult situation.","example":"The investors started to back away from the project when costs increased.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Investors backing away from a project"}]},{"particle":"down","storageKeyPrefix":"backDown","meanings":[{"definition":"To admit that you were wrong, or to stop demanding something because of opposition.","example":"A good manager knows when to back down during a heated argument with a team member.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager backing down in an argument"}]},{"particle":"in","storageKeyPrefix":"backIn","meanings":[{"definition":"To drive a vehicle backward into a parking space.","example":"It is much safer to back in to this parking spot so you can drive out easily later.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Backing a car into a parking spot"}]},{"particle":"into","storageKeyPrefix":"backInto","meanings":[{"definition":"To drive a vehicle backwards and accidentally hit something.","example":"I accidentally backed into the CEO''s car this morning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accidentally backing into a car"},{"definition":"To get into a career or situation by chance, rather than by planning (informal).","example":"She didn''t study management; she just backed into the leadership role when her boss left.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Unexpectedly moving into a leadership role"}]},{"particle":"off","storageKeyPrefix":"backOff","meanings":[{"definition":"To move backward away from danger or a threat.","example":"The security guard told the angry customer to back off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A security guard telling someone to back off"},{"definition":"To stop criticizing someone or telling them what to do.","example":"You need to back off and let your software team solve the problem on their own.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Giving a team space to solve problems"},{"definition":"To stop supporting an idea, or to decide not to do something you were planning to do.","example":"The company backed off from their plan to release the software early.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company backing off from an early release plan"}]},{"particle":"onto","storageKeyPrefix":"backOnto","meanings":[{"definition":"If a building backs onto something, the back of the building faces it.","example":"Our new corporate headquarters backs onto a beautiful public park.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A building backing onto a public park"}]},{"particle":"out / out of","storageKeyPrefix":"backOut","meanings":[{"definition":"To drive a vehicle backward out of a space.","example":"She backed out of the garage very slowly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Backing a car out of a garage"},{"definition":"To decide not to do something that you agreed or promised to do.","example":"The client tried to back out of the contract at the last minute.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A client backing out of a contract"}]},{"particle":"over","storageKeyPrefix":"backOver","meanings":[{"definition":"To drive a vehicle backwards over something or someone.","example":"I accidentally backed over my laptop bag in the driveway.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accidentally backing over a laptop bag"}]},{"particle":"up","storageKeyPrefix":"backUp","meanings":[{"definition":"To move backwards.","example":"Could you back up a few steps so I can see the screen?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Moving backward to see a screen"},{"definition":"To support someone or confirm that what they are saying is true.","example":"I will pitch the new Java framework to the board, but I need you to back me up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A colleague backing up a pitch to the board"},{"definition":"To make a copy of computer data so it is not lost.","example":"Always back up the database before deploying a major update.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Backing up a database before deployment"},{"definition":"To cause traffic to stop or move very slowly.","example":"The accident backed up traffic on the highway for miles.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An accident causing traffic to back up"}]}]'::jsonb),
  ('be', 'Be', '["off","on","up","down","in","into","out","away","across","forward","back","for","by","together","with","without","apart","over","ahead","after","behind","through","about","around / round","to","against"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"beOff","meanings":[{"definition":"To leave.","example":"I am off to the management conference now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Heading off to a conference"},{"definition":"To be canceled.","example":"The project launch is off because of critical bugs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project launch being canceled"},{"definition":"To be absent from work.","example":"Two developers are off sick today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers absent from work"},{"definition":"To go bad (for food).","example":"Don''t drink that milk; I think it is off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Milk that has gone off"}]},{"particle":"on","storageKeyPrefix":"beOn","meanings":[{"definition":"To happen as planned.","example":"Is the team meeting still on for tomorrow?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team meeting still happening as planned"},{"definition":"To function or operate (for machines or devices).","example":"Ensure the backup server is on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A backup server that is on and running"},{"definition":"To take medication.","example":"He is on antibiotics for his cough.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Taking antibiotics for a cough"}]},{"particle":"up","storageKeyPrefix":"beUp","meanings":[{"definition":"To be awake and out of bed.","example":"I was up all night fixing the Java code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Up all night fixing code"},{"definition":"To increase.","example":"Company profits are up by 15% this quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company profits increasing"},{"definition":"To be next in turn.","example":"You are up next for your performance review.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being next for a performance review"},{"definition":"To expire (for time).","example":"Stop writing; your time is up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Time''s up during an exam"},{"definition":"To happen (informal).","example":"What is up with the database connection?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Something wrong with the database connection"}]},{"particle":"down","storageKeyPrefix":"beDown","meanings":[{"definition":"To stop working (for systems or machines).","example":"The production environment is down right now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A production environment that is down"},{"definition":"To decrease.","example":"Sales are down compared to last month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sales figures decreasing"},{"definition":"To feel sad or depressed.","example":"He is a bit down because he didn''t get the promotion.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Someone feeling down after missing a promotion"}]},{"particle":"in","storageKeyPrefix":"beIn","meanings":[{"definition":"To be at home or in the office.","example":"The CEO will be in at 9:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The CEO arriving at the office"},{"definition":"To be submitted.","example":"All financial reports must be in by Friday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Financial reports submitted by a deadline"},{"definition":"To be fashionable or popular.","example":"Agile methodology is very in right now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Agile methodology being popular"}]},{"particle":"into","storageKeyPrefix":"beInto","meanings":[{"definition":"To be very interested in something.","example":"She is really into software architecture and system design.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being enthusiastic about software architecture"}]},{"particle":"out","storageKeyPrefix":"beOut","meanings":[{"definition":"To be absent from home or the office.","example":"The manager is out until next week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager out of the office"},{"definition":"To be published or released.","example":"The new version of the application is out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A new application version released"},{"definition":"To be revealed (for a secret).","example":"The secret is out; everyone knows about the merger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A secret merger being revealed"},{"definition":"To be impossible or unacceptable.","example":"Working over the weekend is out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Weekend work being ruled out"}]},{"particle":"away","storageKeyPrefix":"beAway","meanings":[{"definition":"To be absent or on a trip.","example":"He is away on a business trip to London.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"On a business trip to London"}]},{"particle":"across","storageKeyPrefix":"beAcross","meanings":[{"definition":"To be fully familiar with or understand a topic.","example":"As a project manager, I need to be across all the new data privacy laws.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project manager familiar with data privacy laws"}]},{"particle":"forward","storageKeyPrefix":"beForward","meanings":[{"definition":"To act presumptuously or too confidently.","example":"I do not want to be forward, but I think your strategy has a major flaw.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Politely pointing out a strategic flaw"}]},{"particle":"back","storageKeyPrefix":"beBack","meanings":[{"definition":"To return.","example":"I will be back at my desk in ten minutes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Returning to a desk"}]},{"particle":"for","storageKeyPrefix":"beFor","meanings":[{"definition":"To support or be in favor of.","example":"We are for the new flexible working hours.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Supporting flexible working hours"},{"definition":"To be intended for.","example":"This internal API is for senior developers only.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An API restricted to senior developers"}]},{"particle":"by","storageKeyPrefix":"beBy","meanings":[{"definition":"To be physically near.","example":"The server room is by the elevator.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A server room near the elevator"},{"definition":"To be the work of someone (passive sense).","example":"This excellent module is by our lead Java developer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A module created by the lead developer"}]},{"particle":"together","storageKeyPrefix":"beTogether","meanings":[{"definition":"To be unified or in a relationship.","example":"The leadership team needs to be together on this decision.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A leadership team unified on a decision"},{"definition":"To be organized (have it together).","example":"She is very professional and really has herself together.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A professional and organized person"}]},{"particle":"with","storageKeyPrefix":"beWith","meanings":[{"definition":"To support someone.","example":"I am with you on this proposal; it makes sense.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Supporting a proposal"},{"definition":"To understand someone.","example":"I am not sure I am with you. Can you explain the logic again?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking for clarification on a logic point"}]},{"particle":"without","storageKeyPrefix":"beWithout","meanings":[{"definition":"To lack something.","example":"We are without internet access at the moment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Working without internet access"}]},{"particle":"apart","storageKeyPrefix":"beApart","meanings":[{"definition":"To be separated physically or emotionally.","example":"The two microservices must be apart to avoid system dependencies.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two microservices kept separate"}]},{"particle":"over","storageKeyPrefix":"beOver","meanings":[{"definition":"To be finished.","example":"The sprint planning meeting is over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A sprint planning meeting finishing"}]},{"particle":"ahead","storageKeyPrefix":"beAhead","meanings":[{"definition":"To be winning or further advanced than expected.","example":"Our development team is ahead of schedule this month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A development team ahead of schedule"}]},{"particle":"after","storageKeyPrefix":"beAfter","meanings":[{"definition":"To want, try to get, or look for something.","example":"What exactly are you after in this contract negotiation?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Negotiating a contract"}]},{"particle":"behind","storageKeyPrefix":"beBehind","meanings":[{"definition":"To be late or delayed.","example":"We are two weeks behind schedule on this project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project behind schedule"},{"definition":"To support someone or something.","example":"The board of directors is completely behind the new CEO.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The board of directors supporting the new CEO"}]},{"particle":"through","storageKeyPrefix":"beThrough","meanings":[{"definition":"To be finished doing something or to end a relationship.","example":"I am through with using this outdated software.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Done with using outdated software"}]},{"particle":"about","storageKeyPrefix":"beAbout","meanings":[{"definition":"To be going to happen very soon (be about to).","example":"Save your work; the system is about to restart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A system about to restart"},{"definition":"To mean or consist of (what something is about).","example":"Good leadership is about listening to your team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership being about listening"}]},{"particle":"around / round","storageKeyPrefix":"beAround","meanings":[{"definition":"To be present or available.","example":"Will you be around for a code review later this afternoon?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being available for a code review"}]},{"particle":"to","storageKeyPrefix":"beTo","meanings":[{"definition":"To be required or scheduled to do something (formal).","example":"You are to report directly to the IT director.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Reporting to the IT director"}]},{"particle":"against","storageKeyPrefix":"beAgainst","meanings":[{"definition":"To oppose someone or something.","example":"Many users are against the new interface changes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Users opposing new interface changes"}]}]'::jsonb),
  ('blow', 'Blow', '["about / around (round)","apart","away","back","by","down","in","into","off","out","over","through","up"]'::jsonb, '[{"particle":"about / around (round)","storageKeyPrefix":"blowAbout","meanings":[{"definition":"To move in different directions because of the wind.","example":"The autumn leaves are blowing around the garden.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Autumn leaves blowing around the garden"},{"definition":"To spread rumors or stories (mostly British English).","example":"There are a few rumors blowing about the office regarding the new manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rumors spreading through an office"}]},{"particle":"apart","storageKeyPrefix":"blowApart","meanings":[{"definition":"To completely destroy something using an explosion.","example":"The bomb blew the old building apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Building destroyed by an explosion"},{"definition":"To completely destroy an argument, idea, or plan by showing its flaws.","example":"The senior developer blew apart my software architecture proposal during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer debunking a software proposal"}]},{"particle":"away","storageKeyPrefix":"blowAway","meanings":[{"definition":"To impress someone very much.","example":"The team\\''s presentation on the new Java framework completely blew me away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team presentation impressing the audience"},{"definition":"To move something away using the wind.","example":"Hold onto your documents, or the wind will blow them away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Documents being blown away by wind"},{"definition":"To defeat competitors easily or kill someone.","example":"Our new product will blow the competition away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Product easily defeating the competition"}]},{"particle":"back","storageKeyPrefix":"blowBack","meanings":[{"definition":"When the wind pushes something (like smoke or hair) back toward you.","example":"I tried to light the fire, but the smoke blew back into my face.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Smoke blowing back into someone\\''s face"},{"definition":"To have unexpected negative consequences for the person who started an action (often used as the noun blowback).","example":"The company\\''s aggressive marketing campaign blew back on them when customers complained.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Marketing campaign backfiring on a company"}]},{"particle":"by","storageKeyPrefix":"blowBy","meanings":[{"definition":"To pass very quickly (usually referring to time).","example":"The weekend just blew by, and now it is Monday again.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Time passing very quickly over a weekend"},{"definition":"To easily move past a competitor or obstacle.","example":"The runner blew by the defender to score a goal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Runner passing a defender to score"}]},{"particle":"down","storageKeyPrefix":"blowDown","meanings":[{"definition":"To make something fall to the ground using strong wind.","example":"The storm blew down several trees in our neighborhood.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Storm blowing down trees"}]},{"particle":"in","storageKeyPrefix":"blowIn","meanings":[{"definition":"To arrive casually, suddenly, or unexpectedly.","example":"The CEO just blew in from London and wants to see you.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO arriving unexpectedly from a flight"}]},{"particle":"into","storageKeyPrefix":"blowInto","meanings":[{"definition":"To enter a room or building casually or loudly.","example":"She blew into the office 20 minutes late, holding a cup of coffee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person arriving late to the office with coffee"},{"definition":"To push air from your mouth into a device.","example":"The police officer asked the driver to blow into the breathalyzer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driver blowing into a breathalyzer"}]},{"particle":"off","storageKeyPrefix":"blowOff","meanings":[{"definition":"To ignore someone or fail to attend an appointment.","example":"I tried to organize a meeting with the client, but he blew me off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client ignoring a meeting request"},{"definition":"To ignore a responsibility or task.","example":"He blew off his homework to play video games.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student ignoring homework to play video games"},{"definition":"To release physical or emotional pressure (often \"blow off steam\").","example":"After a stressful week at work, I like to run 10 kilometers to blow off steam.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person running to relieve stress after work"}]},{"particle":"out","storageKeyPrefix":"blowOut","meanings":[{"definition":"To extinguish a flame with your breath or wind.","example":"Make a wish and blow out the candles on your birthday cake.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Blowing out birthday cake candles"},{"definition":"To defeat an opponent very easily.","example":"Our sales team blew out the competition this quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sales team dominating the competition"},{"definition":"When a vehicle''s tire suddenly bursts.","example":"I was driving to Warsaw when my front tire blew out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Car tire blowing out on the road"}]},{"particle":"over","storageKeyPrefix":"blowOver","meanings":[{"definition":"When a bad situation, argument, or storm ends or is forgotten without causing serious damage.","example":"The management decided to wait for the PR scandal to blow over before launching the app.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Waiting for a PR scandal to pass"}]},{"particle":"through","storageKeyPrefix":"blowThrough","meanings":[{"definition":"To spend money very quickly and irresponsibly.","example":"The startup blew through its entire budget in just six months.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Startup spending through its budget rapidly"},{"definition":"To travel through a place quickly without stopping.","example":"We didn\\''t have time for sightseeing; we just blew through Paris on our way south.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Passing through Paris without stopping"}]},{"particle":"up","storageKeyPrefix":"blowUp","meanings":[{"definition":"To explode or be destroyed by an explosion.","example":"The action movie hero walked away as the car blew up behind him.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Car exploding in an action movie scene"},{"definition":"To fill something with air (inflate).","example":"Can you help me blow up these balloons for the party?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Inflating balloons for a party"},{"definition":"To suddenly become very angry.","example":"My boss blew up at me when I accidentally deleted the database.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Boss becoming angry after a database mistake"},{"definition":"To enlarge a photograph or image.","example":"Let\\''s blow up this chart so everyone in the meeting room can see it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Enlarging a chart for a meeting room"},{"definition":"To suddenly become very popular or successful.","example":"Their new social media app blew up overnight.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Social media app becoming viral overnight"}]}]'::jsonb),
  ('break', 'Break', '["off","up","down","in","into","out","away","back","for","with","apart","over","through","to","against"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"breakOff","meanings":[{"definition":"To remove a part of something (by force or snapping).","example":"He broke off a square of chocolate and gave it to me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Breaking off a square of chocolate"},{"definition":"To suddenly stop speaking or doing something.","example":"She broke off in the middle of her sentence when the phone rang.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person stopping mid-sentence when the phone rings"},{"definition":"To end a relationship, agreement, or negotiation.","example":"The two countries have broken off diplomatic relations.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two countries ending diplomatic relations"}]},{"particle":"up","storageKeyPrefix":"breakUp","meanings":[{"definition":"To separate into smaller pieces.","example":"The ship broke up on the rocks during the storm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A ship breaking apart on rocks during a storm"},{"definition":"To end a romantic relationship or marriage.","example":"Sam and Alex broke up after five years of dating.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A couple ending their relationship"},{"definition":"To force a crowd to disperse or to stop a fight.","example":"The police arrived to break up the protest.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police dispersing a protest"},{"definition":"To divide something into smaller, manageable parts.","example":"Let''s break up this large project into smaller tasks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dividing a large project into smaller tasks"},{"definition":"To lose audio signal (telecommunications).","example":"I can''t hear you very well, your voice is breaking up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A poor phone connection breaking up"},{"definition":"To end the school term for holidays (chiefly British).","example":"The children are excited because school breaks up next week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Children excited about school breaking up for holidays"},{"definition":"To burst into laughter, or make someone else laugh (chiefly American).","example":"That comedian always breaks me up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A comedian making someone burst into laughter"}]},{"particle":"down","storageKeyPrefix":"breakDown","meanings":[{"definition":"To stop working (machinery or vehicles).","example":"My car broke down on the highway.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A car breaking down on a highway"},{"definition":"To lose control of one\\''s emotions and start crying.","example":"She broke down in tears when she heard the news.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person breaking down in tears"},{"definition":"To fail or collapse (negotiations, systems, or relationships).","example":"The peace talks broke down after neither side would compromise.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Peace talks collapsing without compromise"},{"definition":"To divide information into smaller parts for easier analysis.","example":"Can you break down this budget so I can see where the money is going?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Breaking down a budget for analysis"},{"definition":"To destroy or remove a barrier or obstacle.","example":"The organization works to break down social barriers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An organization breaking down social barriers"},{"definition":"To decompose or separate into basic chemical elements.","example":"Plastic takes hundreds of years to break down in the environment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Plastic slowly decomposing in the environment"}]},{"particle":"in","storageKeyPrefix":"breakIn","meanings":[{"definition":"To enter a building by force or illegally (intransitive).","example":"Thieves broke in while we were away on vacation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves breaking into a house"},{"definition":"To interrupt a conversation.","example":"\"I completely disagree,\" he broke in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person interrupting a conversation"},{"definition":"To wear new shoes or use new equipment until they become comfortable.","example":"My feet hurt because I\\''m still breaking in these new leather boots.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Breaking in a pair of new leather boots"},{"definition":"To train a new employee, or to train an animal (like a horse) to be ridden.","example":"It takes a few weeks to break in a wild horse.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Training a wild horse to be ridden"}]},{"particle":"into","storageKeyPrefix":"breakInto","meanings":[{"definition":"To enter a building by force (transitive — requires an object).","example":"Someone broke into my apartment last night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An intruder breaking into an apartment"},{"definition":"To suddenly begin doing something (laughing, running, singing, sweating).","example":"As soon as she saw him, she broke into a smile.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person suddenly breaking into a smile"},{"definition":"To successfully enter a new profession, industry, or market.","example":"It is very difficult to break into the publishing industry.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Someone trying to break into the publishing industry"},{"definition":"To open something by force or use emergency supplies/funds.","example":"We had to break into our savings to pay for the roof repair.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Breaking into savings to cover an unexpected expense"}]},{"particle":"out","storageKeyPrefix":"breakOut","meanings":[{"definition":"To start suddenly (war, fire, disease, riots).","example":"World War II broke out in 1939.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The sudden outbreak of World War II"},{"definition":"To escape from a place (like a prison).","example":"Three inmates managed to break out of the maximum-security facility.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Inmates breaking out of a maximum-security prison"},{"definition":"To develop a skin condition (sweat, spots, acne, rash).","example":"Eating too much dairy makes my skin break out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Skin breaking out in spots due to dairy"},{"definition":"To bring something out to use or celebrate with.","example":"We won the contract! Let''s break out the champagne.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Celebrating a contract win with champagne"}]},{"particle":"away","storageKeyPrefix":"breakAway","meanings":[{"definition":"To physically escape from someone who is holding you.","example":"He grabbed her arm, but she managed to break away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person breaking free from someone grabbing their arm"},{"definition":"To separate from a group, crowd, or pack (often in a race).","example":"Three cyclists broke away from the main pack to take the lead.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cyclists breaking away from the main pack in a race"},{"definition":"To leave a political party, country, or organization to form a new one.","example":"The rebel faction broke away to form their own government.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A rebel faction breaking away to form a new government"}]},{"particle":"back","storageKeyPrefix":"breakBack","meanings":[{"definition":"To regain a lost advantage (specifically in sports like tennis).","example":"He lost his serve in the first set but immediately broke back in the next game.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A tennis player breaking back after losing a set"}]},{"particle":"for","storageKeyPrefix":"breakFor","meanings":[{"definition":"To suddenly run toward something (usually safety or cover).","example":"When the rain started pouring, we broke for the trees.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People running for cover under trees in the rain"},{"definition":"To pause an activity for a short period.","example":"Let''s break for lunch and resume the meeting at 2:00 PM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team pausing a meeting for lunch"}]},{"particle":"with","storageKeyPrefix":"breakWith","meanings":[{"definition":"To stop following a tradition, habit, or custom.","example":"The designer broke with tradition by using bright neon colors for the wedding dress.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A designer breaking tradition with a neon wedding dress"},{"definition":"To end a relationship or association with a person or group.","example":"He broke with his family over their political differences.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person severing ties with family over politics"}]},{"particle":"apart","storageKeyPrefix":"breakApart","meanings":[{"definition":"To separate or shatter into pieces (often violently).","example":"The space shuttle broke apart upon re-entering the atmosphere.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A space shuttle breaking apart on re-entry"},{"definition":"To destroy a relationship, organization, or group.","example":"The scandal threatened to break the entire committee apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A scandal threatening to break a committee apart"}]},{"particle":"over","storageKeyPrefix":"breakOver","meanings":[{"definition":"To wash or burst over something (like waves).","example":"The massive wave broke over the bow of the ship.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A massive wave breaking over the bow of a ship"},{"definition":"To happen suddenly and intensely in a specific location (weather or events).","example":"The storm broke over the city just after midnight.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A storm breaking over a city at midnight"}]},{"particle":"through","storageKeyPrefix":"breakThrough","meanings":[{"definition":"To force a way through an obstacle, barrier, or defense.","example":"The sun finally broke through the heavy clouds.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sunlight breaking through heavy clouds"},{"definition":"To make a significant discovery or overcome a major limitation.","example":"Scientists hope to break through in their cancer research this year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Scientists making a breakthrough in cancer research"}]},{"particle":"to","storageKeyPrefix":"breakTo","meanings":[{"definition":"To tell someone bad or surprising news gently (used as \"break it to\" or \"break the news to\").","example":"I hate to break it to you, but your flight has been canceled.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Gently breaking bad news about a canceled flight"}]},{"particle":"against","storageKeyPrefix":"breakAgainst","meanings":[{"definition":"To crash forcefully into something.","example":"We sat and watched the waves break against the rocky cliffs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Waves breaking against rocky cliffs"}]}]'::jsonb),
  ('bring', 'Bring', '["about","around / round","away","back","by","down","forward","in","into","off","on","out","over","through","to","together","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"bringAbout","meanings":[{"definition":"To cause something to happen.","example":"The new management structure brought about a massive improvement in team efficiency.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A management change bringing about improved team efficiency"},{"definition":"(Nautical) To cause a ship to change direction.","example":"The captain brought the ship about to avoid the storm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A captain steering a ship around a storm"}]},{"particle":"around / round","storageKeyPrefix":"bringAround","meanings":[{"definition":"To persuade someone to agree with your point of view.","example":"He didn''t want to use the new software at first, but we eventually brought him around.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Persuading a colleague to adopt new software"},{"definition":"To restore someone to consciousness.","example":"She fainted from the heat, but a glass of cold water brought her round.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Reviving someone who fainted from heat"},{"definition":"To bring someone or something to a place (like a home).","example":"I''ll bring the documents round to your apartment this evening.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Delivering documents to someone\\''s apartment"},{"definition":"To gradually introduce a specific topic into a conversation.","example":"After chatting about the weather, she smoothly brought the conversation around to the job offer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Steering a conversation toward a job offer"}]},{"particle":"away","storageKeyPrefix":"bringAway","meanings":[{"definition":"To learn or gain an impression, memory, or lesson from an experience.","example":"The main insight I brought away from the tech conference was how heavily AI will impact sourcing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Taking away key insights from a tech conference"}]},{"particle":"back","storageKeyPrefix":"bringBack","meanings":[{"definition":"To return something to its original place or owner.","example":"Please bring back the laptop when you finish the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Returning a laptop after a presentation"},{"definition":"To cause someone to remember something from the past.","example":"Walking through my old university campus really brought back memories.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Revisiting a university campus bringing back memories"},{"definition":"To reintroduce something or start doing something again.","example":"The company decided to bring back the remote work policy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company reintroducing a remote work policy"}]},{"particle":"by","storageKeyPrefix":"bringBy","meanings":[{"definition":"To visit someone briefly in order to deliver something.","example":"I''ll bring the signed contracts by the office tomorrow morning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dropping off signed contracts at an office"}]},{"particle":"down","storageKeyPrefix":"bringDown","meanings":[{"definition":"To reduce a level, rate, or amount.","example":"We need to bring down our time-to-hire metric this quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Reducing the time-to-hire metric in a company"},{"definition":"To cause a government or leader to lose power.","example":"The financial scandal eventually brought down the prime minister.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A financial scandal bringing down a prime minister"},{"definition":"To make someone feel sad, depressed, or less energetic.","example":"This endless rainy weather is really bringing me down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rainy weather bringing someone down emotionally"},{"definition":"To cause an aircraft or an animal to fall to the ground.","example":"The pilot safely brought down the plane despite the engine failure.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A pilot safely landing a plane with engine failure"}]},{"particle":"forward","storageKeyPrefix":"bringForward","meanings":[{"definition":"To change the date or time of an event so that it happens earlier.","example":"Because of a scheduling conflict, the interview was brought forward to 10:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Moving an interview to an earlier time"},{"definition":"To introduce a plan, proposal, or argument for discussion.","example":"The team brought forward several excellent ideas during the brainstorming session.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team proposing ideas during a brainstorming session"},{"definition":"(Accounting) To transfer a total from the bottom of one page to the top of the next.","example":"The balance of $5,000 was brought forward to the new ledger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Transferring a balance to a new ledger page"}]},{"particle":"in","storageKeyPrefix":"bringIn","meanings":[{"definition":"To involve someone new in a project or situation (often an expert).","example":"We had to bring in a senior DevOps consultant to fix the server architecture.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bringing in a DevOps consultant to fix server issues"},{"definition":"To earn or produce money.","example":"Her freelance coding projects bring in an extra $2,000 a month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Freelance coding projects generating extra income"},{"definition":"To introduce a new law, rule, or system.","example":"The government is bringing in stricter data privacy regulations.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A government introducing stricter data privacy laws"},{"definition":"To take someone to a police station for questioning or arrest.","example":"The police brought him in for questioning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police bringing a suspect in for questioning"},{"definition":"(Legal) To yield or announce a verdict in court.","example":"The jury brought in a verdict of not guilty.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A jury delivering a not guilty verdict in court"}]},{"particle":"into","storageKeyPrefix":"bringInto","meanings":[{"definition":"To cause someone or something to become involved in a specific situation, state, or condition.","example":"Please don''t bring me into your argument.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being dragged into someone else\\''s argument"}]},{"particle":"off","storageKeyPrefix":"bringOff","meanings":[{"definition":"To succeed in doing something very difficult, often unexpectedly.","example":"Negotiating that salary package with a tight budget was tough, but she brought it off beautifully.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Successfully negotiating a salary package under budget pressure"}]},{"particle":"on","storageKeyPrefix":"bringOn","meanings":[{"definition":"To cause something to happen (usually something negative, like an illness or bad situation).","example":"I think the sudden change in weather brought on my cold.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Weather change bringing on a cold"},{"definition":"To help someone develop or improve, especially in their career or skills.","example":"The senior manager really brought the junior recruiters on over the last year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A senior manager developing junior recruiters"},{"definition":"To send a player onto the field during a sports match.","example":"The coach brought on a substitute striker in the 80th minute.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A coach sending on a substitute striker"},{"definition":"Used as an exclamation (\"Bring it on!\") to show you are prepared for a challenge.","example":"Another difficult technical assessment to evaluate? Bring it on!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Someone confidently accepting a difficult challenge"}]},{"particle":"out","storageKeyPrefix":"bringOut","meanings":[{"definition":"To produce a new product and start selling it, or to publish something.","example":"Apple is bringing out a new iPhone model in September.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Apple launching a new iPhone model"},{"definition":"To highlight or make a particular quality noticeable.","example":"The behavioral interview questions really brought out her leadership qualities.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Interview questions bringing out leadership qualities"},{"definition":"To cause a physical reaction on the skin (like a rash).","example":"Eating strawberries always brings me out in a rash.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Strawberries causing a skin rash"},{"definition":"(Bring someone out of their shell) To make a shy person more confident.","example":"Working closely with a team really brought him out of his shell.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teamwork bringing a shy person out of their shell"}]},{"particle":"over","storageKeyPrefix":"bringOver","meanings":[{"definition":"To bring someone or something from one place to another (especially to someone\\''s home).","example":"I''ll bring over my notes so we can study English grammar together.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bringing notes over to study together"},{"definition":"To persuade someone to change to your side or opinion (similar to bring around).","example":"We managed to bring the hesitant candidate over to our side with a better relocation package.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Persuading a hesitant candidate with a better offer"}]},{"particle":"through","storageKeyPrefix":"bringThrough","meanings":[{"definition":"To help someone successfully survive a very difficult, dangerous, or life-threatening situation.","example":"The incredible medical team brought him through the surgery safely.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A medical team successfully guiding a patient through surgery"}]},{"particle":"to","storageKeyPrefix":"bringTo","meanings":[{"definition":"To make someone conscious again after they have fainted.","example":"The paramedics used smelling salts to bring him to.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Paramedics reviving someone with smelling salts"},{"definition":"To reach a mathematical total.","example":"The latest hires bring our total headcount to 150 employees.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New hires bringing company headcount to 150"}]},{"particle":"together","storageKeyPrefix":"bringTogether","meanings":[{"definition":"To help people or groups to become friendly, collaborate, or unite.","example":"The project brought together software developers from all over Europe.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project uniting software developers from across Europe"}]},{"particle":"up","storageKeyPrefix":"bringUp","meanings":[{"definition":"To care for and raise a child until they are an adult.","example":"She was brought up in a bilingual household.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A child being raised in a bilingual household"},{"definition":"To mention a subject or start talking about a specific topic.","example":"Make sure you bring up the remote work options during the first interview.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Mentioning remote work options in a job interview"},{"definition":"To make something appear on a computer screen.","example":"Let me just bring up his GitHub repository so we can review his code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bringing up a GitHub repository on a computer screen"},{"definition":"To vomit.","example":"He ate some bad seafood and brought up his dinner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Someone feeling ill after eating bad seafood"}]}]'::jsonb),
  ('brush', 'Brush', '["off","up / up on","away","down","out","on","over","against","by","back","through"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"brushOff","meanings":[{"definition":"To use your hand or a brush to remove dirt, dust, or something unwanted from a surface.","example":"I brushed off my suit before entering the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Brushing off a suit before a meeting"},{"definition":"To ignore someone, refuse to listen to them, or treat their ideas as unimportant.","example":"I tried to suggest a new Java framework, but the lead developer brushed me off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer dismissing a framework suggestion"}]},{"particle":"up / up on","storageKeyPrefix":"brushUp","meanings":[{"definition":"To improve your knowledge or skill in something you learned in the past but have partly forgotten.","example":"You should brush up on your management skills before applying for the leadership role.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Improving management skills before a leadership role"}]},{"particle":"away","storageKeyPrefix":"brushAway","meanings":[{"definition":"To remove something by sweeping it with your hand or a brush.","example":"She brushed away the crumbs from the keyboard.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Brushing crumbs off a keyboard"},{"definition":"To quickly dismiss a feeling, thought, or fear.","example":"He brushed away his doubts and launched the new software product.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dismissing doubts before launching a product"}]},{"particle":"down","storageKeyPrefix":"brushDown","meanings":[{"definition":"To clean someone or something by brushing them from top to bottom.","example":"The rider brushed down the horse after the race.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rider brushing down a horse after a race"}]},{"particle":"out","storageKeyPrefix":"brushOut","meanings":[{"definition":"To remove tangles or dirt from hair or fur using a brush.","example":"It takes a long time to brush out this dog''s thick coat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Brushing out a dog''s thick coat"},{"definition":"To clean the inside of something with a brush.","example":"Please brush out the back of the company van before returning it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning the inside of a company van with a brush"}]},{"particle":"on","storageKeyPrefix":"brushOn","meanings":[{"definition":"To apply a liquid (like paint, glue, or a sauce) to a surface using a brush.","example":"Brush on a light coat of varnish to protect the wood.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Applying varnish to wood with a brush"}]},{"particle":"over","storageKeyPrefix":"brushOver","meanings":[{"definition":"To ignore a problem or treat a topic lightly instead of explaining it in detail.","example":"The CEO brushed over the bad financial report and focused only on future goals.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO glossing over a bad financial report"}]},{"particle":"against","storageKeyPrefix":"brushAgainst","meanings":[{"definition":"To touch someone or something lightly while moving past them.","example":"My shoulder brushed against the doorframe as I walked into the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Shoulder lightly touching a doorframe"}]},{"particle":"by","storageKeyPrefix":"brushBy","meanings":[{"definition":"To walk past someone in a narrow space, touching them slightly.","example":"He brushed by me in the crowded hallway without saying excuse me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Walking past someone in a crowded hallway"}]},{"particle":"back","storageKeyPrefix":"brushBack","meanings":[{"definition":"To push hair away from your face.","example":"She brushed back her hair to look closer at the screen.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Brushing hair back to see a screen clearly"},{"definition":"To force someone to move backward (often used in baseball when a pitcher throws a ball very close to the batter).","example":"The pitcher threw a fast ball inside to brush back the batter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Pitcher throwing inside to push back the batter"}]},{"particle":"through","storageKeyPrefix":"brushThrough","meanings":[{"definition":"To move a brush completely through hair to remove knots.","example":"Just brush through your hair quickly before the video call starts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Brushing through hair before a video call"}]}]'::jsonb),
  ('build', 'Build', '["around / round","in / into","on","out","up","to"]'::jsonb, '[{"particle":"around / round","storageKeyPrefix":"buildAround","meanings":[{"definition":"To base a strategy, system, plan, or team on a central person, idea, or concept.","example":"The CEO decided to build the new marketing strategy around customer retention.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO building a marketing strategy around customer retention"}]},{"particle":"in / into","storageKeyPrefix":"buildIn","meanings":[{"definition":"To include something as a permanent, essential, or integral part of a system, plan, or structure from the beginning.","example":"When planning the project schedule, we need to build in some extra time for unexpected delays.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Building extra time into a project schedule"}]},{"particle":"on","storageKeyPrefix":"buildOn","meanings":[{"definition":"To use a past achievement, existing idea, or success as a foundation for further progress and development.","example":"We can build on the momentum of last quarter\\''s sales to reach our new targets.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Building on last quarter\\''s sales momentum"}]},{"particle":"out","storageKeyPrefix":"buildOut","meanings":[{"definition":"To develop, expand, or complete a system, space, or business so that it reaches its full potential or size.","example":"The startup received funding to build out its sales and marketing departments.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Startup expanding its sales and marketing departments"}]},{"particle":"up","storageKeyPrefix":"buildUp","meanings":[{"definition":"To gradually increase in amount, size, strength, or intensity.","example":"If we don\\''t refactor the code regularly, technical debt will build up quickly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Technical debt building up without regular refactoring"},{"definition":"To talk about someone or something in a very positive way to create a good impression (often before introducing them).","example":"The director really built up the new project manager before she walked into the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Director building up a new project manager before a meeting"},{"definition":"To develop an area with many buildings and infrastructure.","example":"The area around the new technology park has become highly built up over the last five years.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Area around a technology park becoming built up"}]},{"particle":"to","storageKeyPrefix":"buildTo","meanings":[{"definition":"To gradually increase and approach a climax, peak, or major event.","example":"The tension in the boardroom was building to a breaking point before the final decision was made.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Tension building in a boardroom toward a decision"}]}]'::jsonb),
  ('call', 'Call', '["off","on / upon","up","down","in","into","out","away","across","forward","back","for","by","together","over","ahead","after","through","about","around / round","to"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"callAbout","meanings":[{"definition":"To make a phone call concerning a specific topic.","example":"I am calling about the open software engineering position.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person making a phone call about a job position"}]},{"particle":"across","storageKeyPrefix":"callAcross","meanings":[{"definition":"To shout to someone on the other side of a room, street, or space.","example":"He called across the open-plan office to ask for the password.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shouting across an open-plan office"}]},{"particle":"after","storageKeyPrefix":"callAfter","meanings":[{"definition":"To shout to someone as they are walking away from you.","example":"I called after him, but he had already entered the elevator.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shouting after someone entering an elevator"},{"definition":"To give a child the same name as someone else.","example":"He was called after his grandfather.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child named after a grandfather"}]},{"particle":"ahead","storageKeyPrefix":"callAhead","meanings":[{"definition":"To telephone a place before you arrive there (often to make a reservation or check something).","example":"We should call ahead to ensure the conference room is available.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person calling ahead to check conference room availability"}]},{"particle":"around / round","storageKeyPrefix":"callAround","meanings":[{"definition":"To telephone several different people or companies, usually to get information or compare prices.","example":"I will call around to find a better price for our cloud hosting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person calling multiple companies to compare prices"},{"definition":"To visit someone\\''s house casually.","example":"Feel free to call round after work for a coffee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person visiting a friend\\''s house casually"}]},{"particle":"away","storageKeyPrefix":"callAway","meanings":[{"definition":"To ask someone to leave the place where they are to go somewhere else, usually for an emergency.","example":"The director was called away to an urgent meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Director being called away to an urgent meeting"}]},{"particle":"back","storageKeyPrefix":"callBack","meanings":[{"definition":"To return a telephone call.","example":"I am in a meeting, can I call you back in an hour?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person returning a phone call after a meeting"},{"definition":"To ask someone to return for a second job interview.","example":"They liked her portfolio and called her back for a final interview.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Candidate being called back for a final interview"}]},{"particle":"by","storageKeyPrefix":"callBy","meanings":[{"definition":"To make a short, informal visit to a place while going somewhere else.","example":"I\\''ll call by the IT department on my way to lunch to drop off the broken mouse.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person making a brief visit to the IT department"}]},{"particle":"down","storageKeyPrefix":"callDown","meanings":[{"definition":"To shout to someone who is on a lower level than you.","example":"She called down from the second floor to ask if the package had arrived.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shouting down from the second floor"},{"definition":"To request negative consequences or punishment upon someone (formal/literary).","example":"He called down curses on his rivals.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person invoking curses on rivals"}]},{"particle":"for","storageKeyPrefix":"callFor","meanings":[{"definition":"To demand or require a specific action or quality.","example":"Managing a large team calls for great communication skills.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager requiring strong communication skills from team"},{"definition":"To publicly ask for something to happen.","example":"The users are calling for better privacy features in the app.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Users demanding better privacy features"},{"definition":"To go to a place to pick someone or something up.","example":"I will call for you at the hotel at 8:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person picking someone up from a hotel"}]},{"particle":"forward","storageKeyPrefix":"callForward","meanings":[{"definition":"To ask someone to step to the front of a group.","example":"The CEO called the project manager forward to receive an award.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO calling project manager forward for an award"}]},{"particle":"in","storageKeyPrefix":"callIn","meanings":[{"definition":"To ask an expert or specialist to come and help with a problem.","example":"The system crashed, so we had to call in an external IT consultant.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"External IT consultant called in to fix a system crash"},{"definition":"To telephone your office or a radio/TV show.","example":"Two team members called in sick today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team members calling in sick to the office"},{"definition":"To demand that people return a product because it is broken or dangerous (a recall).","example":"The manufacturer called in thousands of laptops due to battery issues.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manufacturer recalling laptops due to battery issues"}]},{"particle":"into","storageKeyPrefix":"callInto","meanings":[{"definition":"To call into question means to make people doubt something (idiom).","example":"The recent security breach called into question the software\\''s reliability.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Security breach calling software reliability into question"},{"definition":"To summon someone into a room.","example":"The manager called him into the office for a performance review.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager summoning employee for a performance review"}]},{"particle":"off","storageKeyPrefix":"callOff","meanings":[{"definition":"To cancel an event, meeting, or agreement that was planned.","example":"We had to call off the project meeting because the lead developer was sick.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project meeting being cancelled due to sick developer"},{"definition":"To order a person or animal to stop attacking or searching.","example":"The manager told the legal team to call off their aggressive negotiations.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager calling off aggressive legal negotiations"}]},{"particle":"on / upon","storageKeyPrefix":"callOn","meanings":[{"definition":"To ask someone formally to speak or do something.","example":"I would like to call on our CEO to say a few words.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Host calling on CEO to speak at an event"},{"definition":"To use a quality, skill, or resource that you have.","example":"The team had to call on all their experience to fix the critical bug.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team calling on their experience to fix a critical bug"},{"definition":"To visit someone for a short time (often formally).","example":"We will call on the new client tomorrow morning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business team making a formal visit to a new client"}]},{"particle":"out","storageKeyPrefix":"callOut","meanings":[{"definition":"To publicly criticize someone for doing something wrong.","example":"The leader called out the team member for unprofessional behavior.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leader calling out a team member for unprofessional behavior"},{"definition":"To ask a professional to come for an emergency.","example":"We had to call out an engineer in the middle of the night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Engineer called out for an emergency at night"},{"definition":"To speak loudly so someone can hear you.","example":"The manager called out my name across the warehouse.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager calling out a name across a warehouse"}]},{"particle":"over","storageKeyPrefix":"callOver","meanings":[{"definition":"To ask someone to come to where you are standing.","example":"I called the junior developer over to look at my screen.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer calling a colleague over to look at their screen"},{"definition":"To read aloud a list of names to check who is present (mostly British English).","example":"The trainer called over the names before the workshop started.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Trainer calling over names before a workshop"}]},{"particle":"through","storageKeyPrefix":"callThrough","meanings":[{"definition":"To connect a phone call to someone else.","example":"The receptionist called me through to the HR director.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Receptionist connecting a call to the HR director"}]},{"particle":"to","storageKeyPrefix":"callTo","meanings":[{"definition":"To shout in order to get someone\\''s attention.","example":"She called to the cab driver to stop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shouting to a cab driver to stop"}]},{"particle":"together","storageKeyPrefix":"callTogether","meanings":[{"definition":"To formally ask a group of people to meet in one place.","example":"We need to call the board of directors together to discuss the merger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Board of directors called together to discuss a merger"}]},{"particle":"up","storageKeyPrefix":"callUp","meanings":[{"definition":"To telephone someone.","example":"I will call up the software vendor to ask about the pricing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person calling a software vendor about pricing"},{"definition":"To find and show information on a computer screen.","example":"Can you call up the latest sales data on your monitor?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person displaying sales data on a computer monitor"},{"definition":"To officially order someone to join the military.","example":"His grandfather was called up during the war.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldier being called up during wartime"},{"definition":"To make someone remember something.","example":"The old office building called up memories of my first job.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old office building evoking memories of a first job"}]}]'::jsonb),
  ('carry', 'Carry', '["about / around / round","away","back","forward","off","on","out","over","through"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"carryAbout","meanings":[{"definition":"To keep something with you everywhere you go (physical).","example":"The lead developer carries around a notebook to write down new software ideas.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer carrying a notebook everywhere"},{"definition":"To hold onto a feeling or emotion (usually negative) for a long time.","example":"She carried around a lot of stress after the project failed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person carrying stress after project failure"}]},{"particle":"away","storageKeyPrefix":"carryAway","meanings":[{"definition":"To become too excited and lose control of your behavior (almost always used in the passive voice: \"get/be carried away\").","example":"The marketing team got carried away with the new features and promised the client things we couldn''t build.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Marketing team getting carried away with promises"}]},{"particle":"back","storageKeyPrefix":"carryBack","meanings":[{"definition":"To bring a past memory to mind; to make someone remember a specific time.","example":"Hearing that old startup story carried the CEO back to his first year in business.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO remembering early startup days"}]},{"particle":"forward","storageKeyPrefix":"carryForward","meanings":[{"definition":"To make a project or idea progress to the next stage.","example":"We need a strong manager to carry this initiative forward.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager carrying initiative forward"},{"definition":"(Business / Accounting) To transfer a financial total or a specific benefit to a new page, period, or year.","example":"Any unused vacation days from this year will be carried forward to next year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accountant transferring vacation days to next year"}]},{"particle":"off","storageKeyPrefix":"carryOff","meanings":[{"definition":"To succeed in doing something difficult, often when others did not expect you to.","example":"It was a highly risky strategy, but the leadership team carried it off perfectly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership team succeeding with a risky strategy"},{"definition":"To win a prize, competition, or award.","example":"Our company carried off three major industry awards this year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company winning industry awards"},{"definition":"To cause death, usually due to a disease (formal and older use).","example":"The virus carried off thousands of people in the 19th century.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Historical illustration of disease spreading"}]},{"particle":"on","storageKeyPrefix":"carryOn","meanings":[{"definition":"To continue doing something.","example":"Please carry on with your coding; I will check your progress after lunch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer continuing to code"},{"definition":"To manage, run, or take part in a business or activity.","example":"They carry on a successful IT consulting business in Warsaw.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT consulting business running in Warsaw"},{"definition":"To behave in an uncontrolled, angry, or childish way.","example":"The customer carried on for ten minutes about the delayed software release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Customer complaining about software delay"},{"definition":"To have a secret, often romantic or sexual, relationship.","example":"It was rumored that the two directors were carrying on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people having a secret relationship"}]},{"particle":"out","storageKeyPrefix":"carryOut","meanings":[{"definition":"To perform, execute, or complete a task, instruction, experiment, or plan.","example":"The IT department carried out the system update over the weekend without any issues.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT department performing a system update"},{"definition":"To fulfill a promise or a threat.","example":"The management carried out their promise to increase employee training budgets.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Management fulfilling training budget promise"}]},{"particle":"over","storageKeyPrefix":"carryOver","meanings":[{"definition":"To continue to exist in a different situation, environment, or time.","example":"His excellent management skills carried over perfectly into his new role as a director.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager transferring skills to new director role"},{"definition":"To delay or postpone something to a later time.","example":"We ran out of time, so the final agenda item was carried over to next week''s meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Agenda item postponed to next meeting"}]},{"particle":"through","storageKeyPrefix":"carryThrough","meanings":[{"definition":"To complete a task successfully despite facing significant difficulties.","example":"The team''s dedication carried the software release through to a successful launch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team completing software release despite difficulties"},{"definition":"To help someone or something survive a difficult situation.","example":"The emergency investment carried the business through the financial crisis.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business surviving financial crisis with investment"}]}]'::jsonb),
  ('catch', 'Catch', '["in","on","out","up"]'::jsonb, '[{"particle":"in","storageKeyPrefix":"catchIn","meanings":[{"definition":"To discover someone in the middle of doing something (usually bad).","example":"The audit team caught the vendor in a lie about their data protection protocols.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Audit team catching vendor in a lie"},{"definition":"To be trapped or delayed by an unavoidable situation (used as caught in).","example":"I missed the daily Scrum meeting because I got caught in heavy traffic.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person caught in heavy traffic"}]},{"particle":"on","storageKeyPrefix":"catchOn","meanings":[{"definition":"To understand something (often after a delay or difficulty).","example":"The syntax of the new Java library was confusing at first, but the junior developers eventually caught on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Junior developers understanding a new Java library"},{"definition":"To become popular or widely accepted.","example":"Microservices architecture quickly caught on as the standard for enterprise software development.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Microservices architecture becoming popular"}]},{"particle":"out","storageKeyPrefix":"catchOut","meanings":[{"definition":"To discover that someone has made a mistake, lied, or done something wrong.","example":"The automated testing pipeline caught the developer out by exposing a critical security flaw in the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Testing pipeline exposing a security flaw"},{"definition":"To put someone in a difficult, unexpected, or unprepared situation.","example":"The sudden crash of our cloud servers caught the management team out during the product launch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cloud server crash catching management unprepared"}]},{"particle":"up","storageKeyPrefix":"catchUp","meanings":[{"definition":"To reach the same level, standard, or position as someone or something else.","example":"Our software is lacking some features, so we need to release a major update to catch up with our main competitor.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software team catching up with competitor"},{"definition":"To do work or tasks that you did not have time to do earlier (often followed by \"on\").","example":"I need to block out two hours this afternoon to catch up on my code reviews and emails.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer catching up on code reviews"},{"definition":"To talk to someone to find out the latest news about their life or work.","example":"Let''s schedule a brief meeting on Friday to catch up on the project''s progress.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team meeting to catch up on project progress"},{"definition":"To involve someone in a situation, often against their will (used in the passive: be/get caught up in).","example":"The lead engineer got caught up in administrative tasks and had no time to write code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Engineer caught up in administrative tasks"}]}]'::jsonb),
  ('check', 'Check', '["against","around / round","back","down","for","in","into","off","on","out","over","through","up","with"]'::jsonb, '[{"particle":"against","storageKeyPrefix":"checkAgainst","meanings":[{"definition":"To compare one thing with another to see if they match or to find differences.","example":"The finance team must check the monthly expenses against the budget.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Finance team comparing expenses against budget"}]},{"particle":"around / round","storageKeyPrefix":"checkAround","meanings":[{"definition":"To look in various places or ask several people for information (often to compare prices or options).","example":"We should check around for a cheaper cloud hosting provider before signing a contract.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team checking around for a cheaper cloud provider"}]},{"particle":"back","storageKeyPrefix":"checkBack","meanings":[{"definition":"To return later to see if something has happened or is ready.","example":"The system is still restarting; please check back in five minutes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"System restarting, check back later"}]},{"particle":"down","storageKeyPrefix":"checkDown","meanings":[{"definition":"To go down a list of options until you find one that works (often used in processes or sports).","example":"If the main database fails, the system will check down the list and connect to the backup server.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"System checking down a list to connect to backup server"}]},{"particle":"for","storageKeyPrefix":"checkFor","meanings":[{"definition":"To look closely to find a specific thing (often errors, signs, or problems).","example":"We ran automated tests to check for security bugs in the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Automated tests checking for security bugs"}]},{"particle":"in","storageKeyPrefix":"checkIn","meanings":[{"definition":"To register your arrival at a hotel, airport, or event.","example":"The CEO checked in at the hotel right before the leadership conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO checking in at a hotel"},{"definition":"To contact someone briefly to give an update or make sure everything is okay.","example":"Let''s check in on Friday to discuss the sprint results.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team checking in on Friday to discuss sprint results"},{"definition":"To upload or save source code to a version control system (like Git or SVN).","example":"Make sure to check in your Java code before you leave for the weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer checking in Java code to version control"},{"definition":"To leave your bags at the airport before a flight.","example":"I need to check in my heavy suitcase.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Passenger checking in a heavy suitcase"}]},{"particle":"into","storageKeyPrefix":"checkInto","meanings":[{"definition":"To arrive and register at a hotel, clinic, or hospital.","example":"We checked into the Hilton at 3:00 PM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Guests checking into the Hilton"},{"definition":"To investigate or look for more information about a problem.","example":"The application keeps crashing; the IT team needs to check into it immediately.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT team checking into a crashing application"}]},{"particle":"off","storageKeyPrefix":"checkOff","meanings":[{"definition":"To mark an item on a list to show that it has been completed or verified.","example":"After completing the code review, I checked off the task in Jira.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer checking off a task in Jira"}]},{"particle":"on","storageKeyPrefix":"checkOn","meanings":[{"definition":"To look at someone or something to make sure they are safe, progressing well, or in good condition.","example":"The manager stopped by to check on the new Java developers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager checking on new Java developers"}]},{"particle":"out","storageKeyPrefix":"checkOut","meanings":[{"definition":"To pay your bill and leave a hotel.","example":"We have to check out of our rooms by 11:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Guests checking out of hotel rooms"},{"definition":"To examine, investigate, or look at something interesting.","example":"You should check out this new Java framework; it could save us a lot of time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer checking out a new Java framework"},{"definition":"To prove to be true or correct after investigation.","example":"The server logs show no errors, so the user''s story doesn''t check out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server logs showing the user''s story doesn''t check out"},{"definition":"To pay for goods at a store or online.","example":"I added the books to my online cart and checked out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Customer checking out an online shopping cart"},{"definition":"To download or switch to a specific version of code from a repository (like Git).","example":"Please check out the feature-login branch and run the tests.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer checking out a Git branch"},{"definition":"To stop paying attention or disconnect mentally because you are tired or bored.","example":"The meeting was so long that half the team checked out after an hour.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team members mentally checked out during a long meeting"}]},{"particle":"over","storageKeyPrefix":"checkOver","meanings":[{"definition":"To examine something carefully from start to finish to find errors or problems.","example":"Please check over the business contract before you sign it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lawyer checking over a business contract"}]},{"particle":"through","storageKeyPrefix":"checkThrough","meanings":[{"definition":"To look at or read a collection of items carefully.","example":"I checked through the error logs to find where the Java exception happened.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer checking through error logs"},{"definition":"To send luggage directly to a final destination without needing to collect it during a connection.","example":"My bags were checked through all the way to Warsaw.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bags checked through to Warsaw"}]},{"particle":"up","storageKeyPrefix":"checkUp","meanings":[{"definition":"To investigate someone or something to discover what they are doing or if they are okay.","example":"The client called to check up on the progress of the software release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client checking up on software release progress"}]},{"particle":"with","storageKeyPrefix":"checkWith","meanings":[{"definition":"To ask someone for permission, advice, or information before doing something.","example":"You need to check with the project manager before changing the database structure.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer checking with project manager before changing database"}]}]'::jsonb),
  ('cheer', 'Cheer', '["against","for","off","on","up"]'::jsonb, '[{"particle":"against","storageKeyPrefix":"cheerAgainst","meanings":[{"definition":"To express a desire for someone or something to fail or lose.","example":"In a healthy business environment, you focus on improving your own product rather than cheering against your competitors.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team focused on improving their own product"}]},{"particle":"for","storageKeyPrefix":"cheerFor","meanings":[{"definition":"To publicly support a specific person, team, or idea, hoping they will succeed.","example":"Everyone in the office is cheering for the new software release to be a success.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Office team cheering for a software release"}]},{"particle":"off","storageKeyPrefix":"cheerOff","meanings":[{"definition":"To applaud or shout in support of someone as they are leaving a stage, field, or room.","example":"After 20 years with the company, the retiring manager was cheered off the stage by his colleagues.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Colleagues cheering off a retiring manager"}]},{"particle":"on","storageKeyPrefix":"cheerOn","meanings":[{"definition":"To encourage someone by shouting words of support, usually when they are competing or doing something difficult.","example":"The whole department went to the meeting to cheer her on during her final presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Department cheering on a presenter"}]},{"particle":"up","storageKeyPrefix":"cheerUp","meanings":[{"definition":"To start feeling happier; to stop being sad.","example":"You need to cheer up! The project delay is not a total disaster.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person cheering up after a project delay"},{"definition":"To make another person feel happier.","example":"We bought some coffee and cake to cheer the team up after a stressful week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team being cheered up with coffee and cake"}]}]'::jsonb),
  ('clean', 'Clean', '["around","away","down","off","out","up","up after"]'::jsonb, '[{"particle":"around","storageKeyPrefix":"cleanAround","meanings":[{"definition":"To wash or tidy the space near an object without moving the object itself.","example":"Don''t worry about moving the heavy cabinet; just clean around it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning around a heavy cabinet"}]},{"particle":"away","storageKeyPrefix":"cleanAway","meanings":[{"definition":"To remove dirt, rubbish, or objects to leave a space tidy.","example":"Please clean away the empty plates from the dining table.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning away empty plates from a dining table"}]},{"particle":"down","storageKeyPrefix":"cleanDown","meanings":[{"definition":"To wash an entire surface, usually from top to bottom.","example":"We need to clean down the walls before we start painting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning down walls before painting"}]},{"particle":"off","storageKeyPrefix":"cleanOff","meanings":[{"definition":"To remove dirt, marks, or a substance from a surface.","example":"Make sure to clean the mud off your boots before coming inside.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning mud off boots"}]},{"particle":"out","storageKeyPrefix":"cleanOut","meanings":[{"definition":"To empty and clean the inside of a space (like a room, cupboard, or box), usually by throwing away unwanted items.","example":"I spent my Saturday cleaning out the garage.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning out a garage"},{"definition":"To use or take all of someone''s money.","example":"Paying for those car repairs completely cleaned me out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Car repairs emptying a wallet"},{"definition":"To steal everything of value from a place.","example":"The thieves cleaned out the safe during the night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves cleaning out a safe"}]},{"particle":"up","storageKeyPrefix":"cleanUp","meanings":[{"definition":"To make a place or a person completely clean and tidy.","example":"We need to clean up the living room before our guests arrive.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning up a living room before guests arrive"},{"definition":"To make a large profit or a lot of money quickly.","example":"The retail company cleaned up during the holiday sales.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Retail company making large profits during holiday sales"},{"definition":"To stop crime, corruption, or bad behavior in a specific organization or area.","example":"The new mayor promised to clean up the city center.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New mayor promising to clean up the city center"}]},{"particle":"up after","storageKeyPrefix":"cleanUpAfter","meanings":[{"definition":"To remove the mess or dirt created by someone or something else.","example":"I am constantly cleaning up after my new puppy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cleaning up after a puppy"}]}]'::jsonb),
  ('come', 'Come', '["about","across","after","against","ahead","apart","around / round","away","back","behind","by","down","for","forward","in","into","off","on","out","over","through","to","together","up","with","without"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"comeAbout","meanings":[{"definition":"To happen or occur, especially in a way that is not planned","example":"How did this bug in the Java code come about?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer wondering how a bug appeared"}]},{"particle":"across","storageKeyPrefix":"comeAcross","meanings":[{"definition":"To find or meet something or someone by chance","example":"I came across an excellent article on Agile leadership yesterday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer finding an article by chance"},{"definition":"To give a specific impression to others","example":"She comes across as a very confident and capable manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A confident manager presenting to a team"}]},{"particle":"after","storageKeyPrefix":"comeAfter","meanings":[{"definition":"To chase or pursue someone (often to punish them or take something)","example":"If we break the NDA, the client''s legal team will come after us.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A legal team pursuing someone"},{"definition":"To follow in time or order","example":"Phase two of the project comes after the initial testing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project timeline showing phases in order"}]},{"particle":"against","storageKeyPrefix":"comeAgainst","meanings":[{"definition":"To face a difficult problem or strong opposition (come up against)","example":"We came up against several security issues during deployment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team facing security issues during deployment"}]},{"particle":"ahead","storageKeyPrefix":"comeAhead","meanings":[{"definition":"To finish in a winning, profitable, or advantageous position (come out ahead)","example":"Despite the economic crisis, our company came out ahead of the competition.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company finishing ahead of competitors"}]},{"particle":"apart","storageKeyPrefix":"comeApart","meanings":[{"definition":"To break into pieces or fail completely","example":"The legacy system is so old that its architecture is starting to come apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A legacy system architecture breaking apart"}]},{"particle":"around / round","storageKeyPrefix":"comeAround","meanings":[{"definition":"To change your opinion to agree with someone else","example":"He didn''t like the new Java framework at first, but he came around after seeing the performance tests.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer changing their opinion about a framework"},{"definition":"To visit someone at their home or desk","example":"The CEO is coming around to our department later this afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A CEO visiting a department"},{"definition":"To regain consciousness (wake up after fainting)","example":"He fainted from the heat, but he came round quickly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person regaining consciousness after fainting"}]},{"particle":"away","storageKeyPrefix":"comeAway","meanings":[{"definition":"To leave a place or situation with a specific feeling, idea, or result","example":"I came away from the strategy meeting feeling very optimistic about Q3.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person leaving a meeting feeling optimistic"},{"definition":"To separate or detach from something","example":"The back cover of the laptop just came away in my hands.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A laptop cover detaching unexpectedly"}]},{"particle":"back","storageKeyPrefix":"comeBack","meanings":[{"definition":"To return to a place, state, or topic","example":"Let''s come back to the budget discussion after lunch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team returning to a budget discussion"},{"definition":"To become popular or fashionable again","example":"Older, hierarchical management styles are not likely to come back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An old management style returning"}]},{"particle":"behind","storageKeyPrefix":"comeBehind","meanings":[{"definition":"To follow closely or to rank lower than something else in a list","example":"In the market share report, our main product comes behind theirs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A product ranking lower in a market share report"}]},{"particle":"by","storageKeyPrefix":"comeBy","meanings":[{"definition":"To get or obtain something, especially something that is rare or hard to find","example":"Experienced Senior Java Developers are hard to come by these days.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A recruiter searching for a rare senior developer"},{"definition":"To make a short, casual visit","example":"Please come by my office when you have a moment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person making a short visit to an office"}]},{"particle":"down","storageKeyPrefix":"comeDown","meanings":[{"definition":"To fall or decrease (prices, levels, etc.)","example":"Our cloud hosting costs have finally come down this month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A graph showing decreasing cloud hosting costs"},{"definition":"To make a firm decision or support a specific side","example":"The leadership team came down on the side of investing in AI.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A leadership team deciding to invest in AI"}]},{"particle":"for","storageKeyPrefix":"comeFor","meanings":[{"definition":"To arrive in order to collect someone or something","example":"The courier will come for the signed contracts at 3:00 PM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A courier arriving to collect signed contracts"}]},{"particle":"forward","storageKeyPrefix":"comeForward","meanings":[{"definition":"To offer help, information, or take responsibility","example":"We need two volunteers to come forward and lead the new internal project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Volunteers stepping forward to lead a project"}]},{"particle":"in","storageKeyPrefix":"comeIn","meanings":[{"definition":"To enter a room or building","example":"Please come in and take a seat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person entering a room"},{"definition":"To become relevant or involved in a situation","example":"The backend is finished, so this is where the frontend team comes in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A frontend team becoming involved in a project"},{"definition":"To arrive (news, money, results)","example":"The Q2 revenue reports just came in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Q2 revenue reports arriving"}]},{"particle":"into","storageKeyPrefix":"comeInto","meanings":[{"definition":"To inherit money or property","example":"He came into a lot of money and started his own software firm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person inheriting money to start a software firm"},{"definition":"To become a factor or take effect","example":"When designing this application, data privacy regulations must come into play.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Data privacy regulations coming into effect"}]},{"particle":"off","storageKeyPrefix":"comeOff","meanings":[{"definition":"To happen successfully or go exactly as planned","example":"The software launch came off without a single major bug.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A successful software launch"},{"definition":"To detach or be removed from something","example":"The label came off the server box, so we don''t know the serial number.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A label detaching from a server box"}]},{"particle":"on","storageKeyPrefix":"comeOn","meanings":[{"definition":"To start functioning (machines, systems, lights)","example":"When the power failed, the backup servers came on automatically.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Backup servers starting automatically after a power failure"},{"definition":"To make progress or improve","example":"The junior developer''s coding skills are really coming on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A junior developer improving their coding skills"},{"definition":"Used to encourage someone to hurry up, try harder, or stop being unreasonable","example":"Come on, we can finish this sprint today if we focus!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team being encouraged to finish a sprint"}]},{"particle":"out","storageKeyPrefix":"comeOut","meanings":[{"definition":"To be published, released, or made available to the public","example":"The next version of the Java Development Kit comes out next month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A new version of the Java Development Kit being released"},{"definition":"To become known (often secrets or truth)","example":"It eventually came out that the project was severely underfunded.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The truth about an underfunded project coming out"},{"definition":"To be removed (like a stain)","example":"The coffee stain won''t come out of the carpet.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A coffee stain on a carpet that will not come out"}]},{"particle":"over","storageKeyPrefix":"comeOver","meanings":[{"definition":"To visit someone''s house, office, or country","example":"The regional manager is coming over from London next week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A regional manager traveling from London for a visit"},{"definition":"To affect someone suddenly with a strong feeling","example":"A sudden wave of panic came over him before his presentation to the board.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person overwhelmed by panic before a board presentation"}]},{"particle":"through","storageKeyPrefix":"comeThrough","meanings":[{"definition":"To successfully complete or survive a difficult situation","example":"Thanks to strong leadership, the company came through the financial crisis.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company surviving a financial crisis"},{"definition":"To deliver what was promised or expected","example":"The engineering team came through with the bug fix right before the deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An engineering team delivering a bug fix on time"},{"definition":"To be approved or to arrive (official documents, messages)","example":"My visa approval finally came through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A visa approval document arriving"}]},{"particle":"to","storageKeyPrefix":"comeTo","meanings":[{"definition":"To reach a total amount","example":"The total cost for the new software licenses comes to $15,000.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A bill for software licenses totalling $15,000"},{"definition":"To reach a state, decision, or situation","example":"After hours of negotiation, we finally came to an agreement.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team reaching an agreement after negotiation"},{"definition":"To regain consciousness","example":"When he came to in the hospital, he asked for his laptop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person regaining consciousness in hospital"},{"definition":"Concerning a specific topic (when it comes to)","example":"When it comes to team management, communication is the most important skill.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team discussing management and communication"}]},{"particle":"together","storageKeyPrefix":"comeTogether","meanings":[{"definition":"To unite as a group for a common purpose","example":"The entire IT department came together to resolve the server outage.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An IT department uniting to resolve a server outage"},{"definition":"To begin to form a coherent, successful whole","example":"After weeks of messy coding, the final application is finally coming together.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An application coming together after weeks of development"}]},{"particle":"up","storageKeyPrefix":"comeUp","meanings":[{"definition":"To be mentioned or discussed in conversation","example":"The topic of remote work came up during the board meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Remote work being discussed at a board meeting"},{"definition":"To happen unexpectedly (often causing a problem)","example":"I have to cancel our 1-on-1 meeting; something urgent has come up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An urgent issue coming up unexpectedly"},{"definition":"To approach in time","example":"We need to prepare; the final project deadline is coming up fast.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project deadline approaching fast"}]},{"particle":"with","storageKeyPrefix":"comeWith","meanings":[{"definition":"To be included as part of a product, package, or deal","example":"The enterprise software license comes with 24/7 technical support.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An enterprise software license with technical support included"}]},{"particle":"without","storageKeyPrefix":"comeWithout","meanings":[{"definition":"To lack a feature or item that is normally included","example":"The basic version of the app comes without the advanced analytics dashboard.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A basic app version missing the analytics dashboard"}]}]'::jsonb),
  ('count', 'Count', '["against","back","down","for","in","off","on","out","up"]'::jsonb, '[{"particle":"against","storageKeyPrefix":"countAgainst","meanings":[{"definition":"To be considered a disadvantage or a negative point for someone.","example":"His lack of management experience might count against him in the job interview.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lack of experience counting against a job applicant"}]},{"particle":"back","storageKeyPrefix":"countBack","meanings":[{"definition":"To count backwards from a specific number or date to calculate something.","example":"To figure out when the project started, we need to count back six weeks from today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Counting back weeks on a calendar"}]},{"particle":"down","storageKeyPrefix":"countDown","meanings":[{"definition":"To say numbers backwards to zero, usually before a big event.","example":"The crowd started to count down from ten before the rocket launch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Crowd counting down before a rocket launch"},{"definition":"To wait eagerly for an event to happen.","example":"We are counting down the days until our summer holiday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Counting down the days until summer holiday"}]},{"particle":"for","storageKeyPrefix":"countFor","meanings":[{"definition":"To have a specific level of importance or value.","example":"Good communication skills count for a lot in a software development team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Communication skills counting for a lot in a team"},{"definition":"To be worth something (often used with \"nothing\" or \"something\").","example":"Does all my hard work count for nothing?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hard work counting for nothing"}]},{"particle":"in","storageKeyPrefix":"countIn","meanings":[{"definition":"To include someone in an activity, group, or plan.","example":"If you are ordering pizza for lunch, please count me in!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being counted in for a group pizza order"}]},{"particle":"off","storageKeyPrefix":"countOff","meanings":[{"definition":"To say numbers aloud in order, usually to divide a group of people into smaller teams.","example":"The coach asked the players to count off by threes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Players counting off by threes"}]},{"particle":"on","storageKeyPrefix":"countOn","meanings":[{"definition":"To depend or rely on someone to do something.","example":"You can always count on Sarah to help you finish the report on time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Relying on a colleague to finish a report on time"},{"definition":"To expect something to happen and base your plans on it.","example":"We didn''t count on it raining so heavily during our outdoor meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Unexpected heavy rain at an outdoor meeting"}]},{"particle":"out","storageKeyPrefix":"countOut","meanings":[{"definition":"To not include someone in an activity or plan.","example":"I feel too sick to go to the dinner party, so count me out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Being counted out of a dinner party due to illness"},{"definition":"To count things one by one, often when distributing them (like money).","example":"The cashier slowly counted out the coins and gave me my change.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cashier counting out coins for change"},{"definition":"(In boxing) To declare a fighter defeated because they cannot stand up before the referee counts to ten.","example":"The champion hit him hard, and the referee counted him out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Referee counting out a boxer"}]},{"particle":"up","storageKeyPrefix":"countUp","meanings":[{"definition":"To add things together to find the total amount.","example":"Please count up all the expenses from the business trip.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Counting up business trip expenses"}]}]'::jsonb),
  ('cut', 'Cut', '["off","on","up","down","in","into","out","away","across","back","together","apart","over","ahead","through","about / round","to","against"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"cutOff","meanings":[{"definition":"To remove something by cutting.","example":"He cut off the tags from his new shirt.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Removing tags from a new shirt"},{"definition":"To interrupt someone speaking.","example":"She cut me off mid-sentence to correct a date.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person interrupting a conversation"},{"definition":"To stop providing a service or supply.","example":"The electric company cut off our power because of an unpaid bill.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An electricity supply being cut off"},{"definition":"To isolate or block access to a place.","example":"The heavy snowstorm cut off the mountain village from the main road.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A village isolated by a snowstorm"},{"definition":"To block another vehicle''s path aggressively.","example":"A white van cut me off on the highway, forcing me to brake hard.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A van cutting off another vehicle on a highway"},{"definition":"To disinherit or stop giving someone money.","example":"His wealthy parents finally cut him off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Parents cutting off financial support"}]},{"particle":"on","storageKeyPrefix":"cutOn","meanings":[{"definition":"To turn on a device or switch (Regional/Southern US).","example":"Can you cut on the lights? It''s getting dark in here.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Turning on the lights in a room"}]},{"particle":"up","storageKeyPrefix":"cutUp","meanings":[{"definition":"To chop into small pieces.","example":"Could you cut up the carrots for the stew?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Chopping carrots into small pieces"},{"definition":"To act silly or cause a playful disruption (Informal).","example":"The students were cutting up in the back of the classroom.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Students being silly in a classroom"},{"definition":"To deeply upset someone emotionally (often passive).","example":"He was really cut up about failing his certification exam.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person feeling upset after failing an exam"},{"definition":"To severely criticize.","example":"The reviewers absolutely cut the new software release up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Reviewers harshly criticizing a software release"},{"definition":"To drive aggressively across someone''s path (UK Informal).","example":"That driver just cut me up on the roundabout.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A driver cutting in front of another on a roundabout"}]},{"particle":"down","storageKeyPrefix":"cutDown","meanings":[{"definition":"To cause something to fall by cutting.","example":"The city cut down the old oak tree because it was rotting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Felling a rotting oak tree"},{"definition":"To reduce the amount or frequency of something.","example":"I''m trying to cut down on caffeine before bed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person reducing their caffeine intake"},{"definition":"To kill or severely injure someone (often in a literary or tragic context).","example":"The young soldiers were cut down in their prime.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldiers falling in battle"}]},{"particle":"in","storageKeyPrefix":"cutIn","meanings":[{"definition":"To interrupt a conversation.","example":"Do you mind if I cut in with a quick question?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person interrupting a conversation with a question"},{"definition":"To move suddenly in front of another vehicle or person.","example":"The sports car cut in far too closely.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A sports car cutting in front of another vehicle"},{"definition":"To include someone in a deal or share of profits.","example":"Since you brought us the client, we''ll cut you in on the commission.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Colleagues sharing a commission deal"},{"definition":"To automatically start operating (referring to machines).","example":"When the temperature drops, the backup heater cuts in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A backup heater automatically starting up"},{"definition":"To interrupt a dancing couple to take over as a partner.","example":"May I cut in?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person asking to cut in on a dancing couple"}]},{"particle":"into","storageKeyPrefix":"cutInto","meanings":[{"definition":"To slice or penetrate a physical object.","example":"The sharp wire cut into my skin.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A sharp wire cutting into skin"},{"definition":"To consume a portion of something valuable such as time, money, or profits.","example":"The server outages are cutting into our quarterly profits.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server outages reducing quarterly profits"},{"definition":"To interrupt (similar to cut in).","example":"I don''t want to cut into your lunch break, but this is urgent.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person apologetically interrupting a lunch break"}]},{"particle":"out","storageKeyPrefix":"cutOut","meanings":[{"definition":"To remove a shape or part by cutting.","example":"She cut out an interesting article from the newspaper.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cutting an article out of a newspaper"},{"definition":"To stop eating or doing something completely.","example":"My doctor told me to cut out sugar.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person eliminating sugar from their diet"},{"definition":"To suddenly stop working (referring to engines or machines).","example":"The car engine cut out halfway up the hill.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A car engine stalling on a hill"},{"definition":"To exclude someone.","example":"They completely cut me out of the decision-making process.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person being excluded from a group decision"},{"definition":"To be naturally suited for something (usually negative and passive).","example":"After three weeks, he realized he wasn''t cut out for sales.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person realizing they are not suited for sales"}]},{"particle":"away","storageKeyPrefix":"cutAway","meanings":[{"definition":"To remove the outer or unwanted parts by cutting.","example":"The surgeon carefully cut away the damaged tissue.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A surgeon removing damaged tissue"},{"definition":"To suddenly shift the camera to another scene (Film/Media).","example":"The broadcast cut away to a reporter live at the scene.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A broadcast cutting to a live reporter"}]},{"particle":"across","storageKeyPrefix":"cutAcross","meanings":[{"definition":"To take a shortcut across an area.","example":"We cut across the park to get to the station faster.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People cutting across a park to reach a station"},{"definition":"To affect or apply to multiple different groups, transcending boundaries.","example":"The demand for flexible working conditions cuts across all departments.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A workplace policy affecting all departments"}]},{"particle":"back","storageKeyPrefix":"cutBack","meanings":[{"definition":"To reduce spending, production, or consumption.","example":"The company is cutting back on hiring this quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company reducing its hiring budget"},{"definition":"To prune a plant to control its growth.","example":"We need to cut back the rose bushes before winter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Pruning rose bushes before winter"},{"definition":"To return to a previous scene (Film/Media).","example":"The movie cuts back to the protagonist''s childhood.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A film cutting back to a childhood scene"}]},{"particle":"together","storageKeyPrefix":"cutTogether","meanings":[{"definition":"To edit film or audio by joining distinct pieces.","example":"The marketing team cut together a fast-paced promotional video.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A marketing team editing a promotional video"}]},{"particle":"apart","storageKeyPrefix":"cutApart","meanings":[{"definition":"To separate or dismantle by cutting.","example":"They cut the old ship apart for scrap metal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Workers dismantling an old ship for scrap"},{"definition":"To severely criticize or destroy an argument.","example":"The defense attorney cut the witness''s testimony apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A defense attorney dismantling a witness''s testimony"}]},{"particle":"over","storageKeyPrefix":"cutOver","meanings":[{"definition":"To switch from an old system to a new one (IT/Business context).","example":"The engineering team will cut over to the new cloud servers at midnight.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An engineering team migrating to new cloud servers"}]},{"particle":"ahead","storageKeyPrefix":"cutAhead","meanings":[{"definition":"To move in front of others in a line unethically.","example":"A group of teenagers tried to cut ahead of us in the queue.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teenagers cutting ahead in a queue"}]},{"particle":"through","storageKeyPrefix":"cutThrough","meanings":[{"definition":"To take a shortcut through an area.","example":"Let''s cut through the alley to avoid the main street traffic.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People taking a shortcut through an alley"},{"definition":"To quickly deal with or bypass obstacles and bureaucracy.","example":"We hired a local consultant to cut through the legal red tape.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A consultant cutting through legal bureaucracy"},{"definition":"To penetrate a barrier such as sound, darkness, or confusion.","example":"The siren cut through the silence of the night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A siren cutting through the night silence"}]},{"particle":"about / round","storageKeyPrefix":"cutAbout","meanings":[{"definition":"To move or run around actively or aimlessly (UK Informal).","example":"The kids were cutting about the garden all afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Children running around a garden"},{"definition":"To take a quick shortcut around an obstacle.","example":"If we cut round the back of the building, we''ll miss the crowd.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People cutting round the back of a building"}]},{"particle":"to","storageKeyPrefix":"cutTo","meanings":[{"definition":"To skip ahead to a specific, more important point.","example":"Let''s cut to the chase and discuss the budget.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People cutting to the main point in a discussion"},{"definition":"To shift to a new scene (Film/Media scriptwriting).","example":"The hero falls asleep. Cut to: interior, office, daytime.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A film script directing a scene cut"}]},{"particle":"against","storageKeyPrefix":"cutAgainst","meanings":[{"definition":"To go against the grain, expectations, or natural order.","example":"His decision to expand the business cuts against the current economic trends.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A business decision going against economic trends"}]}]'::jsonb),
  ('deal', 'Deal', '["around / round","away","by","in","into","out","to","with"]'::jsonb, '[{"particle":"around / round","storageKeyPrefix":"dealAround","meanings":[{"definition":"To give a share of something to everyone present in a circle or group.","example":"Please deal the documents around so everyone has a copy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dealing documents around so everyone has a copy"}]},{"particle":"away","storageKeyPrefix":"dealAway","meanings":[{"definition":"To give something away in a trade or negotiation, often losing a valuable asset.","example":"The company dealt away its most profitable division to pay off debts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company dealing away its most profitable division"}]},{"particle":"by","storageKeyPrefix":"dealBy","meanings":[{"definition":"To treat someone in a particular way (formal / old-fashioned).","example":"She always felt that she had been dealt by unfairly in the promotion process.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person feeling dealt by unfairly in a promotion process"}]},{"particle":"in","storageKeyPrefix":"dealIn","meanings":[{"definition":"To buy and sell specific products as a business.","example":"His store deals in rare books and antique maps.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Store dealing in rare books and antique maps"},{"definition":"To include someone in an activity, especially a card game.","example":"We are going to start the next game of poker. Deal me in!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Player being dealt into a poker game"}]},{"particle":"into","storageKeyPrefix":"dealInto","meanings":[{"definition":"To physically or metaphorically include someone in a group or game (very similar to \"deal in\").","example":"Pull up a chair and we will deal you into the game.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dealing someone into a card game"}]},{"particle":"out","storageKeyPrefix":"dealOut","meanings":[{"definition":"To distribute or share things among a group of people.","example":"The manager dealt out the new project assignments to the team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager dealing out project assignments to the team"},{"definition":"To give a punishment to someone.","example":"The judge dealt out a very harsh sentence for the crime.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Judge dealing out a harsh sentence"}]},{"particle":"to","storageKeyPrefix":"dealTo","meanings":[{"definition":"To punish, attack someone, or take strong action to fix a problem (Regional: Australia / New Zealand).","example":"If the server keeps crashing, the IT department will have to deal to it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT department dealing to a crashing server"}]},{"particle":"with","storageKeyPrefix":"dealWith","meanings":[{"definition":"To take action to solve a problem or complete a task.","example":"I have a lot of emails to deal with this morning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person dealing with a lot of emails in the morning"},{"definition":"To do business with someone or an organization.","example":"Our company only deals with local suppliers to reduce shipping costs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company dealing with local suppliers"},{"definition":"To be about a specific subject.","example":"This training course deals with effective management techniques.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Training course dealing with management techniques"},{"definition":"To manage or handle difficult emotions or situations.","example":"It can be hard to deal with stress when you have a tight deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person dealing with stress under a tight deadline"}]}]'::jsonb),
  ('do', 'Do', '["about","away","by","down","for","in","into","out","over","to","up","with","without"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"doAbout","meanings":[{"definition":"To take action to fix a problem.","example":"The project deadline is at risk; what are we going to do about it?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team discussing what to do about a project deadline at risk"}]},{"particle":"away","storageKeyPrefix":"doAway","meanings":[{"definition":"To abolish, get rid of, or stop using something.","example":"Many companies are trying to do away with paper receipts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Companies doing away with paper receipts"},{"definition":"To kill someone or an animal (informal).","example":"The villain in the movie planned to do away with the king.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Villain planning to do away with the king"}]},{"particle":"by","storageKeyPrefix":"doBy","meanings":[{"definition":"To treat someone in a particular way (almost always used in the phrase \"do right by\" or \"do well by\" someone).","example":"As a leader, you must always try to do right by your team members.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leader trying to do right by their team members"}]},{"particle":"down","storageKeyPrefix":"doDown","meanings":[{"definition":"To criticize someone unfairly, making them or yourself seem less successful or important.","example":"Stop doing yourself down; you gave an excellent presentation today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being told to stop doing themselves down after a presentation"},{"definition":"To cheat someone, usually in a business deal.","example":"The mechanic tried to do me down on the cost of the car repairs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Mechanic trying to do a customer down on car repair costs"}]},{"particle":"for","storageKeyPrefix":"doFor","meanings":[{"definition":"To severely damage, ruin, or kill (usually used in the passive \"be done for\").","example":"If the manager catches us sleeping at our desks, we are done for.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employees worried about being done for if caught sleeping at desks"}]},{"particle":"in","storageKeyPrefix":"doIn","meanings":[{"definition":"To make someone extremely tired (exhaust).","example":"That 10-kilometer run really did me in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Runner exhausted after a 10-kilometer run that did them in"},{"definition":"To injure a body part.","example":"I did my back in while moving that heavy sofa.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person who did their back in while moving a heavy sofa"},{"definition":"To kill or murder (informal).","example":"The gang threatened to do him in if he went to the police.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Gang threatening to do someone in if they go to the police"}]},{"particle":"into","storageKeyPrefix":"doInto","meanings":[{"definition":"To translate a piece of text into another language (formal and slightly old-fashioned).","example":"The ancient poem was done into English by a famous scholar.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Scholar doing an ancient poem into English"}]},{"particle":"out","storageKeyPrefix":"doOut","meanings":[{"definition":"To clean or decorate a room thoroughly.","example":"I need to do out the kitchen cupboards this weekend; they are so messy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person doing out messy kitchen cupboards"},{"definition":"To cheat someone in order to take something from them (do someone out of something).","example":"He lied on the contract to do his business partner out of his share of the money.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person lying on a contract to do their business partner out of money"}]},{"particle":"over","storageKeyPrefix":"doOver","meanings":[{"definition":"To do something again because it was wrong the first time (mainly US English).","example":"This financial report is full of mistakes; you need to do it over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee needing to do a financial report over due to mistakes"},{"definition":"To attack and beat someone up (UK informal).","example":"He got done over by a group of angry football fans.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person who got done over by angry football fans"},{"definition":"To burgle or rob a place (UK informal).","example":"Their apartment was done over while they were on holiday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Apartment done over while owners were on holiday"}]},{"particle":"to","storageKeyPrefix":"doTo","meanings":[{"definition":"To treat someone in a certain way, usually causing harm, damage, or change.","example":"I can''t believe what the hairdresser did to my hair!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shocked by what the hairdresser did to their hair"}]},{"particle":"up","storageKeyPrefix":"doUp","meanings":[{"definition":"To fasten or tie clothes, shoelaces, or seatbelts.","example":"It is very cold outside, so make sure to do up your coat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person doing up their coat in cold weather"},{"definition":"To repair, decorate, or renovate a building or room.","example":"They bought an old, ruined house to do it up and sell it for a profit.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People doing up an old ruined house to sell for profit"},{"definition":"To wrap a parcel or gift.","example":"I need to do up this present with a nice red ribbon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person doing up a present with a red ribbon"}]},{"particle":"with","storageKeyPrefix":"doWith","meanings":[{"definition":"To need or want something (always used with \"could\" or \"can\").","example":"I could really do with a hot cup of coffee right now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person who could really do with a hot cup of coffee"},{"definition":"To have a connection or relationship with (often used as \"have something/nothing to do with\").","example":"The software bug has nothing to do with the recent system update.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer explaining the bug has nothing to do with the system update"}]},{"particle":"without","storageKeyPrefix":"doWithout","meanings":[{"definition":"To manage to survive or continue even when you do not have something you need.","example":"We have no milk left for the coffee, so we will just have to do without.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People having to do without milk for their coffee"}]}]'::jsonb),
  ('dress', 'Dress', '["back","by","down","off","on","out","up"]'::jsonb, '[{"particle":"back","storageKeyPrefix":"dressBack","meanings":[{"definition":"To step backward in order to form a straight line (military / marching context).","example":"The front row had to dress back to give the others more space.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Front row stepping backward to form a straight line"}]},{"particle":"by","storageKeyPrefix":"dressBy","meanings":[{"definition":"To use a specific person or point on one side as a guide to form a straight line (military / marching context).","example":"The marching band had to dress by the right.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Marching band aligning by a reference point on the right"}]},{"particle":"down","storageKeyPrefix":"dressDown","meanings":[{"definition":"To wear clothes that are more informal or casual than what you usually wear.","example":"My company allows us to dress down on Fridays and wear jeans.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person wearing casual clothes on a casual Friday"},{"definition":"To strongly criticize or scold someone because they did something wrong.","example":"The manager dressed down the team for missing the important deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager scolding team for missing a deadline"}]},{"particle":"off","storageKeyPrefix":"dressOff","meanings":[{"definition":"To use a specific reference point to form a straight line in a formation (military / marching context).","example":"The soldiers were ordered to dress off the right flank.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldiers aligning off the right flank"}]},{"particle":"on","storageKeyPrefix":"dressOn","meanings":[{"definition":"To use a specific person or point directly as a guide to align a formation (military / marching context).","example":"The captain ordered the soldiers to dress on the center guide.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldiers aligning on the center guide"}]},{"particle":"out","storageKeyPrefix":"dressOut","meanings":[{"definition":"To put on a sports uniform or equipment to get ready to play in a game.","example":"Only twenty players will dress out for the football game this weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Football players putting on uniforms before a game"},{"definition":"To clean and prepare an animal''s body so the meat can be eaten or sold.","example":"It took the hunters a few hours to dress out the deer they caught.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hunters preparing a deer after a hunt"}]},{"particle":"up","storageKeyPrefix":"dressUp","meanings":[{"definition":"To wear formal, elegant, or special clothes, usually for an event.","example":"We are going to a fancy restaurant tonight, so we need to dress up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People dressed up for a fancy restaurant"},{"definition":"To put on a costume to look like someone or something else.","example":"The children decided to dress up as pirates and princesses.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Children dressed up as pirates and princesses"},{"definition":"To make something look more attractive, interesting, or better than it really is.","example":"You can dress up a plain soup by adding some fresh herbs and cream.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Plain soup made more attractive with fresh herbs and cream"}]}]'::jsonb),
  ('drop', 'Drop', '["across","around / round","away","back","behind","by","down","in","into","off","on","out","over","through","to"]'::jsonb, '[{"particle":"across","storageKeyPrefix":"dropAcross","meanings":[{"definition":"To happen to find or meet (very rare / old-fashioned; \"come across\" is almost always preferred today).","example":"I dropped across an old project file on the server.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person unexpectedly finding an old project file"}]},{"particle":"around / round","storageKeyPrefix":"dropAround","meanings":[{"definition":"To visit someone informally.","example":"I will drop round the office tomorrow to sign the final contracts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person making an informal visit to the office"}]},{"particle":"away","storageKeyPrefix":"dropAway","meanings":[{"definition":"To become weaker, smaller, or gradually disappear.","example":"Public interest in the old software version slowly dropped away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Graph showing declining public interest over time"}]},{"particle":"back","storageKeyPrefix":"dropBack","meanings":[{"definition":"To return to a lower position or level.","example":"Our company\\''s market share dropped back to second place this quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Chart showing a company\\''s market share dropping back to second place"},{"definition":"To move into a position behind someone else (like in a race).","example":"The runner dropped back because he was exhausted.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Exhausted runner falling behind others in a race"}]},{"particle":"behind","storageKeyPrefix":"dropBehind","meanings":[{"definition":"To fail to keep up with others; to fall behind a schedule.","example":"We have dropped behind schedule on the latest software release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team falling behind schedule on a software release"}]},{"particle":"by","storageKeyPrefix":"dropBy","meanings":[{"definition":"To make a short, informal visit (similar to \"drop in\").","example":"Please drop by my desk later so we can discuss the leadership training.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person making a brief informal visit to a colleague\\''s desk"}]},{"particle":"down","storageKeyPrefix":"dropDown","meanings":[{"definition":"To fall or move to a lower position.","example":"Please select your country from the drop-down menu in the application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"User selecting a country from a drop-down menu in an application"}]},{"particle":"in","storageKeyPrefix":"dropIn","meanings":[{"definition":"To make a short, informal visit without arranging it in advance.","example":"Feel free to drop in if you have any questions about the new code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person dropping in for an unplanned visit to ask questions"}]},{"particle":"into","storageKeyPrefix":"dropInto","meanings":[{"definition":"To visit a place briefly.","example":"I will drop into the IT department to pick up my new laptop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person briefly visiting the IT department to collect a laptop"},{"definition":"To accidentally fall into a habit or state.","example":"It is easy to drop into bad coding habits if you don\\''t do code reviews.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer falling into bad coding habits without code reviews"}]},{"particle":"off","storageKeyPrefix":"dropOff","meanings":[{"definition":"To take someone or something to a place and leave them there.","example":"I will drop off the management report at your office tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person leaving a management report at an office"},{"definition":"To decrease in level, amount, or quality.","example":"Software sales usually drop off during the summer holidays.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Graph showing software sales declining during summer holidays"},{"definition":"To fall asleep.","example":"The presentation was so boring that a few people dropped off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People falling asleep during a boring presentation"}]},{"particle":"on","storageKeyPrefix":"dropOn","meanings":[{"definition":"To criticize or punish someone suddenly (mainly UK, informal).","example":"The boss dropped on the development team for missing the deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Boss criticizing the development team for missing a deadline"},{"definition":"To accidentally meet someone or find something (informal).","example":"We dropped on a great solution for the Java bug.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team accidentally discovering a solution to a Java bug"}]},{"particle":"out","storageKeyPrefix":"dropOut","meanings":[{"definition":"To stop participating or being involved in something.","example":"One of our main investors dropped out of the project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Investor deciding to leave a project"},{"definition":"To leave a school, college, or course before finishing.","example":"He dropped out of his business degree to start his own company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student leaving university to start a business"}]},{"particle":"over","storageKeyPrefix":"dropOver","meanings":[{"definition":"To visit someone informally at their location (often their home).","example":"Why don\\''t you drop over later to review the Java architecture together?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person visiting a colleague informally to review architecture"}]},{"particle":"through","storageKeyPrefix":"dropThrough","meanings":[{"definition":"To fail to happen or fail to be completed (\"fall through\" is much more common but \"drop through\" is sometimes used).","example":"The business merger dropped through at the last minute.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business merger falling through at the last minute"}]},{"particle":"to","storageKeyPrefix":"dropTo","meanings":[{"definition":"To decrease to a specific level or amount.","example":"The server response time dropped to 50 milliseconds after the update.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server response time decreasing to 50 milliseconds after an update"}]}]'::jsonb),
  ('eat', 'Eat', '["up","into","away","out","in","through","around / round","on","down","off"]'::jsonb, '[{"particle":"up","storageKeyPrefix":"eatUp","meanings":[{"definition":"To consume a meal or food completely.","example":"You need to eat up your vegetables before you can have dessert.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child eating up vegetables before dessert"},{"definition":"To consume a large amount of time, money, or resources.","example":"Heating this massive house eats up a large portion of my monthly salary.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Large house consuming a large portion of monthly salary on heating"},{"definition":"To enjoy something greatly, or to eagerly believe something without questioning it.","example":"The politician told the crowd exactly what they wanted to hear, and they ate it up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Crowd eagerly believing what a politician tells them"},{"definition":"To consume someone emotionally with negative feelings like guilt or jealousy.","example":"Keeping the secret from her best friend was slowly eating her up inside.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person consumed by guilt from keeping a secret"},{"definition":"To completely absorb, destroy, or defeat a competitor.","example":"The tech giant easily ate up the smaller startups in the area.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Tech giant absorbing smaller startups"}]},{"particle":"into","storageKeyPrefix":"eatInto","meanings":[{"definition":"To use up a portion of a valuable reserve, especially money or time.","example":"The unexpected plumbing repairs really ate into our vacation savings.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Plumbing repairs eating into vacation savings"},{"definition":"To gradually damage or destroy a surface through chemical action or corrosion.","example":"Without a protective coating, the salty sea air will quickly eat into the metal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Salty sea air corroding unprotected metal"}]},{"particle":"away","storageKeyPrefix":"eatAway","meanings":[{"definition":"To gradually destroy, erode, or consume something over time.","example":"Over thousands of years, the river slowly ate away the soft limestone.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"River eroding soft limestone over thousands of years"},{"definition":"To continuously bother, distress, or cause anxiety for someone (often used with \"at\").","example":"The stress of the upcoming trial was eating away at him.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person distressed by stress of an upcoming trial"}]},{"particle":"out","storageKeyPrefix":"eatOut","meanings":[{"definition":"To eat a meal at a restaurant or café rather than cooking at home.","example":"I am far too exhausted to cook, so let\\''s eat out tonight.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Couple eating out at a restaurant instead of cooking at home"}]},{"particle":"in","storageKeyPrefix":"eatIn","meanings":[{"definition":"To eat a meal at home instead of going to a restaurant.","example":"We are trying to stick to a tight budget, so we plan to eat in this weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Family eating in at home to stick to a budget"}]},{"particle":"through","storageKeyPrefix":"eatThrough","meanings":[{"definition":"To make a physical hole in something by biting, chewing, or corroding.","example":"During the winter, mice managed to eat through the drywall in the garage.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Mice eating through drywall in a garage during winter"},{"definition":"To exhaust or consume a massive supply of money or resources very rapidly.","example":"He ate through his entire inheritance in just three years of reckless spending.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person rapidly spending through an entire inheritance"}]},{"particle":"around / round","storageKeyPrefix":"eatAround","meanings":[{"definition":"To consume a meal while deliberately avoiding a specific ingredient on the plate.","example":"The child absolutely hated mushrooms and carefully ate around them.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child carefully eating around mushrooms on their plate"}]},{"particle":"on","storageKeyPrefix":"eatOn","meanings":[{"definition":"To gradually consume a large amount of leftover food over an extended period.","example":"We cooked a massive turkey for the holiday and will just eat on it for the rest of the week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Family eating leftover turkey over several days after the holiday"}]},{"particle":"down","storageKeyPrefix":"eatDown","meanings":[{"definition":"To graze pasture or grass until it is very short or completely gone.","example":"The herd of sheep completely ate down the grass in the lower field.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Herd of sheep grazing down the grass in a field"}]},{"particle":"off","storageKeyPrefix":"eatOff","meanings":[{"definition":"To remove a layer or surface by eating, chewing, or chemical corrosion.","example":"The dog chewed the furniture so aggressively that he ate the varnish off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dog chewing furniture and removing the varnish"}]}]'::jsonb),
  ('fall', 'Fall', '["about / around / round","apart","away","back","behind","down","for","in","into","off","on / upon","out","over","through","to"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"fallAbout","meanings":[{"definition":"To laugh uncontrollably (mostly British/Australian English).","example":"The whole team fell about laughing during the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Whole team laughing uncontrollably during a presentation"}]},{"particle":"apart","storageKeyPrefix":"fallApart","meanings":[{"definition":"To fail completely (systems, plans, or organizations).","example":"The software project fell apart due to poor management.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software project failing due to poor management"},{"definition":"To experience a serious emotional or mental breakdown.","example":"He fell apart after losing his leadership role.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person experiencing emotional breakdown after losing their leadership role"},{"definition":"To break into pieces because of poor condition.","example":"These old documents are starting to fall apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old documents breaking into pieces due to poor condition"}]},{"particle":"away","storageKeyPrefix":"fallAway","meanings":[{"definition":"To gradually decrease, fade, or disappear.","example":"Client interest fell away when the prices increased.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client interest declining as prices increase"},{"definition":"To break off and drop to the ground.","example":"The old plaster fell away from the ceiling.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old plaster falling away from the ceiling"},{"definition":"To slope downwards.","example":"The land falls away sharply behind the building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Land sloping downwards sharply behind a building"}]},{"particle":"back","storageKeyPrefix":"fallBack","meanings":[{"definition":"To retreat or move backwards (often military or strategic).","example":"Our competitors pushed hard, forcing us to fall back and rethink our strategy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team falling back and rethinking strategy under competitor pressure"},{"definition":"To rely on something as a backup plan when other things fail (fall back on).","example":"If the Java application fails, we have a backup system to fall back on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Backup system ready to fall back on if Java application fails"}]},{"particle":"behind","storageKeyPrefix":"fallBehind","meanings":[{"definition":"To fail to complete work or make payments on time.","example":"If you don''t manage your time well, you will fall behind on the project schedule.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person falling behind on project schedule due to poor time management"},{"definition":"To move slower than the rest of a group.","example":"She fell behind the other runners because her leg hurt.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Runner falling behind the group due to a leg injury"}]},{"particle":"down","storageKeyPrefix":"fallDown","meanings":[{"definition":"To be proven weak, inadequate, or incorrect (often an argument or plan).","example":"His business strategy falls down when you look at the financial data.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business strategy proven inadequate when examining financial data"},{"definition":"To drop to the ground (literal).","example":"The sign was not attached properly and fell down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sign falling down because it was not attached properly"}]},{"particle":"for","storageKeyPrefix":"fallFor","meanings":[{"definition":"To be tricked or deceived by a lie or scam.","example":"I can''t believe the manager fell for that obvious phishing email.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager falling for an obvious phishing email"},{"definition":"To fall deeply in love with someone.","example":"They met at a tech conference and fell for each other immediately.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people falling for each other at a tech conference"}]},{"particle":"in","storageKeyPrefix":"fallIn","meanings":[{"definition":"To collapse inwards (like a roof, wall, or ceiling).","example":"The roof of the old warehouse fell in under the heavy snow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old warehouse roof collapsing inwards under heavy snow"},{"definition":"To form a line (military).","example":"The sergeant ordered the soldiers to fall in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldiers forming a line after sergeant orders them to fall in"},{"definition":"To agree to a plan or join a group of people (fall in with).","example":"We decided to fall in with the director''s new strategy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team agreeing to fall in with the director''s new strategy"}]},{"particle":"into","storageKeyPrefix":"fallInto","meanings":[{"definition":"To start doing something by chance, rather than by plan (like a career).","example":"I didn''t study management; I just fell into it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person falling into a management career by chance rather than plan"},{"definition":"To be naturally divided into categories.","example":"The users of this software fall into three main groups.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software users naturally divided into three main groups"},{"definition":"To enter a specific state or condition.","example":"The building fell into ruin after years of neglect.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Building falling into ruin after years of neglect"}]},{"particle":"off","storageKeyPrefix":"fallOff","meanings":[{"definition":"To decrease in quantity, quality, or frequency.","example":"Product sales usually fall off during the summer holidays.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Product sales falling off during summer holidays"},{"definition":"To detach from something.","example":"The handle fell off the door.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Door handle falling off"}]},{"particle":"on / upon","storageKeyPrefix":"fallOn","meanings":[{"definition":"To become someone''s duty or responsibility.","example":"When the CEO resigned, the responsibility fell on the vice president.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Responsibility falling on the vice president after the CEO resigned"},{"definition":"To happen on a specific date.","example":"This year, the project deadline falls on a Friday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project deadline falling on a Friday this year"},{"definition":"To attack eagerly or suddenly.","example":"The press fell on the politician after the scandal broke.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Press attacking a politician eagerly after a scandal"},{"definition":"To experience difficult times (idiom: fall on hard times).","example":"The company fell on hard times during the recession.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company experiencing hard times during a recession"}]},{"particle":"out","storageKeyPrefix":"fallOut","meanings":[{"definition":"To have an argument and stop being friends or colleagues.","example":"The two founders fell out over the future direction of the company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two founders arguing and falling out over company direction"},{"definition":"To become detached and drop (usually hair or teeth).","example":"Stress can cause your hair to fall out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hair falling out due to stress"},{"definition":"To leave a formation (military).","example":"The troops were ordered to fall out and rest.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Troops ordered to fall out and rest from military formation"}]},{"particle":"over","storageKeyPrefix":"fallOver","meanings":[{"definition":"To collapse or drop to the ground.","example":"The server rack almost fell over during the earthquake.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server rack almost falling over during an earthquake"},{"definition":"To try extremely hard, often looking foolish, to do something (fall over oneself).","example":"Recruiters are falling over themselves to hire good Java developers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Recruiters eagerly competing to hire good Java developers"}]},{"particle":"through","storageKeyPrefix":"fallThrough","meanings":[{"definition":"To fail to happen or be completed (usually plans, deals, or projects).","example":"The merger fell through at the last minute due to legal issues.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Merger falling through at the last minute due to legal issues"}]},{"particle":"to","storageKeyPrefix":"fallTo","meanings":[{"definition":"To become someone''s duty or responsibility (similar to fall on).","example":"It falls to the senior developer to train the new team members.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Senior developer responsible for training new team members"},{"definition":"To start doing something energetically, especially eating or working.","example":"They fell to eating as soon as the food arrived.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People starting to eat energetically as soon as the food arrived"}]}]'::jsonb),
  ('figure', 'Figure', '["for","in","into","on","out","up"]'::jsonb, '[{"particle":"for","storageKeyPrefix":"figureFor","meanings":[{"definition":"To expect someone to be a certain type of person, or to make an assumption about their character.","example":"I figured him for a strict leader, but he is actually very relaxed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person figured for a strict leader but actually very relaxed"}]},{"particle":"in","storageKeyPrefix":"figureIn","meanings":[{"definition":"To include a specific detail or amount when making a calculation or plan.","example":"When estimating the project timeline, you must figure in the time needed for testing and fixing bugs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer figuring in time needed for testing and fixing bugs in project timeline estimate"}]},{"particle":"into","storageKeyPrefix":"figureInto","meanings":[{"definition":"To be a relevant factor or play a part in a situation, decision, or plan.","example":"The cost of hiring new developers did not figure into the original budget.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cost of hiring new developers not figured into original budget"}]},{"particle":"on","storageKeyPrefix":"figureOn","meanings":[{"definition":"To plan on something happening or expect something to be true.","example":"We figure on launching the new product by the end of the second quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team planning to launch new product by end of second quarter"},{"definition":"To rely on or trust someone/something.","example":"You can always figure on John to deliver his code on time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"John reliably delivering his code on time"}]},{"particle":"out","storageKeyPrefix":"figureOut","meanings":[{"definition":"To understand a problem and find a solution.","example":"It took the team three hours to figure out why the Java application was crashing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team working three hours to figure out why the Java application was crashing"},{"definition":"To calculate an amount or cost.","example":"We need to figure out exactly how much the new software licenses will cost.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team calculating the exact cost of new software licenses"},{"definition":"To understand someone''s character, behavior, or motives.","example":"I cannot figure our new manager out; she is very quiet and hard to read.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person trying to figure out their new manager''s quiet and hard to read character"}]},{"particle":"up","storageKeyPrefix":"figureUp","meanings":[{"definition":"To add numbers together to calculate a total amount.","example":"Let me figure up the total hours we spent on the server migration last month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer calculating total hours spent on server migration last month"}]}]'::jsonb),
  ('fill', 'Fill', '["down","in","out","up","with"]'::jsonb, '[{"particle":"down","storageKeyPrefix":"fillDown","meanings":[{"definition":"To copy data or formulas to the cells below (specific to software/business context like Excel).","example":"Select the top cell and fill down the formula to the bottom of the column.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Selecting top cell and filling down formula to bottom of column"}]},{"particle":"in","storageKeyPrefix":"fillIn","meanings":[{"definition":"To complete a form or document by writing required information.","example":"Please fill in this application form and return it to the HR department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person filling in application form to return to HR department"},{"definition":"To provide someone with missing information (fill someone in).","example":"I missed the morning meeting. Can you fill me in on what the team discussed?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Colleague filling in coworker on what the team discussed at the morning meeting"},{"definition":"To temporarily do someone else\\''s job because they are absent (fill in for).","example":"The lead developer is sick today, so I will fill in for him.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer filling in for sick lead developer"},{"definition":"To close a hole or empty space by putting a substance into it.","example":"The city workers finally filled in the hole in the street.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"City workers filling in the hole in the street"}]},{"particle":"out","storageKeyPrefix":"fillOut","meanings":[{"definition":"To complete a form or document (US English equivalent of \"fill in\").","example":"It took me an hour to fill out the tax documents.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person spending an hour to fill out the tax documents"},{"definition":"To become larger, heavier, or rounder (usually referring to a person gaining weight or muscle).","example":"He used to be very thin, but he has filled out since he started going to the gym.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person who has filled out since starting to go to the gym"}]},{"particle":"up","storageKeyPrefix":"fillUp","meanings":[{"definition":"To make something completely full, or to become completely full.","example":"We need to fill up the car with petrol before we start driving.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Filling up car with petrol before driving"},{"definition":"To eat enough food so that you are no longer hungry.","example":"Don''t fill up on bread before the main course arrives!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person told not to fill up on bread before main course arrives"}]},{"particle":"with","storageKeyPrefix":"fillWith","meanings":[{"definition":"To put a substance or object into a container until there is no more space.","example":"She filled the cup with coffee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person filling the cup with coffee"},{"definition":"To cause someone to feel a strong emotion.","example":"The successful software launch filled the team with pride.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Successful software launch filling the team with pride"}]}]'::jsonb),
  ('find', 'Find', '["out","for","against"]'::jsonb, '[{"particle":"out","storageKeyPrefix":"findOut","meanings":[{"definition":"To discover information, learn a fact, or solve a problem.","example":"We need to review the server logs to find out why the Java application is crashing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Reviewing server logs to find out why the Java application is crashing"},{"definition":"To discover that someone has lied, kept a secret, or done something wrong (separable: find someone out).","example":"He lied on his resume, but the HR department eventually found him out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"HR department finding out that employee lied on resume"}]},{"particle":"for","storageKeyPrefix":"findFor","meanings":[{"definition":"To make an official decision in favor of someone (formal, used in legal or official settings).","example":"After reviewing the contract, the judge found for the software developer and ordered the client to pay the invoice.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Judge finding for the software developer and ordering client to pay the invoice"}]},{"particle":"against","storageKeyPrefix":"findAgainst","meanings":[{"definition":"To make an official decision that someone is guilty or loses a dispute (formal, used in legal or official settings).","example":"The court found against the leadership team because they did not follow labor laws.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Court finding against the leadership team for not following labor laws"}]}]'::jsonb),
  ('get', 'Get', '["off","on","up","down","in","into","out","away","across","forward","back","by","together","with","over","ahead","after","behind","through","about / around","to"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"getOff","meanings":[{"definition":"To leave a form of public transport (bus, train, plane)","example":"We need to get off the train at the next station.","imageSrc":"images/phrasal_verbs/list/get/off/transport.png","imageAlt":"People getting off a train at a station"},{"definition":"To finish work","example":"I usually get off work at 5:00 PM.","imageSrc":"images/phrasal_verbs/list/get/off/work.png","imageAlt":"A person leaving the office at the end of the workday"},{"definition":"To escape punishment","example":"The manager made a huge mistake, but he got off with just a warning.","imageSrc":"images/phrasal_verbs/list/get/off/punishment.png","imageAlt":"A boss giving a warning to an employee"},{"definition":"To send something (like a letter or email)","example":"I will get this report off to the client before the end of the day.","imageSrc":"images/phrasal_verbs/list/get/off/send.png","imageAlt":"Sending a report by email and by post"}]},{"particle":"on","storageKeyPrefix":"getOn","meanings":[{"definition":"To step onto a form of public transport","example":"Hurry up and get on the bus before it leaves!","imageSrc":"images/phrasal_verbs/list/get/on/transport.png","imageAlt":"A person boarding a bus"},{"definition":"To make progress or handle a situation","example":"How are you getting on with the new Java project?","imageSrc":"images/phrasal_verbs/list/get/on/progress.png","imageAlt":"A person making progress on a project"},{"definition":"To have a good relationship (often \"get on with\")","example":"I get on very well with my team members.","imageSrc":"images/phrasal_verbs/list/get/on/relationship.png","imageAlt":"Team members having a good relationship"},{"definition":"To continue doing something","example":"Let''s stop chatting and get on with the meeting.","imageSrc":"images/phrasal_verbs/list/get/on/continue.png","imageAlt":"People continuing with a meeting"}]},{"particle":"up","storageKeyPrefix":"getUp","meanings":[{"definition":"To rise from bed after sleeping","example":"I get up at 6:30 AM every morning.","imageSrc":"images/phrasal_verbs/list/get/up/bed.png","imageAlt":"A person getting out of bed in the morning"},{"definition":"To stand up","example":"He got up from his desk to welcome the visitors.","imageSrc":"images/phrasal_verbs/list/get/up/desk.png","imageAlt":"A person standing up from their desk"},{"definition":"To organize or arrange something","example":"We need to get up a team to handle this new software update.","imageSrc":"images/phrasal_verbs/list/get/up/arrange.png","imageAlt":"People being organized into a team"}]},{"particle":"down","storageKeyPrefix":"getDown","meanings":[{"definition":"To move to a lower position","example":"You need to get down from that ladder before you fall.","imageSrc":"images/phrasal_verbs/list/get/down/climb_down.png","imageAlt":"A person climbing down a ladder"},{"definition":"To make someone feel sad or depressed","example":"This rainy weather is really getting me down.","imageSrc":"images/phrasal_verbs/list/get/down/sad.png","imageAlt":"A person feeling sad and depressed by rainy weather"},{"definition":"To write something","example":"Let me get your contact details down in my notebook.","imageSrc":"images/phrasal_verbs/list/get/down/write.png","imageAlt":"A person writing contact details in a notebook"},{"definition":"To start focusing on a task seriously (often \"get down to\")","example":"Enough small talk; let''s get down to business.","imageSrc":"images/phrasal_verbs/list/get/down/focus.png","imageAlt":"People getting down to business in a meeting"}]},{"particle":"in","storageKeyPrefix":"getIn","meanings":[{"definition":"To enter a car, room, or building","example":"Get in the car, we are going to be late.","imageSrc":"images/phrasal_verbs/list/get/in/car.png","imageAlt":"A person getting into a car"},{"definition":"To arrive (usually a train, flight, or arriving at home/work)","example":"What time does your flight get in?","imageSrc":"images/phrasal_verbs/list/get/in/arriving.jpg","imageAlt":"A flight arriving at an airport"},{"definition":"To be accepted into a school, club, or organization","example":"She applied to a top university and she got in.","imageSrc":"images/phrasal_verbs/list/get/in/accepted.png","imageAlt":"A student receiving an acceptance letter"},{"definition":"To submit something","example":"I need to get my expenses application in by Friday.","imageSrc":"images/phrasal_verbs/list/get/in/submit.png","imageAlt":"A person submitting an expenses application"}]},{"particle":"into","storageKeyPrefix":"getInto","meanings":[{"definition":"To become interested or involved in something","example":"I recently got into software development.","imageSrc":"images/phrasal_verbs/list/get/into/interest.png","imageAlt":"A person becoming interested in software development"},{"definition":"To enter a specific state or situation","example":"The company got into financial trouble last year.","imageSrc":"images/phrasal_verbs/list/get/into/state.png","imageAlt":"A company in financial trouble"},{"definition":"To start a habit","example":"I''ve got into the habit of checking my emails before breakfast.","imageSrc":"images/phrasal_verbs/list/get/into/hobby.png","imageAlt":"A person with a morning email-checking habit"}]},{"particle":"out","storageKeyPrefix":"getOut","meanings":[{"definition":"To leave a place or a car","example":"The fire alarm rang, and everyone got out of the building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People leaving a building after a fire alarm"},{"definition":"To become known (usually a secret or hidden information)","example":"The news of the CEO leaving got out to the press.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"News of a CEO leaving spreading to the press"},{"definition":"To produce or publish something","example":"We need to get this new application out by next month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team launching a new application"},{"definition":"To avoid doing something you do not want to do (often \"get out of\")","example":"He tried to get out of doing the presentation, but his boss said no.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person trying to avoid giving a presentation"}]},{"particle":"away","storageKeyPrefix":"getAway","meanings":[{"definition":"To escape","example":"The thief got away before the police arrived.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A thief escaping before police arrive"},{"definition":"To go on a holiday or take a break","example":"We are hoping to get away to the mountains for the weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A family going on a holiday to the mountains"},{"definition":"To do something wrong without being punished (often \"get away with\")","example":"He lied about his sales numbers, but he won''t get away with it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person lying about sales numbers without consequences"}]},{"particle":"across","storageKeyPrefix":"getAcross","meanings":[{"definition":"To communicate an idea successfully so people understand it","example":"The leader got her vision across perfectly during the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A leader communicating their vision during a presentation"},{"definition":"To physically cross a road, river, or space","example":"We need to get across the street.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People crossing a street"}]},{"particle":"forward","storageKeyPrefix":"getForward","meanings":[{"definition":"To move to the front (often used in sports to describe attacking)","example":"The team''s defenders need to get forward to help score a goal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Defenders moving forward to help score a goal"}]},{"particle":"back","storageKeyPrefix":"getBack","meanings":[{"definition":"To return to a place or a state","example":"When did you get back from your business trip?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person returning from a business trip"},{"definition":"To have something returned to you","example":"I finally got my laptop back from the IT department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person getting their laptop back from IT"},{"definition":"To return to a previous activity (often \"get back to\")","example":"I''ll answer that question later; let''s get back to the main topic.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People getting back to the main topic in a meeting"},{"definition":"To take revenge on someone (often \"get back at\")","example":"She wants to get back at her competitor by launching a better product.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person planning to outperform a competitor"}]},{"particle":"by","storageKeyPrefix":"getBy","meanings":[{"definition":"To manage to survive or do something with limited money, knowledge, or resources","example":"My Spanish isn''t perfect, but I know enough to get by.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person managing with limited resources"},{"definition":"To physically move past someone","example":"Excuse me, could you move a little so I can get by?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person trying to move past someone in a corridor"}]},{"particle":"together","storageKeyPrefix":"getTogether","meanings":[{"definition":"To meet socially","example":"Let''s get together for a coffee next week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Friends meeting for coffee"},{"definition":"To organize your thoughts, life, or things (often \"get your act together\")","example":"If he wants a promotion, he needs to get his act together and work harder.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person organizing their work and thoughts"}]},{"particle":"with","storageKeyPrefix":"getWith","meanings":[{"definition":"To understand or adapt to modern trends or new rules (informal)","example":"You need to get with the new management strategy, or you will be left behind.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person adapting to a new management strategy"}]},{"particle":"over","storageKeyPrefix":"getOver","meanings":[{"definition":"To recover from an illness, a shock, or a bad emotional experience","example":"It took him two weeks to get over the flu.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person recovering from the flu"},{"definition":"To overcome a problem or difficulty","example":"We need to get over this technical issue before the software launches.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team overcoming a technical issue"},{"definition":"To finish something unpleasant so you don\\''t have to worry about it (often \"get it over with\")","example":"I hate performance reviews, but let''s just do it and get it over with.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person finishing an unpleasant performance review"}]},{"particle":"ahead","storageKeyPrefix":"getAhead","meanings":[{"definition":"To be successful and make progress in your career or life","example":"She reads a lot of business books because she wants to get ahead in her career.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person reading business books to advance their career"}]},{"particle":"after","storageKeyPrefix":"getAfter","meanings":[{"definition":"To urge, remind, or scold someone to do something they are supposed to do","example":"I need to get after the developers to finish writing the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager urging developers to finish their work"},{"definition":"To chase someone or something","example":"The dog got after the cat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A dog chasing a cat"}]},{"particle":"behind","storageKeyPrefix":"getBehind","meanings":[{"definition":"To fall behind schedule or fail to keep up with work or payments","example":"I was sick for a week, and I got behind on my emails.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person falling behind on their emails after being sick"},{"definition":"To support a person, idea, or project","example":"The whole team got behind the new manager''s plan.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team supporting their manager''s plan"}]},{"particle":"through","storageKeyPrefix":"getThrough","meanings":[{"definition":"To finish a difficult task or survive a difficult period","example":"We just need to get through this busy week, and then we can relax.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People getting through a busy work week"},{"definition":"To make contact by telephone","example":"I tried to call customer service, but I couldn''t get through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person unable to reach customer service by phone"},{"definition":"To make someone understand something (often \"get through to\")","example":"I''ve explained the risks, but I just can''t get through to him.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person trying to make someone understand the risks"}]},{"particle":"about / around","storageKeyPrefix":"getAboutAround","meanings":[{"definition":"To travel to different places","example":"We used the subway to get around the city.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People using the subway to travel around a city"},{"definition":"To find a way to avoid a rule or solve a problem","example":"The programmers found a clever way to get around the security block.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Programmers finding a way around a security block"},{"definition":"To spread (usually news or rumors)","example":"Word gets around fast in this office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"News spreading quickly through an office"},{"definition":"To finally do something you have delayed doing (often \"get around to\")","example":"I will get around to updating my resume this weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person finally updating their resume"}]},{"particle":"to","storageKeyPrefix":"getTo","meanings":[{"definition":"To arrive at a destination","example":"What time did you get to the office this morning?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person arriving at the office in the morning"},{"definition":"To have the opportunity to do something","example":"Because of my job, I get to travel all over the world.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person traveling all over the world for their job"},{"definition":"To annoy or upset someone","example":"The constant complaining is really getting to me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person being annoyed by constant complaining"},{"definition":"To begin an action (often \"get to work\")","example":"The break is over; let''s get to work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People getting back to work after a break"}]}]'::jsonb),
  ('give', 'Give', '["away","back","in","in to","off","on / onto","out","over","up","(it) up for","with"]'::jsonb, '[{"particle":"away","storageKeyPrefix":"giveAway","meanings":[{"definition":"To provide something for free (as a gift or promotion)","example":"The software company is giving away free trials to new users.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A software company giving away free trials"},{"definition":"To reveal a secret or hidden information","example":"Please don''t give away our negotiation strategy to the competitors.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person revealing a secret strategy"},{"definition":"To betray someone or accidentally show their true identity or feelings","example":"He tried to hide his frustration, but his tone of voice gave him away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person whose tone of voice betrays their true feelings"},{"definition":"To formally hand over a bride at a wedding","example":"Her father gave her away at the ceremony.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A father walking his daughter down the aisle"}]},{"particle":"back","storageKeyPrefix":"giveBack","meanings":[{"definition":"To return something to its original owner","example":"You must give back the company laptop when you leave the job.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An employee returning a laptop to the company"},{"definition":"To contribute to society or a community after achieving success","example":"The successful manager likes to give back by mentoring junior developers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager mentoring junior developers"}]},{"particle":"in","storageKeyPrefix":"giveIn","meanings":[{"definition":"To finally agree to what someone wants after initially refusing (yield/surrender)","example":"Management finally gave in to the workers'' demands for flexible hours.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Management agreeing to workers demands"},{"definition":"To hand over or submit a document (mainly British English)","example":"Please give in your project reports by Friday afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An employee submitting a project report"}]},{"particle":"in to","storageKeyPrefix":"giveInTo","meanings":[{"definition":"To stop resisting a feeling, desire, or pressure","example":"The company gave in to market pressure and lowered its prices.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company yielding to market pressure"}]},{"particle":"off","storageKeyPrefix":"giveOff","meanings":[{"definition":"To produce or emit something physical (heat, light, smell) or an invisible feeling (a vibe/energy)","example":"The server room gives off a lot of heat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A server room emitting heat"}]},{"particle":"on / onto","storageKeyPrefix":"giveOnOnto","meanings":[{"definition":"To open in the direction of, or provide a view of (used for doors, windows, or rooms)","example":"The CEO''s office has large windows that give onto the city skyline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An office window with a view onto the city skyline"}]},{"particle":"out","storageKeyPrefix":"giveOut","meanings":[{"definition":"To distribute something to a group of people","example":"They were giving out informational flyers at the business conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person distributing flyers at a conference"},{"definition":"To stop working or fail completely (used for machines, supplies, or body parts)","example":"We couldn''t finish the presentation because the projector''s lamp gave out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A projector failing during a presentation"},{"definition":"To make information public","example":"The HR department will give out the details of the new health plan tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An HR department announcing new health plan details"}]},{"particle":"over","storageKeyPrefix":"giveOver","meanings":[{"definition":"To hand over control, responsibility, or possession of something","example":"The founder gave over control of the daily operations to the new CEO.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A founder handing over control to a new CEO"},{"definition":"To dedicate time or space to a specific purpose (usually passive: be given over to)","example":"The afternoon meeting was given over to brainstorming new Java applications.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A meeting dedicated entirely to brainstorming"},{"definition":"To stop doing something annoying (mainly British informal)","example":"Oh, give over! Stop complaining about the minor bugs in the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person telling someone to stop complaining"}]},{"particle":"up","storageKeyPrefix":"giveUp","meanings":[{"definition":"To stop trying to do something or accept defeat (surrender)","example":"The coding problem was incredibly difficult, but the developer didn''t give up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer persisting through a difficult coding problem"},{"definition":"To stop doing a regular habit","example":"I decided to give up drinking coffee late in the afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person deciding to stop drinking coffee"},{"definition":"To part with something valuable or give away your time","example":"We had to give up our weekend to finish the software release on time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team working over the weekend to finish a software release"},{"definition":"To surrender yourself to the authorities","example":"The hacker finally gave himself up to the police.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person surrendering to the police"}]},{"particle":"(it) up for","storageKeyPrefix":"giveItUpFor","meanings":[{"definition":"To applaud or clap for someone (used to welcome a speaker or performer)","example":"Let''s give it up for our keynote speaker!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An audience applauding a keynote speaker"}]},{"particle":"with","storageKeyPrefix":"giveWith","meanings":[{"definition":"To provide or tell information (informal/slang)","example":"Come on, give with the details! What happened during the board meeting?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person asking for details about a board meeting"}]}]'::jsonb),
  ('go', 'Go', '["off","on","up","down","in","into","out","away","across","forward","back","for","by","together","with","without","over","ahead","after","behind","through","about","around / round","to","against"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"goOff","meanings":[{"definition":"To explode or fire (a weapon or device)","example":"The bomb went off in the city center.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An explosion in a city center"},{"definition":"To make a sudden loud noise (an alarm)","example":"My morning alarm went off at 6:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An alarm clock going off in the morning"},{"definition":"To stop working or power down","example":"The lights went off during the storm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lights going off during a storm"},{"definition":"To spoil or go bad (food)","example":"This milk smells like it has gone off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Spoiled milk that has gone off"},{"definition":"To happen in a specific way","example":"The software presentation went off without any problems.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A successful software presentation"},{"definition":"To stop liking someone or something","example":"I used to love Java, but I''ve gone off it recently.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer who has lost interest in Java"},{"definition":"To leave a place","example":"The manager went off to a meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager leaving for a meeting"}]},{"particle":"on","storageKeyPrefix":"goOn","meanings":[{"definition":"To continue doing something","example":"Please go on with your code explanation; I am listening.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person continuing to explain something"},{"definition":"To happen or be taking place","example":"What is going on in the server room?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A server room with activity happening"},{"definition":"To start operating (power, lights, machines)","example":"The backup generator went on automatically.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A backup generator starting up automatically"},{"definition":"To talk too much or at excessive length about something","example":"He goes on and on about his leadership skills.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person talking excessively about their leadership"},{"definition":"To proceed to do something next after completing a previous action","example":"After fixing the bug, she went on to optimize the database.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer moving on to optimize the database"},{"definition":"To base an opinion or decision on something","example":"We don''t have much data to go on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team lacking data to base a decision on"}]},{"particle":"up","storageKeyPrefix":"goUp","meanings":[{"definition":"To increase or rise","example":"Software licensing prices have gone up this year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A graph showing rising software prices"},{"definition":"To be built or constructed","example":"New office buildings are going up in the business district.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New office buildings under construction"},{"definition":"To explode or catch fire","example":"The old factory went up in flames.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A factory going up in flames"}]},{"particle":"down","storageKeyPrefix":"goDown","meanings":[{"definition":"To decrease or fall","example":"Our server error rates went down last month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A graph showing decreasing server error rates"},{"definition":"To stop working (computers or systems)","example":"The entire network went down for two hours.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A network that has gone down"},{"definition":"To be remembered in a certain way","example":"He will go down in history as a great CEO.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A CEO being remembered in history"},{"definition":"To be received by an audience in a specific way","example":"The new management policy did not go down well with the team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team reacting poorly to a new management policy"},{"definition":"To set (the sun)","example":"We finished work just as the sun was going down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The sun setting as the workday ends"}]},{"particle":"in","storageKeyPrefix":"goIn","meanings":[{"definition":"To enter a place","example":"The door is open, so you can go in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person entering through an open door"},{"definition":"To be understood or remembered","example":"The complex instructions just didn''t go in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person struggling to understand complex instructions"},{"definition":"To become hidden (the sun going behind clouds)","example":"It suddenly got cold when the sun went in behind a cloud.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The sun disappearing behind a cloud"}]},{"particle":"into","storageKeyPrefix":"goInto","meanings":[{"definition":"To discuss or explain something in detail","example":"Let''s not go into the budget problems right now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People choosing not to discuss budget problems"},{"definition":"To enter a specific profession or business","example":"She decided to go into project management.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person entering the project management profession"},{"definition":"To crash or collide with something","example":"The car lost control and went into a tree.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A car crashing into a tree"},{"definition":"To enter a specific state or condition","example":"The company went into liquidation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company entering liquidation"}]},{"particle":"out","storageKeyPrefix":"goOut","meanings":[{"definition":"To leave home for a social event or activity","example":"We are going out for dinner to celebrate the launch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team going out for a celebratory dinner"},{"definition":"To stop burning or shining (fire or lights)","example":"The fire went out because we forgot to add wood.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A fire going out for lack of wood"},{"definition":"To be published, broadcast, or sent","example":"The team email went out yesterday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team email being sent"},{"definition":"To become unfashionable or out of date","example":"That style of UI design went out years ago.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An outdated UI design style"},{"definition":"To have a romantic relationship with someone","example":"They have been going out for two years.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A couple in a romantic relationship"}]},{"particle":"away","storageKeyPrefix":"goAway","meanings":[{"definition":"To leave a place or person","example":"Please go away, I need to focus on my work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person asking for space to focus on work"},{"definition":"To disappear or fade","example":"The error message went away when I restarted the application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An error message disappearing after a restart"},{"definition":"To leave home for a holiday","example":"We are going away to the mountains for the weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person going on a mountain holiday"}]},{"particle":"across","storageKeyPrefix":"goAcross","meanings":[{"definition":"To move to the other side of something","example":"We need to go across the street to reach the client''s office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People crossing the street to reach an office"}]},{"particle":"forward","storageKeyPrefix":"goForward","meanings":[{"definition":"To progress or advance with a plan or idea","example":"We are going forward with the new business strategy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team advancing with a new business strategy"},{"definition":"To move clocks ahead (daylight saving time)","example":"The clocks go forward in the spring.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A clock being moved forward in spring"}]},{"particle":"back","storageKeyPrefix":"goBack","meanings":[{"definition":"To return to a place or previous state","example":"I need to go back to the office; I forgot my laptop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person returning to the office for a forgotten laptop"},{"definition":"To have existed or started since a specific time","example":"This legacy code goes back to 2010.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Legacy code dating back to 2010"},{"definition":"To break a promise or agreement (go back on something)","example":"The vendor went back on their promise to deliver the software today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A vendor breaking a delivery promise"}]},{"particle":"for","storageKeyPrefix":"goFor","meanings":[{"definition":"To choose or select something","example":"I will go for the standard Java framework instead of the experimental one.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer choosing a Java framework"},{"definition":"To try to achieve or get something","example":"If you want that promotion, you should go for it!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person going for a promotion"},{"definition":"To attack someone physically or verbally","example":"The dog suddenly went for the mailman.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A dog attacking the mailman"},{"definition":"To apply equally to someone or something else","example":"The rules are strict, and that goes for managers, too.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rules applying equally to all employees including managers"}]},{"particle":"by","storageKeyPrefix":"goBy","meanings":[{"definition":"To pass (used for time)","example":"As the years went by, the technology improved significantly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Technology improving as years go by"},{"definition":"To base a decision on something or follow rules","example":"If we go by the manual, this should take two hours.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person following the manual to complete a task"},{"definition":"To be known by a specific name","example":"His name is Robert, but he goes by Bob.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A man named Robert who goes by the name Bob"}]},{"particle":"together","storageKeyPrefix":"goTogether","meanings":[{"definition":"To look or sound good in combination","example":"The new logo and the brand colors go together perfectly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A logo and brand colors that complement each other"},{"definition":"To frequently accompany each other","example":"High risk and high reward usually go together in business.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"High risk and high reward going hand in hand"}]},{"particle":"with","storageKeyPrefix":"goWith","meanings":[{"definition":"To match or suit something","example":"That font doesn''t go with the website''s professional design.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A font that clashes with a professional website design"},{"definition":"To choose or accept an idea or offer","example":"We decided to go with the second marketing proposal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team accepting a marketing proposal"},{"definition":"To accompany someone","example":"I''m going to the conference; do you want to go with me?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people going to a conference together"}]},{"particle":"without","storageKeyPrefix":"goWithout","meanings":[{"definition":"To manage or live without something you usually have","example":"The budget is tight, so we will have to go without the extra monitors this year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team managing without extra monitors due to budget cuts"}]},{"particle":"over","storageKeyPrefix":"goOver","meanings":[{"definition":"To review, check, or examine something carefully","example":"Let''s go over the project requirements one more time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team reviewing project requirements"},{"definition":"To move toward someone or something","example":"I will go over to the IT department to ask for help.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person walking over to the IT department"},{"definition":"To be received in a specific way by an audience","example":"His joke didn''t go over very well during the serious meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A joke falling flat during a serious meeting"}]},{"particle":"ahead","storageKeyPrefix":"goAhead","meanings":[{"definition":"To start or proceed with an action","example":"We have the budget, so we can go ahead with the development.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team proceeding with development after budget approval"},{"definition":"To move in front of someone","example":"You go ahead, I will catch up with you in a minute.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person moving ahead while another catches up"}]},{"particle":"after","storageKeyPrefix":"goAfter","meanings":[{"definition":"To try to catch or stop someone","example":"The police went after the thief.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police chasing a thief"},{"definition":"To try to achieve or get something (like a job or goal)","example":"She is going after a leadership role in the company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A professional pursuing a leadership role"}]},{"particle":"behind","storageKeyPrefix":"goBehind","meanings":[{"definition":"To go to the back of something","example":"The cat went behind the sofa.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A cat going behind the sofa"},{"definition":"To do something secretly without someone''s knowledge or permission","example":"He went behind the manager''s back and changed the server configurations.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An employee secretly changing server configurations"}]},{"particle":"through","storageKeyPrefix":"goThrough","meanings":[{"definition":"To experience a difficult situation","example":"The company went through a tough financial period last year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company experiencing a tough financial period"},{"definition":"To search or examine something carefully","example":"I need to go through my emails to find the invoice.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person carefully searching through emails"},{"definition":"To be officially approved or completed","example":"The merger finally went through yesterday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A merger being officially approved"},{"definition":"To use up a supply of something","example":"We go through a lot of coffee in the developers'' room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers going through a lot of coffee"},{"definition":"To practise or rehearse something","example":"Let''s go through the presentation one more time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team rehearsing a presentation"}]},{"particle":"about","storageKeyPrefix":"goAbout","meanings":[{"definition":"To begin to tackle a task or problem","example":"I don''t know how to go about fixing this complex bug.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer figuring out how to fix a complex bug"},{"definition":"To behave or do things in a normal or usual way","example":"Despite the bad news, they went about their daily work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employees continuing their daily work despite bad news"}]},{"particle":"around / round","storageKeyPrefix":"goAround","meanings":[{"definition":"To circulate or spread (illness or news)","example":"There is a rumor going around about a new software release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A rumor spreading through an office about a software release"},{"definition":"To be enough for everyone to have a share","example":"Are there enough printed reports to go around?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Reports being distributed to everyone in the meeting"},{"definition":"To visit someone at their location","example":"I''ll go around to his desk later to discuss the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A colleague visiting a desk to discuss code"},{"definition":"To spin or rotate","example":"The wheels go around.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Wheels spinning and rotating"}]},{"particle":"to","storageKeyPrefix":"goTo","meanings":[{"definition":"To start a specific action or enter a state","example":"After 12 hours of coding, I finally went to sleep.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer going to sleep after a long coding session"},{"definition":"To be given or assigned to someone","example":"All the extra project funds will go to the marketing team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project funds being allocated to the marketing team"}]},{"particle":"against","storageKeyPrefix":"goAgainst","meanings":[{"definition":"To oppose or disagree with something","example":"Implementing this feature goes against our main design principles.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A feature that conflicts with design principles"},{"definition":"To be unfavorable to someone (especially in contests or legal cases)","example":"The final verdict went against the company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A court verdict going against a company"}]}]'::jsonb),
  ('grow', 'Grow', '["apart","away","back","in","into","on","out / out of","over","to","together","up","with"]'::jsonb, '[{"particle":"apart","storageKeyPrefix":"growApart","meanings":[{"definition":"To gradually become less close in a relationship over time.","example":"The co-founders grew apart over the years and eventually split the business.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Co-founders growing apart over the years and eventually splitting the business"}]},{"particle":"away","storageKeyPrefix":"growAway","meanings":[{"definition":"To gradually become less connected to someone or something, or to stop supporting a past habit or idea.","example":"As the startup expanded, we naturally grew away from our original, informal working style.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Startup growing away from its original informal working style"}]},{"particle":"back","storageKeyPrefix":"growBack","meanings":[{"definition":"To grow again after being cut, broken, or damaged (usually referring to plants or hair).","example":"We had to cut down the tree, but the branches are starting to grow back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Tree branches starting to grow back after being cut down"}]},{"particle":"in","storageKeyPrefix":"growIn","meanings":[{"definition":"To fill an empty space by growing (often used for hair or plants).","example":"We planted new seeds in the garden, and the grass is finally growing in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Grass finally growing in after planting new seeds in the garden"}]},{"particle":"into","storageKeyPrefix":"growInto","meanings":[{"definition":"To develop the skills and confidence needed for a new role or responsibility.","example":"It was a big promotion, but she quickly grew into her position as a team leader.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee growing into her position as a team leader after a big promotion"},{"definition":"To become large enough to fit into clothing.","example":"The jacket is too big for him now, but he will grow into it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child who will grow into a jacket that is currently too big"},{"definition":"To develop into a different or larger state.","example":"What started as a simple Java application grew into a massive enterprise platform.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Simple Java application growing into a massive enterprise platform"}]},{"particle":"on","storageKeyPrefix":"growOn","meanings":[{"definition":"To become increasingly liked or appreciated by someone over time.","example":"I didn''t like the new management software at first, but it is starting to grow on me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New management software growing on a user over time"}]},{"particle":"out / out of","storageKeyPrefix":"growOut","meanings":[{"definition":"To allow hair to grow back to its natural style or color.","example":"She is growing out her dyed blonde hair.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person growing out dyed blonde hair"},{"definition":"To become too big for a physical space or piece of clothing.","example":"Our development team grew out of the small office in just six months.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Development team growing out of the small office in six months"},{"definition":"To stop doing something as you become older or more mature.","example":"He used to micromanage his team, but luckily he grew out of that habit.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager growing out of the habit of micromanaging his team"},{"definition":"To develop or happen as a direct result of something else.","example":"The new mobile app grew out of a simple idea shared during a brainstorming meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Mobile app growing out of a simple idea from a brainstorming meeting"}]},{"particle":"over","storageKeyPrefix":"growOver","meanings":[{"definition":"To become covered with growing plants (like vines, moss, or grass).","example":"The old, abandoned factory was eventually grown over by ivy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old abandoned factory grown over by ivy"}]},{"particle":"to","storageKeyPrefix":"growTo","meanings":[{"definition":"To gradually begin to experience a feeling or an action (usually followed by another verb, like like, love, realize, understand).","example":"After working with him for a year, I grew to respect his leadership style.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee growing to respect their manager''s leadership style after working together"}]},{"particle":"together","storageKeyPrefix":"growTogether","meanings":[{"definition":"To become closely united or emotionally connected.","example":"After the merger, the two departments slowly grew together to form one strong team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two departments growing together to form one strong team after a merger"},{"definition":"To fuse or join while growing (often used for plants or healing bones).","example":"The broken bone was set in a cast and grew together perfectly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Broken bone growing together perfectly after being set in a cast"}]},{"particle":"up","storageKeyPrefix":"growUp","meanings":[{"definition":"To change from being a child to being an adult.","example":"He grew up in Poland and later moved abroad to study software engineering.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person who grew up in Poland and moved abroad to study software engineering"},{"definition":"To behave in a mature, adult way (often used as a criticism or command when someone is acting childish).","example":"Stop arguing about minor code formatting and grow up!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers being told to grow up and stop arguing about minor code formatting"},{"definition":"To slowly develop, arise, or establish itself (often used for cities, industries, or systems).","example":"A massive ecosystem of tools and frameworks grew up around the Java programming language.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Ecosystem of tools and frameworks growing up around the Java programming language"}]},{"particle":"with","storageKeyPrefix":"growWith","meanings":[{"definition":"To expand, develop, or change proportionally alongside something else.","example":"You need a server architecture that can grow with your business needs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server architecture growing with business needs"}]}]'::jsonb),
  ('hand', 'Hand', '["back","down","in","off","on","out","over","around / round / about","to"]'::jsonb, '[{"particle":"back","storageKeyPrefix":"handBack","meanings":[{"definition":"To return something to the person who owned it or gave it to you.","example":"After reviewing the code, please hand back the printed reports to the project manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Handing back printed reports to the project manager after reviewing the code"}]},{"particle":"down","storageKeyPrefix":"handDown","meanings":[{"definition":"To pass knowledge, traditions, or items from an older person to a younger person (or from a predecessor to a successor).","example":"The retiring CEO handed down his leadership principles to the new management team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Retiring CEO handing down leadership principles to the new management team"},{"definition":"To officially announce a formal or legal decision.","example":"The board of directors will hand down their final decision on the software budget next week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Board of directors handing down their final decision on the software budget"}]},{"particle":"in","storageKeyPrefix":"handIn","meanings":[{"definition":"To submit something or give it to a person in authority (like a boss, teacher, or official).","example":"He decided to hand in his resignation because he found a new job in software development.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person handing in their resignation after finding a new job in software development"}]},{"particle":"off","storageKeyPrefix":"handOff","meanings":[{"definition":"To pass the responsibility, control, or execution of a task to someone else.","example":"I will hand off the server maintenance tasks to the junior Java developers tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Handing off server maintenance tasks to junior Java developers"}]},{"particle":"on","storageKeyPrefix":"handOn","meanings":[{"definition":"To give something to the next person, often in a sequence (similar to passing a message or object along).","example":"Please read this project update and hand it on to the rest of the management team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Handing on a project update to the rest of the management team"}]},{"particle":"out","storageKeyPrefix":"handOut","meanings":[{"definition":"To distribute something to multiple people in a group.","example":"The team leader handed out the new coding guidelines during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team leader handing out new coding guidelines during the meeting"}]},{"particle":"over","storageKeyPrefix":"handOver","meanings":[{"definition":"To give control, responsibility, or ownership of something to someone else.","example":"When the project is finished, we will hand over the new application to the client.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Handing over the new application to the client when the project is finished"},{"definition":"To give something to someone because they demand it (often formal or forced).","example":"The security guard asked him to hand over his company ID card.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Security guard asking someone to hand over their company ID card"}]},{"particle":"around / round / about","storageKeyPrefix":"handAround","meanings":[{"definition":"To offer or pass something to each person in a group.","example":"They handed around the new smartphones so the development team could test them.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Handing around new smartphones for the development team to test"}]},{"particle":"to","storageKeyPrefix":"handTo","meanings":[{"definition":"Used in the phrase \"have to hand it to someone\" — to admit that someone has done something very well and give them credit for it.","example":"You have to hand it to her; she managed that difficult software project perfectly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Giving credit to someone who managed a difficult software project perfectly"}]}]'::jsonb),
  ('hang', 'Hang', '["about / around / round","back","behind","down","in","off","on","out","over","together","up","with"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"hangAbout","meanings":[{"definition":"To spend time somewhere doing nothing in particular, just waiting or relaxing.","example":"Teenagers often hang around the shopping mall on weekends.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teenagers hanging around the shopping mall on weekends"},{"definition":"To wait or stay in a place for a specific reason.","example":"I''ll hang around until the management meeting is over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Waiting around until the management meeting is over"},{"definition":"To spend time with a specific group of people.","example":"He started to hang around with the software development team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hanging around with the software development team"}]},{"particle":"back","storageKeyPrefix":"hangBack","meanings":[{"definition":"To hesitate or stay behind the rest of a group because of fear, shyness, or uncertainty.","example":"She hung back while the other candidates rushed to introduce themselves to the CEO.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Candidate hanging back while others rushed to introduce themselves to the CEO"}]},{"particle":"behind","storageKeyPrefix":"hangBehind","meanings":[{"definition":"To stay in a place after other people have already left.","example":"The lead developer hung behind after the meeting to ask a few more questions.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lead developer hanging behind after the meeting to ask more questions"}]},{"particle":"down","storageKeyPrefix":"hangDown","meanings":[{"definition":"To drop or fall loosely downwards (usually describing hair, clothing, or branches).","example":"Her long coat hung down to her ankles.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Long coat hanging down to the ankles"}]},{"particle":"in","storageKeyPrefix":"hangIn","meanings":[{"definition":"To remain positive and not give up during a difficult situation. (Almost always used in the phrase \"hang in there\".)","example":"The Java migration project is really tough right now, but hang in there — it will get easier soon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Encouraging someone to hang in there during a tough Java migration project"}]},{"particle":"off","storageKeyPrefix":"hangOff","meanings":[{"definition":"To hold onto the side of something to prevent yourself from falling.","example":"The rescue worker was hanging off the side of the helicopter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rescue worker hanging off the side of a helicopter"},{"definition":"To hesitate or wait before taking an action (less common).","example":"The board hung off making a final decision until they saw the financial report.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Board hanging off making a final decision until they saw the financial report"}]},{"particle":"on","storageKeyPrefix":"hangOn","meanings":[{"definition":"To wait for a short time.","example":"Hang on a minute, I need to find my laptop charger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone to hang on a minute while finding a laptop charger"},{"definition":"To hold something very securely.","example":"Hang on to the railing so you don''t slip on the ice.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hanging on to the railing to avoid slipping on ice"},{"definition":"To keep something instead of throwing it away or giving it away (usually \"hang on to\").","example":"You should hang on to those old code backups, just in case.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hanging on to old code backups just in case"},{"definition":"To rely or depend completely on something.","example":"The company''s future hangs on the success of this new application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company''s future hanging on the success of a new application"}]},{"particle":"out","storageKeyPrefix":"hangOut","meanings":[{"definition":"To spend free time relaxing or socializing with friends.","example":"We usually hang out at the local coffee shop after work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Friends hanging out at the local coffee shop after work"},{"definition":"To put wet clothes outside on a line to dry.","example":"I need to hang the washing out before it rains.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hanging the washing out on a line before it rains"},{"definition":"To lean your body out of a window or opening.","example":"Do not hang out of the train window while it is moving.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warning not to hang out of the train window while moving"}]},{"particle":"over","storageKeyPrefix":"hangOver","meanings":[{"definition":"To make someone worry about a future problem, or to loom like a threat.","example":"The threat of budget cuts was hanging over the entire IT department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Threat of budget cuts hanging over the entire IT department"}]},{"particle":"together","storageKeyPrefix":"hangTogether","meanings":[{"definition":"To support each other and stay united as a group, especially in difficult times.","example":"If the startup wants to survive this crisis, the leadership team must hang together.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership team hanging together to survive the startup crisis"},{"definition":"To be logical, consistent, or believable (usually describing a story, theory, or argument).","example":"The system architect''s explanation for the server crash simply doesn''t hang together.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"System architect''s explanation for the server crash not hanging together"}]},{"particle":"up","storageKeyPrefix":"hangUp","meanings":[{"definition":"To end a telephone conversation by breaking the connection.","example":"Please don''t hang up on me, I haven''t finished explaining the problem!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone not to hang up before finishing explaining the problem"},{"definition":"To place a piece of clothing on a hook or a hanger.","example":"When you enter the office, please hang up your coat in the closet.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hanging up a coat in the office closet"},{"definition":"To cause a delay or problem (often used in the passive voice).","example":"The software release got hung up by a series of unexpected bugs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software release getting hung up by unexpected bugs"}]},{"particle":"with","storageKeyPrefix":"hangWith","meanings":[{"definition":"An informal version of \"hang out with\"; to spend time with people.","example":"I prefer to hang with people who share my interest in business management.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Preferring to hang with people who share an interest in business management"}]}]'::jsonb),
  ('hold', 'Hold', '["against","back","down","in","off","on","out","over","to","together","up","with"]'::jsonb, '[{"particle":"against","storageKeyPrefix":"holdAgainst","meanings":[{"definition":"To let a past mistake or negative action influence your opinion of someone; to hold a grudge.","example":"The developer made a major error in the code, but the manager did not hold it against him during his performance review.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager not holding a code error against a developer during performance review"}]},{"particle":"back","storageKeyPrefix":"holdBack","meanings":[{"definition":"To hesitate to act or speak.","example":"We need all your ideas for this project, so please do not hold back in the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Encouraging team members not to hold back their ideas in a meeting"},{"definition":"To stop something from moving forward, developing, or succeeding.","example":"The team is highly skilled, but outdated legacy software is holding them back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Legacy software holding back a skilled team"},{"definition":"To keep information a secret.","example":"I suspect the client is holding back some details about their budget.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client holding back budget details"}]},{"particle":"down","storageKeyPrefix":"holdDown","meanings":[{"definition":"To manage to keep a job for a period of time.","example":"It requires excellent leadership skills to hold down a management position in such a fast-paced company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leader holding down a management position in a fast-paced company"},{"definition":"To keep costs, prices, or numbers at a low level.","example":"We need to hold down our server costs this quarter to remain profitable.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping server costs held down to remain profitable"},{"definition":"To physically prevent someone or something from moving.","example":"The wind was so strong that we had to hold down the equipment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding down equipment in strong wind"}]},{"particle":"in","storageKeyPrefix":"holdIn","meanings":[{"definition":"To hide or control your emotions.","example":"The CEO was furious about the delayed release, but she managed to hold in her anger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO holding in anger about a delayed release"},{"definition":"To pull your stomach inwards.","example":"He held his stomach in to look better in the photograph.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding stomach in for a photograph"}]},{"particle":"off","storageKeyPrefix":"holdOff","meanings":[{"definition":"To delay doing something.","example":"We decided to hold off on deploying the new Java application until the testing phase was 100% complete.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding off on deploying a Java application until testing is complete"},{"definition":"To stop an opponent or competitor from defeating you.","example":"The company managed to hold off its main competitors by launching a superior product.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company holding off competitors by launching a superior product"}]},{"particle":"on","storageKeyPrefix":"holdOn","meanings":[{"definition":"To wait for a short time (often used on the phone).","example":"Could you hold on a minute while I check the project schedule?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone to hold on while checking the project schedule"},{"definition":"To survive in a difficult or dangerous situation.","example":"The startup held on through the economic crisis and eventually became a market leader.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Startup holding on through an economic crisis"},{"definition":"To grip something tightly.","example":"Hold on to the handrail so you do not fall on the stairs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding on to the handrail to avoid falling on stairs"}]},{"particle":"out","storageKeyPrefix":"holdOut","meanings":[{"definition":"To continue to defend yourself or survive in a difficult situation.","example":"The team held out against the pressure from the clients and delivered high-quality work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team holding out against client pressure to deliver quality work"},{"definition":"To offer a possibility, chance, or hope.","example":"The new business strategy holds out hope for a better financial year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New business strategy holding out hope for a better financial year"},{"definition":"To extend a part of your body (like a hand) or an object.","example":"She held out her hand to welcome the new employee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding out a hand to welcome a new employee"},{"definition":"To wait and refuse to accept anything less than what you want (hold out for).","example":"The senior developer is holding out for a higher salary before signing the contract.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Senior developer holding out for a higher salary before signing a contract"}]},{"particle":"over","storageKeyPrefix":"holdOver","meanings":[{"definition":"To postpone or delay an event or discussion until a later time.","example":"We do not have enough time today, so we will hold over the architecture discussion until tomorrow\\''s meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding over an architecture discussion until the next meeting"},{"definition":"To allow someone to stay in a job or position longer than originally planned.","example":"The outgoing director was held over for three months to help train the new leadership team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Outgoing director held over to help train the new leadership team"}]},{"particle":"to","storageKeyPrefix":"holdTo","meanings":[{"definition":"To make someone keep a promise or follow a standard.","example":"We agreed to deliver the software by Friday, and the client will hold us to that deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client holding the team to a Friday software delivery deadline"},{"definition":"To continue to believe an idea or follow a plan, even when it is difficult.","example":"We must hold to our original business plan if we want to see long-term results.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holding to the original business plan for long-term results"}]},{"particle":"together","storageKeyPrefix":"holdTogether","meanings":[{"definition":"To remain united or to keep a group united.","example":"A strong manager knows how to hold a team together during stressful project sprints.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Strong manager holding a team together during stressful project sprints"},{"definition":"To remain intact and not break into pieces.","example":"The old database system is barely holding together; we need to replace it soon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old database system barely holding together"}]},{"particle":"up","storageKeyPrefix":"holdUp","meanings":[{"definition":"To delay someone or something.","example":"A critical bug in the code is holding up the entire product release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Critical bug holding up the entire product release"},{"definition":"To remain strong, successful, or true when tested.","example":"Their argument sounded good at first, but it did not hold up under close examination.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Argument not holding up under close examination"},{"definition":"To support the weight of something.","example":"These concrete pillars hold up the entire roof of the building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Concrete pillars holding up the roof of a building"},{"definition":"To rob a bank, shop, or person using violence or a weapon.","example":"The thieves tried to hold up the security van.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves attempting to hold up a security van"}]},{"particle":"with","storageKeyPrefix":"holdWith","meanings":[{"definition":"To approve of an idea or activity (almost always used in the negative).","example":"I do not hold with micromanaging experienced developers; they work better with independence.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Not holding with micromanaging experienced developers"}]}]'::jsonb),
  ('keep', 'Keep', '["about / around / round","across","after","ahead","apart","away","back","behind","down","in","off","on","out","to","together","up"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"keepAbout","meanings":[{"definition":"To keep something near you because it might be useful.","example":"I always keep a pen around just in case I need to take notes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping a pen around in case notes are needed"},{"definition":"To continue to associate with someone or let them stay in a group or company.","example":"He isn\\''t very productive, so I don\\''t know why they keep him around.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping an unproductive person around in a company"}]},{"particle":"across","storageKeyPrefix":"keepAcross","meanings":[{"definition":"To stay informed about a situation or topic (mainly British English).","example":"As a project manager, I need to keep across all the software updates.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project manager keeping across all software updates"}]},{"particle":"after","storageKeyPrefix":"keepAfter","meanings":[{"definition":"To repeatedly remind or nag someone to do something (mainly US English).","example":"I have to keep after my team to submit their timesheets on Friday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager keeping after team to submit timesheets"}]},{"particle":"ahead","storageKeyPrefix":"keepAhead","meanings":[{"definition":"To stay in front of others or stay more advanced than competitors.","example":"To succeed in business, you must innovate to keep ahead of your rivals.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business innovating to keep ahead of rivals"}]},{"particle":"apart","storageKeyPrefix":"keepApart","meanings":[{"definition":"To prevent people, animals, or things from coming together.","example":"The two dogs were fighting, so we had to keep them apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping two fighting dogs apart"},{"definition":"To stay away from each other.","example":"The two rival teams were told to keep apart before the match.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rival teams told to keep apart before a match"}]},{"particle":"away","storageKeyPrefix":"keepAway","meanings":[{"definition":"To avoid going near something or someone.","example":"You should keep away from that dog; it looks aggressive.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping away from an aggressive-looking dog"},{"definition":"To prevent someone or something from going near.","example":"Keep the children away from the hot stove.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping children away from a hot stove"}]},{"particle":"back","storageKeyPrefix":"keepBack","meanings":[{"definition":"To stay at a safe distance, or make someone stay back.","example":"The police told the crowd to keep back from the accident.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police telling crowd to keep back from an accident"},{"definition":"To hide information; to not tell someone everything you know.","example":"I feel like the client is keeping something back from us.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client keeping information back from the team"},{"definition":"To stop yourself from showing an emotion.","example":"She struggled to keep back her tears during the sad movie.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person struggling to keep back tears during a sad movie"}]},{"particle":"behind","storageKeyPrefix":"keepBehind","meanings":[{"definition":"To stay in a place after everyone else has left.","example":"I kept behind after the meeting to ask the speaker a question.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Staying behind after a meeting to ask the speaker a question"},{"definition":"To make someone stay after others have left.","example":"The manager kept me behind to discuss my performance.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager keeping an employee behind to discuss performance"}]},{"particle":"down","storageKeyPrefix":"keepDown","meanings":[{"definition":"To stop the number, level, or size of something from increasing.","example":"We need to keep our expenses down this quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping expenses down during the quarter"},{"definition":"To manage to keep food or medicine in your stomach without vomiting.","example":"He was so sick that he couldn\\''t keep any water down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sick person unable to keep any water down"},{"definition":"To stay hidden by crouching or lying flat.","example":"Keep down! I don\\''t want anyone to see us.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Crouching down to stay hidden from view"},{"definition":"To prevent a person or group of people from having power or freedom.","example":"The corrupt government tried to keep the citizens down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Corrupt government trying to keep citizens from having power"}]},{"particle":"in","storageKeyPrefix":"keepIn","meanings":[{"definition":"To make someone stay inside as a punishment.","example":"The teacher kept him in after school because he didn\\''t do his homework.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teacher keeping a student in after school as punishment"},{"definition":"To control or hide an emotion.","example":"She was very angry but managed to keep her feelings in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person managing to keep their feelings in despite being angry"},{"definition":"To prevent a fire from dying out.","example":"Add some more wood to keep the fire in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Adding wood to keep a fire burning"}]},{"particle":"off","storageKeyPrefix":"keepOff","meanings":[{"definition":"To avoid touching or walking on something.","example":"Please keep off the grass while the park is being maintained.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sign asking people to keep off the grass during maintenance"},{"definition":"To avoid mentioning or discussing a specific topic.","example":"Let\\''s keep off the subject of politics during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping off the subject of politics during a meeting"},{"definition":"To prevent something from touching or harming something else.","example":"Use this spray to keep the bugs off your plants.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Using spray to keep bugs off plants"},{"definition":"To avoid eating, drinking, or using something.","example":"I am trying to keep off sugar to improve my health.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person trying to keep off sugar to improve health"}]},{"particle":"on","storageKeyPrefix":"keepOn","meanings":[{"definition":"To continue doing something.","example":"Even though the project was difficult, the team kept on working.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team keeping on working despite a difficult project"},{"definition":"To continue to employ someone.","example":"The company decided to keep him on as a consultant after he retired.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company keeping a retired employee on as a consultant"},{"definition":"To leave a piece of clothing on your body.","example":"It\\''s cold in here, so I will keep my jacket on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping a jacket on because it is cold"},{"definition":"To repeatedly remind or complain to someone.","example":"My manager keeps on at me to finish the financial report.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager repeatedly reminding an employee to finish the financial report"}]},{"particle":"out","storageKeyPrefix":"keepOut","meanings":[{"definition":"To not enter a place, or to stop someone or something from entering.","example":"There is a sign on the door that says \\''Danger: Keep Out.\\''","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Danger: Keep Out sign on a door"},{"definition":"To stay away from a problem, argument, or situation.","example":"This is a private argument, so please keep out of it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Staying out of a private argument"}]},{"particle":"to","storageKeyPrefix":"keepTo","meanings":[{"definition":"To follow a plan, rule, or agreement.","example":"We have a tight deadline, so let\\''s keep to the schedule.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team keeping to the schedule due to a tight deadline"},{"definition":"To limit something to a certain amount.","example":"Please keep your presentation to ten minutes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Keeping a presentation to ten minutes"},{"definition":"To stay on a particular path or road.","example":"When hiking in the forest, always keep to the marked trail.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hiker keeping to the marked trail in a forest"},{"definition":"To avoid talking to other people; to stay private.","example":"He is very shy and mostly keeps to himself at the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Shy person keeping to himself at the office"}]},{"particle":"together","storageKeyPrefix":"keepTogether","meanings":[{"definition":"To stay in a group and not separate.","example":"We need to keep together so we don\\''t get lost in the city.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Group keeping together to avoid getting lost in the city"},{"definition":"To not break apart or fall to pieces.","example":"I hope my old laptop keeps together until I can buy a new one.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old laptop barely keeping together"}]},{"particle":"up","storageKeyPrefix":"keepUp","meanings":[{"definition":"To move at the same speed as someone or something else.","example":"The software industry changes so fast that it\\''s hard to keep up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Struggling to keep up with fast-changing software industry"},{"definition":"To continue doing something at a high level.","example":"You are doing a great job — keep up the good work!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Encouraging someone to keep up the good work"},{"definition":"To stay awake, or to prevent someone from sleeping.","example":"My neighbor\\''s loud music kept me up all night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Neighbor\\''s loud music keeping someone up all night"},{"definition":"To maintain something in good condition.","example":"It costs a lot of money to keep up such a large office building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Maintaining a large office building in good condition"}]}]'::jsonb),
  ('knock', 'Knock', '["about / around / round","against","apart","back","down","in","into","off","on","out","over","through","together","up"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"knockAbout","meanings":[{"definition":"To talk about ideas in an informal way.","example":"We knocked a few new software features around during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team knocking software feature ideas around during a meeting"},{"definition":"To relax or travel without a strict schedule.","example":"After selling his startup, he knocked about Europe for a year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person knocking about Europe after selling his startup"},{"definition":"When an object is somewhere in a room but not organised.","example":"I have an old Java textbook knocking around my office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old Java textbook knocking around an office"},{"definition":"To hit someone repeatedly.","example":"The robbers knocked the guard about.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Robbers knocking the guard about"}]},{"particle":"against","storageKeyPrefix":"knockAgainst","meanings":[{"definition":"To accidentally hit something while moving.","example":"I knocked against the server rack and unplugged a cable.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accidentally knocking against a server rack and unplugging a cable"}]},{"particle":"apart","storageKeyPrefix":"knockApart","meanings":[{"definition":"To hit something so hard it breaks into pieces.","example":"The storm knocked the old warehouse apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Storm knocking the old warehouse apart"}]},{"particle":"back","storageKeyPrefix":"knockBack","meanings":[{"definition":"To reject an offer or application.","example":"The investors knocked back our business proposal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Investors knocking back a business proposal"},{"definition":"To cost someone a large amount of money.","example":"That new server knocked the company back $5,000.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New server knocking the company back five thousand dollars"},{"definition":"To consume an alcoholic drink quickly.","example":"He knocked back a coffee before the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person knocking back a coffee before a presentation"},{"definition":"To surprise or shock someone; to leave someone amazed or stunned.","example":"The sudden drop in sales really knocked me back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sudden drop in sales knocking someone back"}]},{"particle":"down","storageKeyPrefix":"knockDown","meanings":[{"definition":"To destroy a building completely.","example":"They knocked down the old office to build a new one.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking down an old office to build a new one"},{"definition":"To reduce the cost of an item.","example":"The vendor knocked down the price of the software license.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Vendor knocking down the price of a software license"},{"definition":"To successfully negotiate a discount.","example":"I knocked the supplier down by 15%.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Negotiating a supplier down by fifteen percent"},{"definition":"To strike someone with a vehicle so they fall.","example":"A delivery bike almost knocked him down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Delivery bike almost knocking someone down"}]},{"particle":"in","storageKeyPrefix":"knockIn","meanings":[{"definition":"To hit a nail or object so it goes into a surface.","example":"He knocked the nail in with a hammer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking a nail in with a hammer"}]},{"particle":"into","storageKeyPrefix":"knockInto","meanings":[{"definition":"To unexpectedly meet someone you know.","example":"I knocked into my old project manager at the tech conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Unexpectedly knocking into an old project manager at a tech conference"},{"definition":"To walk into something by accident.","example":"She was looking at her phone and knocked into the desk.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking at phone and knocking into the desk"}]},{"particle":"off","storageKeyPrefix":"knockOff","meanings":[{"definition":"To finish your workday.","example":"Let''s knock off early today and go home.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team knocking off early to go home"},{"definition":"To remove an amount from a total.","example":"Can you knock 10% off the final invoice?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking ten percent off a final invoice"},{"definition":"To produce a piece of work very quickly.","example":"She knocked off the weekly report in just 20 minutes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person knocking off the weekly report in twenty minutes"},{"definition":"To make a cheap imitation of a product illegally.","example":"A competitor tried to knock off our main application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Competitor trying to knock off the main application"},{"definition":"To rob a place (informal).","example":"The thieves knocked off a local bank.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves knocking off a local bank"},{"definition":"To kill someone (informal).","example":"The gang knocked him off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Gang knocking someone off"}]},{"particle":"on","storageKeyPrefix":"knockOn","meanings":[{"definition":"To hit a door repeatedly.","example":"I knocked on, but no one answered the door.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking on a door with no answer"},{"definition":"Used as \"knock-on effect\" to describe how one event causes another.","example":"The bug in the Java code had a knock-on effect on the whole database.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bug in Java code having a knock-on effect on the database"}]},{"particle":"out","storageKeyPrefix":"knockOut","meanings":[{"definition":"To hit someone so hard they become unconscious.","example":"The boxer knocked his opponent out in the first round.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Boxer knocking opponent out in the first round"},{"definition":"To remove a person or team from a competition.","example":"Our team was knocked out in the quarter-finals.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team knocked out in the quarter-finals"},{"definition":"To stop a system from working.","example":"The power outage knocked out our main servers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Power outage knocking out main servers"},{"definition":"To create something at high speed.","example":"The developers can knock out a prototype by tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers knocking out a prototype by tomorrow"},{"definition":"To greatly impress someone.","example":"Her leadership skills completely knocked me out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership skills completely knocking someone out with admiration"}]},{"particle":"over","storageKeyPrefix":"knockOver","meanings":[{"definition":"To hit something so it falls on its side.","example":"I accidentally knocked over my coffee onto the keyboard.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accidentally knocking over coffee onto the keyboard"},{"definition":"To steal from a business (informal).","example":"They knocked over a gas station.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves knocking over a gas station"}]},{"particle":"through","storageKeyPrefix":"knockThrough","meanings":[{"definition":"To remove a wall between two spaces to connect rooms.","example":"We knocked through the wall to create an open-plan office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking through a wall to create an open-plan office"}]},{"particle":"together","storageKeyPrefix":"knockTogether","meanings":[{"definition":"To create something quickly using whatever is available.","example":"I knocked together a quick test environment for the new app.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking together a quick test environment for a new app"}]},{"particle":"up","storageKeyPrefix":"knockUp","meanings":[{"definition":"To make a meal or item in a short time.","example":"Let me knock up a quick presentation for the client.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking up a quick presentation for a client"},{"definition":"To knock on a door to wake someone (UK English).","example":"Can you knock me up at 6 AM?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Knocking someone up at six in the morning"},{"definition":"To make someone pregnant (informal/slang).","example":"He knocked his girlfriend up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Informal reference to knocking someone up"},{"definition":"To warm up for tennis by hitting the ball before a match.","example":"The players are knocking up on the court.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Tennis players knocking up on the court before a match"}]}]'::jsonb),
  ('lay', 'Lay', '["about","away","by","down","for","in","into","off","on","out","over","to","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"layAbout","meanings":[{"definition":"To hit out in all directions; to attack violently.","example":"When the attackers approached, he began laying about him with a heavy stick.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person laying about with a heavy stick to defend against attackers"}]},{"particle":"away","storageKeyPrefix":"layAway","meanings":[{"definition":"To save money or goods for future use (often used in retail as \"layaway\").","example":"The company lays away a portion of its quarterly profits for future software investments.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company laying away quarterly profits for future software investments"}]},{"particle":"by","storageKeyPrefix":"layBy","meanings":[{"definition":"To save money for a specific future need (similar to lay away).","example":"She laid by some money every month to fund her new startup.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person laying by money every month to fund a new startup"}]},{"particle":"down","storageKeyPrefix":"layDown","meanings":[{"definition":"To officially establish a rule, policy, or principle.","example":"The management team laid down clear guidelines for remote work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Management team laying down clear guidelines for remote work"},{"definition":"To surrender weapons; to stop fighting.","example":"The rebels finally agreed to lay down their arms.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Rebels agreeing to lay down their arms"},{"definition":"To record music or audio.","example":"The band went into the studio to lay down a new track.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Band going into the studio to lay down a new track"},{"definition":"To store wine in a cellar for aging.","example":"We laid down several bottles of red wine to drink in ten years.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Laying down bottles of red wine in a cellar for aging"}]},{"particle":"for","storageKeyPrefix":"layFor","meanings":[{"definition":"To wait secretly to attack someone; to ambush (old-fashioned/rare).","example":"The thieves were laying for the manager outside the bank.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves laying for the manager outside the bank"}]},{"particle":"in","storageKeyPrefix":"layIn","meanings":[{"definition":"To collect and store a large supply of something for future use.","example":"We need to lay in plenty of coffee before the development team starts the big sprint.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Laying in plenty of coffee before the development team starts the big sprint"}]},{"particle":"into","storageKeyPrefix":"layInto","meanings":[{"definition":"To criticize someone angrily or attack them physically.","example":"The lead developer laid into the junior programmer for pushing broken code to the main server.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lead developer laying into junior programmer for pushing broken code"}]},{"particle":"off","storageKeyPrefix":"layOff","meanings":[{"definition":"To end a worker''s employment, usually because the company has no work or no budget.","example":"The business had to lay off 20 employees due to the economic crisis.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business laying off 20 employees due to the economic crisis"},{"definition":"To stop criticizing or bothering someone.","example":"Lay off him! He is doing the best he can to meet the deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being told to lay off someone who is doing their best"},{"definition":"To stop using, consuming, or doing something for a while.","example":"I need to lay off the caffeine; I''ve been drinking too much coffee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person deciding to lay off caffeine after drinking too much coffee"}]},{"particle":"on","storageKeyPrefix":"layOn","meanings":[{"definition":"To provide or supply something, especially food, entertainment, or transport.","example":"The company laid on a massive buffet for the leadership conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company laying on a massive buffet for the leadership conference"},{"definition":"To apply something very thickly (like paint) or to exaggerate something (like praise or guilt).","example":"Don''t lay on the praise too thick, or it will sound insincere.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being warned not to lay on the praise too thick"}]},{"particle":"out","storageKeyPrefix":"layOut","meanings":[{"definition":"To explain a plan or idea clearly and in detail.","example":"The CEO laid out the new business strategy during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO laying out the new business strategy during the meeting"},{"definition":"To arrange things so they can be easily seen or used.","example":"The designer laid out the new Java application interface on the screen.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Designer laying out the new Java application interface on the screen"},{"definition":"To spend a large amount of money.","example":"We laid out thousands of dollars on the new server infrastructure.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team laying out thousands of dollars on new server infrastructure"},{"definition":"To knock someone unconscious.","example":"One punch was enough to lay him out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"One punch being enough to lay someone out"}]},{"particle":"over","storageKeyPrefix":"layOver","meanings":[{"definition":"To stop somewhere temporarily during a long journey (this creates the noun \"layover\").","example":"I had to lay over in Frankfurt for six hours before my connecting flight to New York.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Traveller laying over in Frankfurt for six hours before a connecting flight"}]},{"particle":"to","storageKeyPrefix":"layTo","meanings":[{"definition":"(Nautical) To bring a ship to a standstill while facing the wind.","example":"The captain decided to lay to until the storm passed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Captain deciding to lay to until the storm passed"}]},{"particle":"up","storageKeyPrefix":"layUp","meanings":[{"definition":"To be forced to stay in bed because of illness or injury (usually used in the passive: \"laid up\").","example":"Our project manager is laid up with the flu and won''t be in the office this week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project manager laid up with the flu and unable to come to the office"},{"definition":"To take something out of active use and store it (often applied to ships, cars, or machinery).","example":"The old hardware was laid up in the storage room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old hardware laid up in the storage room"}]}]'::jsonb),
  ('leave', 'Leave', '["about / around","back","behind","for","in","off","on","out","over","to","up (to)","with"]'::jsonb, '[{"particle":"about / around","storageKeyPrefix":"leaveAbout","meanings":[{"definition":"To put things in random places in an untidy way, making a mess.","example":"Please don''t leave your dirty clothes around the house.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person leaving dirty clothes around the house"}]},{"particle":"back","storageKeyPrefix":"leaveBack","meanings":[{"definition":"To make a student repeat a school year because their grades were too low (mainly used in US English).","example":"He failed his math and science exams, so the school left him back a year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student being left back a year due to failing exams"}]},{"particle":"behind","storageKeyPrefix":"leaveBehind","meanings":[{"definition":"To forget to take someone or something with you when you depart.","example":"I accidentally left my umbrella behind at the coffee shop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person accidentally leaving an umbrella behind at a coffee shop"},{"definition":"To permanently move on from a situation, place, or person.","example":"She moved to a new city to leave her difficult past behind.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person moving to a new city to leave a difficult past behind"},{"definition":"To progress much faster than competitors, making them look slow or outdated.","example":"The software company left its competitors behind by releasing a revolutionary new app.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software company leaving competitors behind with a revolutionary new app"}]},{"particle":"for","storageKeyPrefix":"leaveFor","meanings":[{"definition":"To begin a journey with a specific destination in mind.","example":"We need to pack our bags because we leave for London early tomorrow morning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person packing bags to leave for London early in the morning"}]},{"particle":"in","storageKeyPrefix":"leaveIn","meanings":[{"definition":"To not remove something; to let it stay where it is.","example":"The editor decided to leave that paragraph in the final article.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Editor deciding to leave a paragraph in the final article"}]},{"particle":"off","storageKeyPrefix":"leaveOff","meanings":[{"definition":"To stop doing something.","example":"Let''s start the meeting exactly where we left off yesterday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team starting a meeting where they left off yesterday"},{"definition":"To purposefully or accidentally exclude someone or something from a list.","example":"I think there is a mistake; my name was left off the guest list.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person noticing their name was left off the guest list"}]},{"particle":"on","storageKeyPrefix":"leaveOn","meanings":[{"definition":"To let a machine, device, or light continue working.","example":"Don''t leave the TV on when you go to sleep.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being reminded not to leave the TV on when going to sleep"},{"definition":"To continue wearing a piece of clothing.","example":"It''s cold in the office, so I will leave my jacket on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person leaving their jacket on because the office is cold"}]},{"particle":"out","storageKeyPrefix":"leaveOut","meanings":[{"definition":"To not include someone or something.","example":"You can leave out the last exercise; it is optional.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teacher telling students they can leave out the last exercise"},{"definition":"To make a person feel excluded from a group or activity.","example":"She felt left out when her colleagues went to lunch without her.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person feeling left out when colleagues went to lunch without her"}]},{"particle":"over","storageKeyPrefix":"leaveOver","meanings":[{"definition":"To have a portion of something remaining after the rest has been used or eaten (almost always used in the passive as \"left over\").","example":"We have a lot of pizza left over from the project launch party.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Pizza left over from a project launch party"}]},{"particle":"to","storageKeyPrefix":"leaveTo","meanings":[{"definition":"To give someone else the responsibility or authority to handle a task.","example":"I don''t know how to fix this server error; I''ll leave it to the IT department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person leaving a server error fix to the IT department"},{"definition":"To give money or property to someone in a will after passing away.","example":"The CEO left his entire estate to charity.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO leaving his entire estate to charity in his will"}]},{"particle":"up (to)","storageKeyPrefix":"leaveUp","meanings":[{"definition":"To let someone else make a decision or choose an option.","example":"We can eat pizza or sushi for lunch; I will leave it up to you.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person leaving the lunch decision up to someone else"},{"definition":"To let a physical object or decoration remain hanging.","example":"We usually leave our holiday decorations up until the middle of January.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Holiday decorations left up until the middle of January"}]},{"particle":"with","storageKeyPrefix":"leaveWith","meanings":[{"definition":"To give an object to someone so they can keep it safe or take care of it temporarily.","example":"Can I leave my heavy bags with you while I quickly run to the store?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person leaving heavy bags with someone while running to the store"}]}]'::jsonb),
  ('let', 'Let', '["down","in","into","off","on","out","up","by","through"]'::jsonb, '[{"particle":"down","storageKeyPrefix":"letDown","meanings":[{"definition":"To disappoint someone by failing to do what you promised or what they expected.","example":"The manager promised a bonus, but she let the team down by canceling it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager letting the team down by canceling a promised bonus"},{"definition":"To make clothing longer.","example":"My son has grown so much that I need to let down his trousers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Parent letting down the hem of trousers for a growing child"},{"definition":"To allow air to escape from something (like a tire).","example":"Someone let down the tires on my car.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Someone letting down the tires on a car"}]},{"particle":"in","storageKeyPrefix":"letIn","meanings":[{"definition":"To allow someone or something to enter a place.","example":"Please open the door and let the client in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person opening the door to let the client in"},{"definition":"To allow someone to share a secret or know about a special plan.","example":"The CEO let me in on the new business strategy before it was announced.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO letting an employee in on the new business strategy"}]},{"particle":"into","storageKeyPrefix":"letInto","meanings":[{"definition":"To allow someone to enter a room or building.","example":"The security guard let us into the server room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Security guard letting employees into the server room"},{"definition":"To share a secret with someone.","example":"She let me into her plans for starting a new software company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sharing secret plans for starting a new software company"}]},{"particle":"off","storageKeyPrefix":"letOff","meanings":[{"definition":"To not punish someone, or to give them a very light punishment.","example":"The boss let him off with a warning for being late to the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Boss letting an employee off with a warning for being late"},{"definition":"To make a bomb explode, or to fire a gun or firework.","example":"The children let off fireworks in the park to celebrate.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Children letting off fireworks in the park to celebrate"},{"definition":"To excuse someone from a duty or obligation.","example":"My manager let me off early today so I could go to the doctor.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager letting an employee off early to go to the doctor"}]},{"particle":"on","storageKeyPrefix":"letOn","meanings":[{"definition":"To reveal a secret or show that you know something.","example":"We are planning a surprise party, so please don''t let on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being asked not to let on about a surprise party"},{"definition":"To pretend.","example":"He let on that he was an expert in Java, but he actually knew very little.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person letting on that they are an expert in Java"}]},{"particle":"out","storageKeyPrefix":"letOut","meanings":[{"definition":"To allow a person or animal to leave a place.","example":"Someone left the gate open and let the dogs out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dogs being let out through an open gate"},{"definition":"To make clothing wider.","example":"I gained a few kilos on holiday, so I need to let out this suit.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person letting out a suit after gaining weight on holiday"},{"definition":"To suddenly make a sound.","example":"She let out a sigh of relief when the code finally compiled.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer letting out a sigh of relief when code finally compiled"},{"definition":"When a class, school, or meeting finishes and people can leave.","example":"The leadership seminar lets out at 4:00 PM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership seminar letting out at 4:00 PM"}]},{"particle":"up","storageKeyPrefix":"letUp","meanings":[{"definition":"To stop or become less severe (usually referring to bad weather or a difficult situation).","example":"The heavy workload hasn''t let up since we started this new project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Heavy workload not letting up since starting a new project"},{"definition":"To stop working as hard as you were before.","example":"We are close to the deadline, so we can''t let up now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team unable to let up as deadline approaches"}]},{"particle":"by","storageKeyPrefix":"letBy","meanings":[{"definition":"To move aside to allow someone or something to pass you.","example":"Please step aside and let the paramedics by.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person stepping aside to let the paramedics by"}]},{"particle":"through","storageKeyPrefix":"letThrough","meanings":[{"definition":"To allow someone or something to pass a barrier, a security check, or a test.","example":"The firewall is strictly configured and will not let unauthorized traffic through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Firewall not letting unauthorized traffic through"}]}]'::jsonb),
  ('log', 'Log', '["in / into","out","on","off","up"]'::jsonb, '[{"particle":"in / into","storageKeyPrefix":"logIn","meanings":[{"definition":"To provide credentials (like a username and password) to access a computer system, application, or network.","example":"You must log into the Java application using your administrator credentials.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person logging into a Java application using administrator credentials"},{"definition":"To officially record that someone has arrived at a place, such as an office or hotel.","example":"All new contractors need to log in at the reception desk before entering the building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New contractors logging in at the reception desk before entering the building"}]},{"particle":"out","storageKeyPrefix":"logOut","meanings":[{"definition":"To safely close your session and disconnect from a system, application, or website.","example":"Always remember to log out of the database when you finish your shift.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person logging out of a database at the end of their shift"}]},{"particle":"on","storageKeyPrefix":"logOn","meanings":[{"definition":"To connect to a computer network or start using a digital system (same meaning as log in).","example":"The project manager logged on to the company network to review the latest software release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project manager logging on to company network to review the latest software release"}]},{"particle":"off","storageKeyPrefix":"logOff","meanings":[{"definition":"To disconnect from a computer network or system (same meaning as log out).","example":"Make sure you log off your workstation before leaving the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee logging off their workstation before leaving the office"}]},{"particle":"up","storageKeyPrefix":"logUp","meanings":[{"definition":"To achieve, record, or complete a specific amount of time, distance, or number of items (more common in British English).","example":"The development team has logged up over 200 hours of overtime to meet the project deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Development team logging up over 200 hours of overtime to meet the project deadline"}]}]'::jsonb),
  ('look', 'Look', '["after","ahead","around / round / about","away","back (on)","down on","for","forward to","in (on)","into","on","out","over","through","to","up"]'::jsonb, '[{"particle":"after","storageKeyPrefix":"lookAfter","meanings":[{"definition":"To take care of someone or something and make sure they have what they need.","example":"As a manager, you must look after your team''s well-being.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager looking after the team''s well-being"}]},{"particle":"ahead","storageKeyPrefix":"lookAhead","meanings":[{"definition":"To think about and plan for the future.","example":"A good leader needs to look ahead to anticipate changes in the market.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leader looking ahead to anticipate market changes"}]},{"particle":"around / round / about","storageKeyPrefix":"lookAround","meanings":[{"definition":"To walk through a place to see what is there.","example":"We took some time to look around the new office before the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team looking around the new office before a meeting"},{"definition":"To search for something in various places.","example":"I am looking about for a new software developer to join the team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking about for a new software developer to hire"}]},{"particle":"away","storageKeyPrefix":"lookAway","meanings":[{"definition":"To turn your eyes away from someone or something.","example":"The presentation data was so confusing that I had to look away from the screen.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking away from confusing presentation data on the screen"}]},{"particle":"back (on)","storageKeyPrefix":"lookBack","meanings":[{"definition":"To think about something that happened in the past.","example":"When I look back on my early days programming in Java, I realize how much I have learned.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer looking back on early Java programming days"}]},{"particle":"down on","storageKeyPrefix":"lookDown","meanings":[{"definition":"To think that you are better or more important than someone else.","example":"A professional leader should never look down on junior employees.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Professional leader avoiding looking down on junior employees"}]},{"particle":"for","storageKeyPrefix":"lookFor","meanings":[{"definition":"To try to find something or someone.","example":"The development team is looking for a solution to the database error.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Development team looking for a solution to a database error"}]},{"particle":"forward to","storageKeyPrefix":"lookForward","meanings":[{"definition":"To feel excited and happy about something that is going to happen in the future.","example":"I look forward to reviewing the new business strategy with you tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking forward to reviewing a new business strategy"}]},{"particle":"in (on)","storageKeyPrefix":"lookIn","meanings":[{"definition":"To visit a person for a short time, usually to check that they are okay.","example":"I will look in on the new trainees later to see if they need help.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager looking in on new trainees to check if they need help"}]},{"particle":"into","storageKeyPrefix":"lookInto","meanings":[{"definition":"To investigate or research the facts of a situation or problem.","example":"The IT department will look into why the server crashed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT department looking into the cause of a server crash"}]},{"particle":"on","storageKeyPrefix":"lookOn","meanings":[{"definition":"To watch an event happen without taking part in it.","example":"The manager looked on as the team successfully deployed the new code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager looking on as the team deploys new code"},{"definition":"To consider someone or something in a specific way.","example":"I look on her as the best project manager in the company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking on a colleague as the best project manager"}]},{"particle":"out","storageKeyPrefix":"lookOut","meanings":[{"definition":"To be careful or to warn someone of danger.","example":"Look out! That server rack is falling.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warning to look out as a server rack is falling"},{"definition":"To take care of someone and make sure they are treated well (look out for).","example":"Good business partners always look out for each other.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business partners looking out for each other"},{"definition":"To watch carefully in order to find something (look out for).","example":"Please look out for any spelling errors in the final contract.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking out for spelling errors in a final contract"}]},{"particle":"over","storageKeyPrefix":"lookOver","meanings":[{"definition":"To examine or read something quickly to check its quality.","example":"Could you look over this financial report before I send it to the client?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking over a financial report before sending it to a client"}]},{"particle":"through","storageKeyPrefix":"lookThrough","meanings":[{"definition":"To read something quickly.","example":"I will look through the Java documentation to find the correct method.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer looking through Java documentation to find a method"},{"definition":"To deliberately ignore someone you know by pretending you do not see them.","example":"I smiled at my former boss, but he just looked straight through me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Former boss looking straight through a person and pretending not to see them"}]},{"particle":"to","storageKeyPrefix":"lookTo","meanings":[{"definition":"To rely on someone to provide something (like help or advice).","example":"The board of directors looks to the CEO for clear guidance.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Board of directors looking to the CEO for guidance"},{"definition":"To direct your attention to something.","example":"We must look to our competitors to see what strategies they are using.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team looking to competitors to study their strategies"}]},{"particle":"up","storageKeyPrefix":"lookUp","meanings":[{"definition":"To try to find a piece of information in a book, list, or on the internet.","example":"If you don''t know the exact syntax, look it up in the manual.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person looking up syntax in a manual"},{"definition":"To improve or get better (usually referring to a situation or business).","example":"After a difficult first quarter, sales are finally looking up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sales looking up after a difficult first quarter"},{"definition":"To contact or visit someone you have not seen for a long time.","example":"If you are ever in Warsaw, please look me up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being asked to look up a friend when visiting Warsaw"},{"definition":"To deeply respect and admire someone (look up to).","example":"Many junior developers look up to him because of his deep technical knowledge.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Junior developers looking up to an experienced developer for his technical knowledge"}]}]'::jsonb),
  ('make', 'Make', '["after","away (with)","for","into","off (with)","out","over","up","up for","with"]'::jsonb, '[{"particle":"after","storageKeyPrefix":"makeAfter","meanings":[{"definition":"To chase someone or something","example":"The security guard made after the shoplifter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A security guard chasing a shoplifter"}]},{"particle":"away (with)","storageKeyPrefix":"makeAway","meanings":[{"definition":"To steal something and escape with it (make away with)","example":"Hackers made away with thousands of encrypted passwords.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hackers stealing encrypted passwords"}]},{"particle":"for","storageKeyPrefix":"makeFor","meanings":[{"definition":"To move directly towards a place","example":"After the meeting ended, we made for the exit.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People moving towards the exit after a meeting"},{"definition":"To help make something possible or produce a specific result","example":"Clear communication makes for a highly effective management team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team communicating clearly and effectively"}]},{"particle":"into","storageKeyPrefix":"makeInto","meanings":[{"definition":"To change or transform something into something else","example":"The developers made the old legacy system into a modern Java application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers transforming a legacy system into a modern application"}]},{"particle":"off (with)","storageKeyPrefix":"makeOff","meanings":[{"definition":"To leave quickly, especially to escape after doing something wrong (make off with)","example":"The thieves made off before the police arrived.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Thieves leaving quickly before police arrive"}]},{"particle":"out","storageKeyPrefix":"makeOut","meanings":[{"definition":"To manage to see, hear, or read something with difficulty","example":"I could not make out the error message on the monitor because the screen was too bright.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person struggling to read an error message on a bright screen"},{"definition":"To understand someone''s character or a situation","example":"He is a very quiet team leader; I cannot quite make him out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person trying to understand their team leader"},{"definition":"To write all the necessary information on an official document (like a check or invoice)","example":"Please make the invoice out to the company''s head office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person writing an invoice to a head office"},{"definition":"To claim or pretend that something is true","example":"The software vendor made out that their system was completely bug-free.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A software vendor claiming their system has no bugs"},{"definition":"To progress, perform, or succeed in a situation","example":"How did you make out with the new project timeline?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person asking about progress on a project timeline"},{"definition":"To kiss and touch romantically (informal)","example":"The teenagers were making out in the back of the cinema.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teenagers at the back of a cinema"}]},{"particle":"over","storageKeyPrefix":"makeOver","meanings":[{"definition":"To change or improve the appearance of someone or something","example":"We made over the entire office space to encourage better collaboration.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An office space being redesigned for better collaboration"},{"definition":"To legally transfer ownership of property or money to someone else","example":"The CEO made over his shares to his business partner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A CEO transferring shares to a business partner"}]},{"particle":"up","storageKeyPrefix":"makeUp","meanings":[{"definition":"To invent a story, excuse, or explanation","example":"He made up an excuse for missing the daily stand-up meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person inventing an excuse for missing a meeting"},{"definition":"To form the whole of something","example":"Senior developers make up 40% of our engineering department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Senior developers forming part of an engineering department"},{"definition":"To become friendly again after an argument","example":"The co-founders argued over the budget, but they made up the next day.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two co-founders reconciling after an argument"},{"definition":"To prepare, build, or arrange something from parts","example":"Can you make up a list of requirements for the new software module?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person preparing a list of requirements"}]},{"particle":"up for","storageKeyPrefix":"makeUpFor","meanings":[{"definition":"To compensate for something bad, missing, or lost","example":"We worked late on Friday to make up for the time lost during the server crash.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team members working late to compensate for lost time"}]},{"particle":"with","storageKeyPrefix":"makeWith","meanings":[{"definition":"To produce, supply, or give something quickly (slang/informal)","example":"Make with the financial reports, the board is waiting!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person urgently requesting financial reports for the board"}]}]'::jsonb),
  ('mix', 'Mix', '["up","in / into","with","together","down"]'::jsonb, '[{"particle":"up","storageKeyPrefix":"mixUp","meanings":[{"definition":"To confuse two things or people by thinking that one person or thing is another because they are similar.","example":"I always mix up the two brothers because they look exactly the same.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person confusing two brothers who look exactly the same"},{"definition":"To make a mixture by combining different ingredients.","example":"Give me a few minutes, and I will mix up some pancake batter for breakfast.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person mixing up pancake batter for breakfast"},{"definition":"To do something differently to make it more interesting and less boring (\"mix it up\").","example":"We usually have our team meetings on Mondays, but let''s mix it up and meet on Friday this week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team deciding to mix up their meeting schedule by switching from Monday to Friday"},{"definition":"To be connected to or involved in something illegal, dishonest, or complicated (\"be mixed up in\").","example":"The manager was fired when the company discovered he was mixed up in financial fraud.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager being fired after being discovered mixed up in financial fraud"}]},{"particle":"in / into","storageKeyPrefix":"mixIn","meanings":[{"definition":"To put a new substance into an existing mixture and stir it.","example":"Add the sugar to the bowl and mix it in slowly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person adding sugar to a bowl and mixing it in slowly"},{"definition":"To join a group of people and interact with them naturally.","example":"The new employee tried to mix in with the rest of the team during the lunch break.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New employee mixing in with the rest of the team during lunch break"}]},{"particle":"with","storageKeyPrefix":"mixWith","meanings":[{"definition":"To spend time talking to different people, usually at a social event or at work.","example":"A good leader needs to be able to mix with people from all departments.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Good leader mixing with people from all departments"},{"definition":"To put two or more substances together.","example":"Oil does not mix with water.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Oil and water that do not mix together"}]},{"particle":"together","storageKeyPrefix":"mixTogether","meanings":[{"definition":"To blend two or more items so that they become a single substance or group.","example":"In software development, you cannot easily mix together two completely different programming architectures.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software developer unable to mix together two completely different programming architectures"}]},{"particle":"down","storageKeyPrefix":"mixDown","meanings":[{"definition":"In audio engineering and music production, to combine multiple individual sound tracks into one final stereo or mono track.","example":"After recording the vocals and instruments, the sound engineer will mix down the project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sound engineer mixing down vocals and instruments into a final track"}]}]'::jsonb),
  ('pass', 'Pass', '["away","by","down","for","in","into","off","on","out","over","through","to","up","around / round / about"]'::jsonb, '[{"particle":"away","storageKeyPrefix":"passAway","meanings":[{"definition":"To die (a polite and respectful phrase).","example":"The founder of the company passed away peacefully last year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The founder of the company passed away peacefully last year"}]},{"particle":"by","storageKeyPrefix":"passBy","meanings":[{"definition":"To go past a place or person.","example":"I pass by your office every morning on my way to get coffee.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person passing by an office every morning on the way to get coffee"},{"definition":"To happen without affecting someone, or to miss an opportunity.","example":"We cannot let this great market opportunity pass us by.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team unable to let a great market opportunity pass them by"}]},{"particle":"down","storageKeyPrefix":"passDown","meanings":[{"definition":"To give knowledge, skills, or items to younger generations or junior members.","example":"The senior manager passed down her negotiation skills to the new team members.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Senior manager passing down negotiation skills to new team members"}]},{"particle":"for","storageKeyPrefix":"passFor","meanings":[{"definition":"To be accepted as something else, often despite not being it.","example":"His Java skills are so good that he could easily pass for a senior developer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer with such good Java skills that he could pass for a senior developer"}]},{"particle":"in","storageKeyPrefix":"passIn","meanings":[{"definition":"To give work to a teacher or manager (similar to \"hand in\").","example":"Please remember to pass in your project reports by Friday afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee passing in project reports by Friday afternoon"}]},{"particle":"into","storageKeyPrefix":"passInto","meanings":[{"definition":"To become part of something, usually history or legend.","example":"His successful software release passed into company history.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A successful software release passing into company history"}]},{"particle":"off","storageKeyPrefix":"passOff","meanings":[{"definition":"To falsely present someone or something as something else.","example":"He tried to pass off the copied code as his own original work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer trying to pass off copied code as his own original work"},{"definition":"To happen or take place in a certain way.","example":"The project launch passed off without any major problems.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project launch passing off without any major problems"}]},{"particle":"on","storageKeyPrefix":"passOn","meanings":[{"definition":"To give information or an object to someone else.","example":"Please pass on this message to the development team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person passing on a message to the development team"},{"definition":"To refuse an opportunity or offer.","example":"I think I will pass on the invitation to the conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person deciding to pass on the invitation to the conference"},{"definition":"To die (another polite phrase).","example":"Sadly, his grandfather passed on last week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person''s grandfather sadly passing on last week"}]},{"particle":"out","storageKeyPrefix":"passOut","meanings":[{"definition":"To distribute something to a group of people.","example":"Could you pass out these documents before the management meeting starts?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person passing out documents before the management meeting starts"},{"definition":"To lose consciousness or faint.","example":"It was so hot in the server room that he almost passed out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person almost passing out because it was so hot in the server room"}]},{"particle":"over","storageKeyPrefix":"passOver","meanings":[{"definition":"To ignore or not choose someone for a position or promotion.","example":"She was passed over for the leadership role, so she decided to leave the company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee passed over for the leadership role deciding to leave the company"},{"definition":"To ignore a topic in a conversation.","example":"Let''s pass over this minor detail and focus on the main strategy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team deciding to pass over a minor detail and focus on the main strategy"}]},{"particle":"through","storageKeyPrefix":"passThrough","meanings":[{"definition":"To travel or stop in a place for a very short time.","example":"I am just passing through Warsaw, so I only have time for a quick lunch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Traveller passing through Warsaw with only time for a quick lunch"},{"definition":"To experience a phase or situation.","example":"The tech industry is passing through a difficult period right now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"The tech industry passing through a difficult period"}]},{"particle":"to","storageKeyPrefix":"passTo","meanings":[{"definition":"To transfer ownership or responsibility to someone else.","example":"When the CEO retired, leadership passed to her deputy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership passing to the deputy when the CEO retired"}]},{"particle":"up","storageKeyPrefix":"passUp","meanings":[{"definition":"To fail to take advantage of an opportunity.","example":"You should not pass up the chance to lead this new team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being advised not to pass up the chance to lead a new team"}]},{"particle":"around / round / about","storageKeyPrefix":"passAround","meanings":[{"definition":"To offer or give something to every person in a group.","example":"They passed around the tablet so everyone could see the new app design.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team passing around a tablet so everyone could see the new app design"}]}]'::jsonb),
  ('pay', 'Pay', '["off","up","down","in / into","out","away","forward","back","for","over"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"payOff","meanings":[{"definition":"To completely pay back a debt.","example":"After five years, the company finally paid off its bank loan.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company finally paying off its bank loan after five years"},{"definition":"To result in success or yield good results after hard work or investment.","example":"The team''s long hours of coding really paid off when the software launched successfully.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team''s long hours of coding paying off when the software launched successfully"},{"definition":"To bribe someone so they keep quiet or do not cause trouble.","example":"The corrupt manager tried to pay off the inspector.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Corrupt manager trying to pay off the inspector"},{"definition":"To dismiss workers and give them their final wages (more common in British English).","example":"The factory closed down and paid off all its workers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Factory closing down and paying off all its workers"}]},{"particle":"up","storageKeyPrefix":"payUp","meanings":[{"definition":"To give someone the money you owe them, especially when you do not want to or when you are forced to do it.","example":"The supplier threatened legal action until the client finally paid up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Client finally paying up after supplier threatened legal action"}]},{"particle":"down","storageKeyPrefix":"payDown","meanings":[{"definition":"To reduce the total amount of a debt by paying a portion of it.","example":"The management team decided to pay down the company''s debt before investing in new projects.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Management team deciding to pay down the company''s debt before investing in new projects"}]},{"particle":"in / into","storageKeyPrefix":"payIn","meanings":[{"definition":"To put money into a bank account, pension, or fund.","example":"I need to go to the bank to pay in these checks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person going to the bank to pay in some checks"}]},{"particle":"out","storageKeyPrefix":"payOut","meanings":[{"definition":"To disburse or spend a large amount of money, often from a fund, insurance, or company profit (like dividends).","example":"The insurance policy paid out $50,000 after the office roof leaked.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Insurance policy paying out after the office roof leaked"},{"definition":"To slowly release or let out a rope (nautical).","example":"The sailor paid out the rope to let the boat move away from the dock.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sailor paying out the rope to let the boat move away from the dock"}]},{"particle":"away","storageKeyPrefix":"payAway","meanings":[{"definition":"Similar to \"pay out,\" meaning to let a rope slide through your hands (nautical/rare).","example":"He paid away the line as the anchor dropped.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sailor paying away the line as the anchor dropped"}]},{"particle":"forward","storageKeyPrefix":"payForward","meanings":[{"definition":"To respond to someone\\''s kindness or help by doing a good deed for someone else, rather than returning the favor to the original person.","example":"My mentor helped me start my career, so I try to pay it forward by mentoring junior developers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person paying it forward by mentoring junior developers after being helped by a mentor"}]},{"particle":"back","storageKeyPrefix":"payBack","meanings":[{"definition":"To return money to someone who loaned it to you.","example":"If you lend me $20 for lunch, I will pay you back tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person promising to pay back $20 borrowed for lunch"},{"definition":"To do something bad to someone because they did something bad to you (revenge).","example":"I will pay him back for stealing my promotion.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person planning to pay back someone who stole their promotion"}]},{"particle":"for","storageKeyPrefix":"payFor","meanings":[{"definition":"To give money in exchange for goods or services.","example":"The company will pay for your travel expenses.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company agreeing to pay for travel expenses"},{"definition":"To suffer the negative results of a mistake or bad decision.","example":"We ignored the software bugs during testing, and now we are paying for it with customer complaints.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team paying for ignoring software bugs with customer complaints"}]},{"particle":"over","storageKeyPrefix":"payOver","meanings":[{"definition":"To transfer money to someone in authority or to a third party.","example":"The business is required to pay over all collected taxes to the government at the end of the quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business paying over collected taxes to the government at the end of the quarter"}]}]'::jsonb),
  ('pick', 'Pick', '["apart","away","off","on","out","over","through","up"]'::jsonb, '[{"particle":"apart","storageKeyPrefix":"pickApart","meanings":[{"definition":"To pull something into separate physical pieces.","example":"The birds picked the piece of bread apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Birds picking the piece of bread apart"},{"definition":"To find all the mistakes or flaws in an idea or argument.","example":"The senior developers picked my code architecture apart during the review.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Senior developers picking apart code architecture during review"}]},{"particle":"away","storageKeyPrefix":"pickAway","meanings":[{"definition":"To remove small pieces of something slowly.","example":"He picked away the old paint from the wall.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person picking away old paint from the wall"},{"definition":"To slowly reduce or destroy something (usually \"pick away at\").","example":"The new competitor slowly picked away at our market share.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New competitor picking away at market share"}]},{"particle":"off","storageKeyPrefix":"pickOff","meanings":[{"definition":"To target or shoot one by one.","example":"The sniper picked off the enemy guards from a distance.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sniper picking off enemy guards from a distance"},{"definition":"To remove something by pulling it.","example":"She picked off the dry leaves from the houseplant.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person picking off dry leaves from the houseplant"},{"definition":"To intercept (often in sports).","example":"The defender picked off the pass perfectly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Defender picking off the pass perfectly"}]},{"particle":"on","storageKeyPrefix":"pickOn","meanings":[{"definition":"To bully or treat someone unfairly.","example":"The older children always picked on him at school.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Older children picking on a student at school"},{"definition":"To choose someone to do a task or answer a question.","example":"The manager picked on me to lead the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager picking someone to lead the presentation"}]},{"particle":"out","storageKeyPrefix":"pickOut","meanings":[{"definition":"To choose or select carefully.","example":"We need to pick out a good candidate for the management role.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team picking out a candidate for the management role"},{"definition":"To recognize someone or something in a group.","example":"I could easily pick her out in the crowded room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person picking someone out in a crowded room"},{"definition":"To play a tune on an instrument slowly or with difficulty.","example":"He picked out a simple melody on the piano.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Musician picking out a simple melody on the piano"}]},{"particle":"over","storageKeyPrefix":"pickOver","meanings":[{"definition":"To carefully examine a group of things to select the best ones.","example":"By the time I arrived at the market, the best fruit had already been picked over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Fruit at the market already picked over by the time someone arrived"}]},{"particle":"through","storageKeyPrefix":"pickThrough","meanings":[{"definition":"To search carefully among a pile or collection of items.","example":"The team picked through the raw data looking for helpful trends.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team picking through raw data looking for helpful trends"}]},{"particle":"up","storageKeyPrefix":"pickUp","meanings":[{"definition":"To lift something from a surface.","example":"Please pick up your clothes from the floor.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person picking up clothes from the floor"},{"definition":"To collect someone in a vehicle.","example":"I will pick you up at the airport at six.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being picked up at the airport"},{"definition":"To learn a skill casually, without formal training.","example":"I picked up some new programming skills while working on that project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer picking up new programming skills on a project"},{"definition":"To improve or increase.","example":"Sales usually pick up in the fourth quarter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sales graph picking up in the fourth quarter"},{"definition":"To catch an illness.","example":"I picked up a bad cold at the conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person picking up a cold at the conference"},{"definition":"To resume an activity (often \"pick back up\").","example":"We are out of time, so let''s pick this discussion back up tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team planning to pick up a discussion again tomorrow"},{"definition":"To pay a bill.","example":"The company will pick up the tab for the team dinner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company picking up the tab for the team dinner"},{"definition":"To notice or detect something (usually \"pick up on\").","example":"The software easily picks up on errors in the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software picking up on errors in the code"}]}]'::jsonb),
  ('point', 'Point', '["ahead / forward","back","off","out","to","up"]'::jsonb, '[{"particle":"ahead / forward","storageKeyPrefix":"pointAhead","meanings":[{"definition":"To look toward or indicate the future.","example":"This new business model points forward to a more automated and efficient company.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business model pointing forward to an automated and efficient company"}]},{"particle":"back","storageKeyPrefix":"pointBack","meanings":[{"definition":"To show that something is connected to a past event, or to remind someone of the past.","example":"Most of these software bugs point back to the rushed code we merged last month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software bugs pointing back to rushed code merged last month"}]},{"particle":"off","storageKeyPrefix":"pointOff","meanings":[{"definition":"To separate numbers with a decimal point (used mainly in mathematics and accounting).","example":"When calculating the final cost, remember to point off two decimal places.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Pointing off decimal places when calculating final cost"}]},{"particle":"out","storageKeyPrefix":"pointOut","meanings":[{"definition":"To tell someone a fact they did not know or had forgotten.","example":"The lead developer pointed out that the Java update would break our older systems.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lead developer pointing out that a Java update would break older systems"},{"definition":"To direct attention to someone or something using your finger.","example":"During the office tour, the manager pointed out where the IT department sits.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager pointing out where the IT department sits during office tour"}]},{"particle":"to","storageKeyPrefix":"pointTo","meanings":[{"definition":"To mention something as proof or as a reason why something happened.","example":"The CEO pointed to the new marketing strategy to explain the sudden growth in sales.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO pointing to new marketing strategy to explain growth in sales"},{"definition":"To suggest that a particular situation or result is likely.","example":"All the server performance metrics point to a memory leak in the application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server performance metrics pointing to a memory leak in the application"},{"definition":"To physically aim your finger or an object at something.","example":"The architect pointed to the database schema on the whiteboard.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Architect pointing to the database schema on the whiteboard"}]},{"particle":"up","storageKeyPrefix":"pointUp","meanings":[{"definition":"To emphasize something or make a problem easier to notice (similar to \"highlight\").","example":"The recent system crash points up the need for better error handling in our code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"System crash pointing up the need for better error handling in code"}]}]'::jsonb),
  ('pull', 'Pull', '["about","ahead","against","apart","around / round","away","back","down","for","forward","in","into","off","on","out","over","through","to","together","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"pullAbout","meanings":[{"definition":"To treat someone or something roughly.","example":"The older children were pulling the little boy about, so the teacher intervened.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Older children pulling a little boy about while teacher intervenes"}]},{"particle":"ahead","storageKeyPrefix":"pullAhead","meanings":[{"definition":"To take the lead in a race or competition.","example":"In the final months of the year, our software company finally pulled ahead of the competition.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Software company pulling ahead of the competition in the final months"}]},{"particle":"against","storageKeyPrefix":"pullAgainst","meanings":[{"definition":"To resist or oppose a force.","example":"The dog kept pulling against the leash.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dog pulling against the leash"},{"definition":"To work in opposition to someone.","example":"The team will fail if half the members are pulling against the manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team members pulling against the manager causing failure"}]},{"particle":"apart","storageKeyPrefix":"pullApart","meanings":[{"definition":"To separate people or animals that are fighting.","example":"The referee had to pull the two players apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Referee pulling two players apart during a fight"},{"definition":"To criticize heavily to show the flaws in something.","example":"The manager pulled the marketing plan apart during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager pulling the marketing plan apart during a meeting"},{"definition":"To break or tear something into pieces.","example":"The child pulled the toy apart to see how it worked.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child pulling a toy apart to see how it works"}]},{"particle":"around / round","storageKeyPrefix":"pullAround","meanings":[{"definition":"To recover from a serious illness or injury (mostly British English).","example":"He was very sick after the surgery, but the doctors say he will pull round.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Patient recovering after surgery as doctors say he will pull round"}]},{"particle":"away","storageKeyPrefix":"pullAway","meanings":[{"definition":"To start moving (usually a vehicle).","example":"The train pulled away from the station exactly on time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Train pulling away from the station exactly on time"},{"definition":"To move your body back from someone.","example":"She pulled away when he tried to grab her arm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling away when someone tries to grab their arm"},{"definition":"To increase your lead in a competition.","example":"In the second half of the race, the leading runner pulled away from the rest of the group.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leading runner pulling away from the rest of the group in the second half"}]},{"particle":"back","storageKeyPrefix":"pullBack","meanings":[{"definition":"To retreat or move backwards.","example":"The army was ordered to pull back from the city.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Army ordered to pull back from the city"},{"definition":"To decide not to do something you previously planned.","example":"The investors pulled back from the deal at the last minute because of financial risks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Investors pulling back from a deal at the last minute due to financial risks"}]},{"particle":"down","storageKeyPrefix":"pullDown","meanings":[{"definition":"To demolish or destroy a building.","example":"They are pulling down the old factory to build a new office block.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Workers pulling down an old factory to build a new office block"},{"definition":"To make someone feel depressed or weak.","example":"The stress of the new project is really pulling him down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project stress pulling a person down and making them feel depressed"},{"definition":"To earn a specific amount of money (informal).","example":"As a senior Java developer, she pulls down a very high salary.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Senior Java developer pulling down a very high salary"}]},{"particle":"for","storageKeyPrefix":"pullFor","meanings":[{"definition":"To support, hope, or cheer for someone\\''s success.","example":"Good luck with your job interview tomorrow! We are all pulling for you.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team pulling for a colleague before their job interview"}]},{"particle":"forward","storageKeyPrefix":"pullForward","meanings":[{"definition":"To move a vehicle slightly forward.","example":"Can you pull forward a little bit so I have room to park behind you?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driver pulling forward slightly to make room for parking"}]},{"particle":"in","storageKeyPrefix":"pullIn","meanings":[{"definition":"To arrive (usually for trains).","example":"The train from Warsaw is pulling in at platform 3.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Train from Warsaw pulling in at platform 3"},{"definition":"To move a vehicle to the side of the road.","example":"I need to pull in at the next gas station.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driver pulling in at the next gas station"},{"definition":"To attract people or money.","example":"The new advertising campaign is pulling in a lot of new customers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New advertising campaign pulling in many new customers"},{"definition":"To arrest someone.","example":"The police pulled him in for questioning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police pulling someone in for questioning"}]},{"particle":"into","storageKeyPrefix":"pullInto","meanings":[{"definition":"To arrive at a destination (for vehicles).","example":"The bus pulled into the station twenty minutes late.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bus pulling into the station twenty minutes late"}]},{"particle":"off","storageKeyPrefix":"pullOff","meanings":[{"definition":"To succeed in doing something very difficult or unexpected.","example":"No one thought we could finish the software update by Friday, but the team pulled it off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team pulling off a software update by Friday against all expectations"},{"definition":"To drive a vehicle off the main road.","example":"We pulled off the highway to find a place to eat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Car pulling off the highway to find a place to eat"},{"definition":"To remove clothing quickly.","example":"He pulled off his boots and left them by the door.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling off their boots and leaving them by the door"}]},{"particle":"on","storageKeyPrefix":"pullOn","meanings":[{"definition":"To put on clothing quickly.","example":"She pulled on a sweater because it was getting cold.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling on a sweater because it is getting cold"},{"definition":"To breathe in smoke from a cigarette or pipe.","example":"He pulled heavily on his cigar.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling heavily on a cigar"}]},{"particle":"out","storageKeyPrefix":"pullOut","meanings":[{"definition":"To move into traffic (for vehicles).","example":"A truck pulled out right in front of me, and I had to brake hard.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Truck pulling out in front of a car forcing the driver to brake hard"},{"definition":"To leave a station (for trains).","example":"Our train was pulling out just as we arrived at the platform.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Train pulling out just as passengers arrive at the platform"},{"definition":"To withdraw from an agreement, deal, or situation.","example":"The sponsor pulled out of the project due to budget cuts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sponsor pulling out of the project due to budget cuts"},{"definition":"To extract or remove something.","example":"He reached into his bag and pulled out a laptop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person reaching into their bag and pulling out a laptop"}]},{"particle":"over","storageKeyPrefix":"pullOver","meanings":[{"definition":"To stop a vehicle by the side of the road.","example":"The police officer signaled for the driver to pull over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police officer signaling for a driver to pull over"}]},{"particle":"through","storageKeyPrefix":"pullThrough","meanings":[{"definition":"To recover from a very serious illness or injury.","example":"It was a terrible accident, but the doctors are confident she will pull through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Doctors confident that a patient will pull through after a terrible accident"},{"definition":"To succeed in a very difficult situation.","example":"The economy was bad, but strong leadership helped the business pull through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Strong leadership helping a business pull through a bad economy"}]},{"particle":"to","storageKeyPrefix":"pullTo","meanings":[{"definition":"To close something, like a door or window, but often without locking it.","example":"Please pull the door to when you leave the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling the door to when leaving the office"}]},{"particle":"together","storageKeyPrefix":"pullTogether","meanings":[{"definition":"To work as a team to achieve something.","example":"If we all pull together, we can finish this development phase by the deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team pulling together to finish a development phase by the deadline"},{"definition":"To collect or organize information/things.","example":"I need an hour to pull together the data for the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person taking an hour to pull together data for a presentation"},{"definition":"To regain emotional control (often \"pull yourself together\").","example":"You need to pull yourself together and focus on the task.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling themselves together and focusing on the task"}]},{"particle":"up","storageKeyPrefix":"pullUp","meanings":[{"definition":"To slow down and stop a vehicle.","example":"A black taxi pulled up outside the building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Black taxi pulling up outside the building"},{"definition":"To bring information onto a computer screen.","example":"Give me a second to pull up your account on my system.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling up a customer account on their system"},{"definition":"To correct or criticize someone for a mistake.","example":"The manager pulled him up on his constant lateness.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager pulling an employee up on their constant lateness"},{"definition":"To move a piece of furniture closer.","example":"Pull up a chair and join our meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person pulling up a chair to join a meeting"}]}]'::jsonb),
  ('put', 'Put', '["off","on","up","down","in","into","out","away","across / over","forward","back","by","together","with","ahead","behind","through","about / around / round","to"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"putOff","meanings":[{"definition":"To delay or postpone something","example":"We have to put off the sprint planning meeting until tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A meeting being postponed"},{"definition":"To make someone not want to do something or dislike something","example":"The complex code architecture put me off learning Java at first.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person deterred by complex code"},{"definition":"To distract someone","example":"Please be quiet; your talking is putting me off my work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person being distracted from their work"}]},{"particle":"on","storageKeyPrefix":"putOn","meanings":[{"definition":"To dress oneself in clothing","example":"I put on my suit for the management interview.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person putting on a suit for an interview"},{"definition":"To organize a performance or event","example":"The company put on a great training event for new developers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company training event for developers"},{"definition":"To gain weight","example":"He put on three kilos during the holidays.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person who gained weight during holidays"},{"definition":"To turn on a machine or appliance","example":"Could you put the projector on for the presentation?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person turning on a projector for a presentation"},{"definition":"To pretend to have a feeling or attitude","example":"She isn''t really angry; she''s just putting it on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person pretending to be angry"}]},{"particle":"up","storageKeyPrefix":"putUp","meanings":[{"definition":"To build or erect something","example":"They put up a new office building in Warsaw.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A new office building being constructed in Warsaw"},{"definition":"To increase prices or rates","example":"The software provider put up their subscription fees.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A software provider raising subscription fees"},{"definition":"To provide accommodation for someone","example":"I can put you up at my apartment while you are visiting for the conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person offering accommodation to a conference visitor"},{"definition":"To offer resistance or fight back","example":"The competitor put up a strong fight for the market share.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A competitor fighting for market share"}]},{"particle":"down","storageKeyPrefix":"putDown","meanings":[{"definition":"To write something down","example":"Let me put down your contact details.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person writing down contact details"},{"definition":"To criticize or humiliate someone","example":"A good leader never puts down their team members.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A leader treating team members respectfully"},{"definition":"To pay a deposit","example":"We put down a 10% deposit for the new office space.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person paying a deposit for office space"},{"definition":"To suppress a rebellion or protest by force","example":"The government quickly put down the protests.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A government suppressing protests"},{"definition":"To euthanize an animal","example":"The vet had to put down the sick dog.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A vet with a sick dog"},{"definition":"To attribute a cause to something (put down to)","example":"I put the project''s success down to excellent teamwork.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team celebrating a successful project"}]},{"particle":"in","storageKeyPrefix":"putIn","meanings":[{"definition":"To spend time or effort on something","example":"The development team put in 50 hours a week to finish the Java update.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A development team working long hours on a Java update"},{"definition":"To install an appliance or system","example":"We are putting in a new server system today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Technicians installing a new server system"},{"definition":"To officially submit a request or document","example":"I put in a request for more holiday time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person submitting a holiday request form"},{"definition":"To interrupt a conversation with a remark","example":"\"I think we should test the code first,\" the junior developer put in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A junior developer interrupting a conversation"}]},{"particle":"into","storageKeyPrefix":"putInto","meanings":[{"definition":"To invest time, money, or effort into a project","example":"The company put a lot of money into research and development.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company investing in research and development"},{"definition":"To express something in words","example":"It is hard to put this complex business strategy into simple words.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person trying to simplify a complex business strategy"}]},{"particle":"out","storageKeyPrefix":"putOut","meanings":[{"definition":"To extinguish a fire or a cigarette","example":"The fire alarm rang, but they quickly put out the small fire.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People extinguishing a small office fire"},{"definition":"To publish or release something","example":"The team put out a new version of the app last night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team releasing a new app version"},{"definition":"To inconvenience someone","example":"I hope it doesn''t put you out if we move the meeting to 5 PM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person asking if a meeting time change is inconvenient"},{"definition":"To place something outside","example":"Don''t forget to put out the recycling bins.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person placing recycling bins outside"}]},{"particle":"away","storageKeyPrefix":"putAway","meanings":[{"definition":"To store things in their correct place","example":"Please put away those files when you finish reading them.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person storing files in their correct place"},{"definition":"To save money for the future","example":"She puts away a portion of her salary every month for retirement.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person saving money for retirement"},{"definition":"To send someone to prison or a mental hospital (informal)","example":"The judge put him away for ten years for fraud.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A judge sentencing someone for fraud"},{"definition":"To eat or drink a large amount","example":"He can really put away a lot of coffee during a coding session.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer drinking a lot of coffee during a coding session"}]},{"particle":"across / over","storageKeyPrefix":"putAcrossOver","meanings":[{"definition":"To explain an idea clearly so people understand it (put across / put over)","example":"The CEO put his vision across very well during the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A CEO clearly explaining a vision during a meeting"}]},{"particle":"forward","storageKeyPrefix":"putForward","meanings":[{"definition":"To suggest an idea, plan, or person for consideration","example":"The manager put forward a new agile framework for the team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager suggesting an agile framework to the team"},{"definition":"To change a clock to a later time","example":"Don''t forget to put your clocks forward in the spring.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person changing a clock forward in spring"}]},{"particle":"back","storageKeyPrefix":"putBack","meanings":[{"definition":"To return something to its original place","example":"Please put the laptop back in the cabinet.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person returning a laptop to a cabinet"},{"definition":"To delay an event or appointment","example":"The product launch was put back to November.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A product launch calendar being moved to November"},{"definition":"To change a clock to an earlier time","example":"We put the clocks back one hour in the autumn.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person setting a clock back one hour in autumn"}]},{"particle":"by","storageKeyPrefix":"putBy","meanings":[{"definition":"To save money for the future","example":"I try to put by some money each month for a new computer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person saving money each month for a new computer"}]},{"particle":"together","storageKeyPrefix":"putTogether","meanings":[{"definition":"To assemble the parts of something","example":"We need to put together the new office furniture.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People assembling new office furniture"},{"definition":"To organize or create a group or plan","example":"The HR director put together an excellent leadership training program.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An HR director organizing a leadership training program"}]},{"particle":"with","storageKeyPrefix":"putWith","meanings":[{"definition":"To tolerate or accept a difficult situation without complaining (put up with)","example":"As a project manager, you have to put up with unexpected delays.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A project manager dealing with unexpected delays"}]},{"particle":"ahead","storageKeyPrefix":"putAhead","meanings":[{"definition":"To give someone an advantage over others","example":"Learning Java will really put you ahead in the job market.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person gaining an advantage in the job market by learning Java"}]},{"particle":"behind","storageKeyPrefix":"putBehind","meanings":[{"definition":"To forget about a bad experience and move on","example":"We lost a big client, but we need to put it behind us and focus on the future.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team moving forward after losing a client"}]},{"particle":"through","storageKeyPrefix":"putThrough","meanings":[{"definition":"To connect someone on the telephone","example":"Please hold the line, I will put you through to the IT department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A receptionist connecting a call to the IT department"},{"definition":"To make someone experience something very difficult","example":"The tough interview process really put the candidates through a lot of stress.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Candidates experiencing a stressful interview process"},{"definition":"To successfully complete a business transaction or proposal","example":"We finally managed to put the deal through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business partners completing a deal"}]},{"particle":"about / around / round","storageKeyPrefix":"putAboutAroundRound","meanings":[{"definition":"To spread a rumour or false story (put about / put around / put round)","example":"Someone is putting it about that the company is going bankrupt.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A rumour spreading about a company going bankrupt"}]},{"particle":"to","storageKeyPrefix":"putTo","meanings":[{"definition":"To suggest an idea or a question to someone directly","example":"I put it to the board of directors, but they rejected the idea.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person presenting an idea to the board of directors"},{"definition":"To cause trouble or expense for someone","example":"Moving the server room put us to a lot of trouble.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team dealing with the trouble of moving a server room"}]}]'::jsonb),
  ('run', 'Run', '["about / around / round","across","after","against","ahead","away","back","behind","by","down","for","in","into","off","on","out","over","through","to","together","up","with","without"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"runAbout","meanings":[{"definition":"To be very busy doing many different tasks.","example":"The project manager was running around all day trying to organize the sprint planning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project manager running around all day organizing the sprint planning"},{"definition":"To deceive or cheat someone (usually \"run around on\").","example":"The vendor was giving us the runaround instead of delivering the software on time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Vendor giving the runaround instead of delivering software on time"}]},{"particle":"across","storageKeyPrefix":"runAcross","meanings":[{"definition":"To find something or meet someone by chance.","example":"I ran across an old Java library that perfectly solves our database problem.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer running across an old Java library that solves a database problem"}]},{"particle":"after","storageKeyPrefix":"runAfter","meanings":[{"definition":"To chase someone or something.","example":"Startups spend a lot of time running after new investors.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Startups running after new investors"}]},{"particle":"against","storageKeyPrefix":"runAgainst","meanings":[{"definition":"To compete with someone in an election or business contest.","example":"Our product is running against two major competitors in the enterprise market.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Product running against two major competitors in the enterprise market"},{"definition":"To cause difficulties or oppose principles.","example":"The new company policy runs against our agile working methods.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New company policy running against agile working methods"}]},{"particle":"ahead","storageKeyPrefix":"runAhead","meanings":[{"definition":"To progress faster than scheduled.","example":"The development team is running ahead of schedule for the Q3 release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Development team running ahead of schedule for the Q3 release"}]},{"particle":"away","storageKeyPrefix":"runAway","meanings":[{"definition":"To escape or leave a difficult situation.","example":"A good leader does not run away from hard decisions.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Good leader not running away from hard decisions"}]},{"particle":"back","storageKeyPrefix":"runBack","meanings":[{"definition":"To return quickly.","example":"I need to run back to the office to get my security badge.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person running back to the office to get a security badge"},{"definition":"To replay audio or video.","example":"Let''s run the recording back to hear what the client said about the API requirements.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running the recording back to hear what the client said about API requirements"}]},{"particle":"behind","storageKeyPrefix":"runBehind","meanings":[{"definition":"To be late or delayed according to a schedule.","example":"We are running behind on the backend integration.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team running behind on the backend integration"}]},{"particle":"by","storageKeyPrefix":"runBy","meanings":[{"definition":"To tell someone about an idea to get their opinion or approval.","example":"I need to run this new architecture design by the CTO before we start coding.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer running a new architecture design by the CTO before coding"}]},{"particle":"down","storageKeyPrefix":"runDown","meanings":[{"definition":"To lose power (a battery/machine) or energy (a person).","example":"The server''s backup battery finally ran down after three hours.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Server backup battery running down after three hours"},{"definition":"To criticize someone constantly.","example":"A toxic manager constantly runs down their employees in front of others.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Toxic manager constantly running down employees in front of others"},{"definition":"To find the source of something after a long search.","example":"The QA team finally ran down the cause of the memory leak in the Java application.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"QA team running down the cause of a memory leak in the Java application"}]},{"particle":"for","storageKeyPrefix":"runFor","meanings":[{"definition":"To try to be elected to an official or leadership position.","example":"She decided to run for the board of directors.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"She decided to run for the board of directors"}]},{"particle":"in","storageKeyPrefix":"runIn","meanings":[{"definition":"To use a new machine carefully until it is ready for normal use.","example":"We need to run in the new servers before putting them into full production.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running in new servers before putting them into full production"},{"definition":"To arrest someone (informal police term).","example":"The police ran him in for trespassing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police running someone in for trespassing"}]},{"particle":"into","storageKeyPrefix":"runInto","meanings":[{"definition":"To experience a problem or difficulty unexpectedly.","example":"We ran into an unexpected bug while compiling the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer running into an unexpected bug while compiling the code"},{"definition":"To meet someone unexpectedly.","example":"I ran into our former lead developer at a tech conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running into a former lead developer at a tech conference"}]},{"particle":"off","storageKeyPrefix":"runOff","meanings":[{"definition":"To quickly make copies of a document.","example":"Could you run off 20 copies of the meeting agenda?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running off 20 copies of the meeting agenda"},{"definition":"To force someone or something to leave.","example":"The aggressive takeover ran the original founders off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Aggressive takeover running the original founders off"}]},{"particle":"on","storageKeyPrefix":"runOn","meanings":[{"definition":"To be powered by something.","example":"The legacy enterprise system still runs on Java 8.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Legacy enterprise system still running on Java 8"},{"definition":"To continue for too long.","example":"The daily stand-up meeting ran on for an hour.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Daily stand-up meeting running on for an hour"}]},{"particle":"out","storageKeyPrefix":"runOut","meanings":[{"definition":"To use all of a supply so there is nothing left.","example":"We ran out of budget before finishing the software testing phase.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running out of budget before finishing the software testing phase"},{"definition":"To expire (for a contract, document, or agreement).","example":"Our cloud service contract runs out next month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cloud service contract running out next month"}]},{"particle":"over","storageKeyPrefix":"runOver","meanings":[{"definition":"To go beyond a time limit.","example":"The project review ran over its scheduled time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project review running over its scheduled time"},{"definition":"To quickly review or explain something.","example":"Let''s run over the main points of the business strategy one more time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running over the main points of the business strategy"},{"definition":"To hit with a vehicle.","example":"The delivery truck ran over a sign in the company parking lot.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Delivery truck running over a sign in the company parking lot"}]},{"particle":"through","storageKeyPrefix":"runThrough","meanings":[{"definition":"To practice, review, or explain something from beginning to end.","example":"The team ran through the deployment steps before the actual release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team running through the deployment steps before the actual release"},{"definition":"To spend money very quickly.","example":"The startup ran through its initial funding in just six months.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Startup running through its initial funding in just six months"}]},{"particle":"to","storageKeyPrefix":"runTo","meanings":[{"definition":"To reach a particular amount or cost.","example":"The costs for upgrading the IT infrastructure will run to $50,000.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Costs for upgrading IT infrastructure running to $50,000"},{"definition":"To ask someone for help, often too quickly.","example":"You cannot just run to the CEO every time there is a minor conflict in the team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running to the CEO every time there is a minor conflict in the team"}]},{"particle":"together","storageKeyPrefix":"runTogether","meanings":[{"definition":"To mix or blend so that things cannot be separated.","example":"When you work from home, your professional and personal lives can easily run together.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Professional and personal lives running together when working from home"}]},{"particle":"up","storageKeyPrefix":"runUp","meanings":[{"definition":"To create a large debt or cost.","example":"We ran up a huge AWS bill during the load testing phase.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Running up a huge AWS bill during the load testing phase"}]},{"particle":"with","storageKeyPrefix":"runWith","meanings":[{"definition":"To take an idea and develop it independently.","example":"The management team loved the proposal and told us to run with it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Management team telling the team to run with the proposal"}]},{"particle":"without","storageKeyPrefix":"runWithout","meanings":[{"definition":"To function lacking something.","example":"The microservice is designed to run without a continuous database connection.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Microservice designed to run without a continuous database connection"}]}]'::jsonb),
  ('set', 'Set', '["about","against","ahead","apart","back","by","down","in","off","on","out","over","to","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"setAbout","meanings":[{"definition":"To start doing something that needs a lot of time and energy.","example":"The team immediately set about rewriting the legacy Java code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team setting about rewriting the legacy Java code"}]},{"particle":"against","storageKeyPrefix":"setAgainst","meanings":[{"definition":"To make people or groups oppose or hate each other.","example":"Poor leadership set the development team against the testing team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Poor leadership setting the development team against the testing team"},{"definition":"To balance one thing against another (often used in finance).","example":"You can set the cost of the new servers against your tax bill.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting cost of new servers against tax bill"}]},{"particle":"ahead","storageKeyPrefix":"setAhead","meanings":[{"definition":"To change the time on a clock to a later time.","example":"Don''t forget to set your clocks ahead by one hour this weekend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting clocks ahead by one hour this weekend"}]},{"particle":"apart","storageKeyPrefix":"setApart","meanings":[{"definition":"To make someone or something different and better than others.","example":"Her excellent leadership skills set her apart from other managers.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Excellent leadership skills setting her apart from other managers"},{"definition":"To keep time or space for a special purpose.","example":"We set apart two hours on Friday afternoons for code reviews.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting apart two hours on Friday afternoons for code reviews"}]},{"particle":"back","storageKeyPrefix":"setBack","meanings":[{"definition":"To delay the progress of a project or plan.","example":"A critical bug in the database set the project back by three weeks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Critical bug in the database setting the project back by three weeks"},{"definition":"To cost someone a large amount of money (informal).","example":"Buying those enterprise software licenses will set us back a lot of money.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Buying enterprise software licenses setting us back a lot of money"}]},{"particle":"by","storageKeyPrefix":"setBy","meanings":[{"definition":"To save money or things for the future.","example":"The company has a budget set by for emergency server repairs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company budget set by for emergency server repairs"}]},{"particle":"down","storageKeyPrefix":"setDown","meanings":[{"definition":"To write something on paper so there is an official record.","example":"The new coding standards are set down in the employee handbook.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New coding standards set down in the employee handbook"},{"definition":"To state officially how something must be done (to make a rule).","example":"The CEO set down strict rules for working remotely.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO setting down strict rules for working remotely"},{"definition":"To stop a vehicle to let a passenger get out.","example":"The taxi driver set him down right in front of the office building.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Taxi driver setting him down in front of the office building"}]},{"particle":"in","storageKeyPrefix":"setIn","meanings":[{"definition":"To begin and seem likely to continue for a long time (usually used for negative situations, feelings, or bad weather).","example":"Panic set in when the main production server crashed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Panic setting in when the main production server crashed"}]},{"particle":"off","storageKeyPrefix":"setOff","meanings":[{"definition":"To start a journey.","example":"They set off for the tech conference in Berlin at 8:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting off for the tech conference in Berlin at 8:00 AM"},{"definition":"To cause an alarm to ring or a bomb to explode.","example":"The faulty sensor set off the fire alarm in the data center.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Faulty sensor setting off the fire alarm in the data center"},{"definition":"To cause a series of events to happen.","example":"The manager''s email set off a wave of complaints.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager''s email setting off a wave of complaints"},{"definition":"To make someone start laughing or crying.","example":"The presenter''s joke set the whole room off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Presenter''s joke setting the whole room off"}]},{"particle":"on","storageKeyPrefix":"setOn","meanings":[{"definition":"To attack someone, or to make an animal attack someone.","example":"The security guards set their dogs on the intruders.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Security guards setting their dogs on the intruders"},{"definition":"To be very determined to do something (used passively as \"be set on\").","example":"The lead architect is set on using microservices for this project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lead architect set on using microservices for this project"}]},{"particle":"out","storageKeyPrefix":"setOut","meanings":[{"definition":"To begin an activity with a specific goal in mind.","example":"We set out to build the fastest application on the market.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting out to build the fastest application on the market"},{"definition":"To explain ideas, facts, or plans clearly in writing or speaking.","example":"The project manager set out the timeline during the sprint planning meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Project manager setting out the timeline during sprint planning meeting"},{"definition":"To start a journey (similar to \"set off\").","example":"She set out for the client''s office early in the morning.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting out for the client''s office early in the morning"}]},{"particle":"over","storageKeyPrefix":"setOver","meanings":[{"definition":"To give someone authority or power over someone else.","example":"She was set over the entire IT department after the reorganization.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"She was set over the entire IT department after the reorganization"}]},{"particle":"to","storageKeyPrefix":"setTo","meanings":[{"definition":"To start working or doing something with a lot of energy and determination.","example":"The developers set to and fixed all the major bugs before the deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers setting to and fixing all the major bugs before the deadline"}]},{"particle":"up","storageKeyPrefix":"setUp","meanings":[{"definition":"To start a new business or organization.","example":"They set up a successful software company five years ago.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting up a successful software company five years ago"},{"definition":"To arrange or plan a meeting or event.","example":"I will set up a video call with the stakeholders for tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Setting up a video call with stakeholders for tomorrow"},{"definition":"To prepare equipment or software so it is ready to use.","example":"The IT support team is coming to set up your new Java development environment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT support team setting up new Java development environment"},{"definition":"To trick someone in order to make them look guilty of a crime or mistake.","example":"He didn''t leak the company data; he was set up by a rival.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"He was set up by a rival to look guilty"}]}]'::jsonb),
  ('settle', 'Settle', '["back","down","for","in","into","on","out","over","to","up","with"]'::jsonb, '[{"particle":"back","storageKeyPrefix":"settleBack","meanings":[{"definition":"To relax into a comfortable physical position, usually leaning backward.","example":"After a very successful product launch, the CEO settled back in his chair with a smile.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO settling back in his chair with a smile after a successful product launch"}]},{"particle":"down","storageKeyPrefix":"settleDown","meanings":[{"definition":"To become quiet and relaxed after being excited, nervous, or angry.","example":"The manager waited for the noisy room to settle down before starting her presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager waiting for the noisy room to settle down before starting her presentation"},{"definition":"To start living a quiet, stable life, often by staying in one place, buying a house, or starting a family.","example":"After years of moving between different tech startups, he decided to settle down in Warsaw and take a stable corporate job.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person deciding to settle down in Warsaw and take a stable corporate job after moving between tech startups"},{"definition":"To start paying serious attention to a task (\"settle down to\").","example":"We need to settle down to work if we want to finish this software update today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team settling down to work to finish a software update"}]},{"particle":"for","storageKeyPrefix":"settleFor","meanings":[{"definition":"To accept something that is available, even though it is not exactly what you wanted or hoped for.","example":"We wanted to hire a senior Java developer, but because of the budget, we had to settle for a mid-level programmer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team settling for a mid-level programmer because of budget constraints"}]},{"particle":"in","storageKeyPrefix":"settleIn","meanings":[{"definition":"To become comfortable, relaxed, and familiar in a new home, environment, or job.","example":"It takes about a month for a new employee to fully settle in and learn the company culture.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New employee settling in and learning the company culture"}]},{"particle":"into","storageKeyPrefix":"settleInto","meanings":[{"definition":"To get used to a new role, routine, or situation and become comfortable with it.","example":"She quickly settled into her new position as the lead project manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly settling into her new position as lead project manager"}]},{"particle":"on","storageKeyPrefix":"settleOn","meanings":[{"definition":"To make a final decision or choice after thinking about multiple options.","example":"After reviewing several different programming languages, the development team settled on Java for the new project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Development team settling on Java for the new project after reviewing programming languages"},{"definition":"To land or rest on a physical surface.","example":"The dust finally settled on the old office desks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dust settling on old office desks"}]},{"particle":"out","storageKeyPrefix":"settleOut","meanings":[{"definition":"To reach an agreement without going through a full court trial (often phrased as \"settle out of court\").","example":"The two companies decided to settle out of court to avoid a long and expensive legal battle.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two companies deciding to settle out of court to avoid a legal battle"},{"definition":"To sink to the bottom of a liquid.","example":"If you leave the coffee pot alone, the grounds will settle out at the bottom.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Coffee grounds settling out at the bottom of the coffee pot"}]},{"particle":"over","storageKeyPrefix":"settleOver","meanings":[{"definition":"To descend and cover something (often used to describe weather, a feeling, or a mood in a room).","example":"A deep silence settled over the boardroom when the team saw the terrible financial results.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Deep silence settling over the boardroom when the team saw the terrible financial results"}]},{"particle":"to","storageKeyPrefix":"settleTo","meanings":[{"definition":"To begin giving your full attention and effort to a task (very similar to \"settle down to\").","example":"Once everyone had their coffee, the team settled to the task of fixing the software bugs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team settling to the task of fixing software bugs after getting coffee"}]},{"particle":"up","storageKeyPrefix":"settleUp","meanings":[{"definition":"To pay money that you owe, usually to balance an account or share a bill.","example":"I will pay for the client\\''s lunch now, and we can settle up when we get back to the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person paying for client lunch and arranging to settle up later at the office"}]},{"particle":"with","storageKeyPrefix":"settleWith","meanings":[{"definition":"To reach a financial agreement or pay a debt to a person or organization.","example":"The company finally settled with its suppliers after a long dispute over the late invoices.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company settling with its suppliers after a long dispute over late invoices"},{"definition":"To punish someone who has done something bad to you in the past.","example":"I have an old argument to settle with a former competitor.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person having an old argument to settle with a former competitor"}]}]'::jsonb),
  ('show', 'Show', '["around / round / about","down","for","in / into","off","out","over","through","to","up"]'::jsonb, '[{"particle":"around / round / about","storageKeyPrefix":"showAround","meanings":[{"definition":"To act as a guide and give someone a tour of a new place.","example":"Welcome to the new headquarters! Let me show you around the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person showing a new colleague around the office headquarters"}]},{"particle":"down","storageKeyPrefix":"showDown","meanings":[{"definition":"In card games, to lay your cards face-up on the table to reveal your hand.","example":"After the final bet, it was time to show down their cards.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Players showing down their cards at the end of a poker game"}]},{"particle":"for","storageKeyPrefix":"showFor","meanings":[{"definition":"Used in the phrase \"have something to show for [an effort],\" meaning to have a result or evidence of your hard work.","example":"I worked all weekend on the project, but because of a server crash, I have nothing to show for it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer frustrated after a server crash left nothing to show for a weekend of work"}]},{"particle":"in / into","storageKeyPrefix":"showIn","meanings":[{"definition":"To act as a guide and lead someone inside a room or building (show in).","example":"When the candidates arrive, please show them in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Receptionist showing candidates into the office"},{"definition":"To lead someone into a specific room (show into).","example":"The receptionist showed the guests into the main conference room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Receptionist showing guests into the main conference room"}]},{"particle":"off","storageKeyPrefix":"showOff","meanings":[{"definition":"To behave in a way that is intended to attract attention or admiration (often seen as negative or boastful).","example":"He only bought that expensive sports car to show off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person showing off an expensive sports car to attract attention"},{"definition":"To proudly display something you have or have achieved.","example":"She wanted to show off her new Java application to the management team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer showing off a new Java application to the management team"},{"definition":"To make something look its best or highlight its good qualities.","example":"That tailored suit really shows off his professional style.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person in a tailored suit that shows off their professional style"}]},{"particle":"out","storageKeyPrefix":"showOut","meanings":[{"definition":"To lead or escort someone to the exit of a building or room.","example":"Thank you for the interview. My assistant will show you out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Assistant showing an interview candidate out of the office"}]},{"particle":"over","storageKeyPrefix":"showOver","meanings":[{"definition":"To guide someone around a building to inspect it (primarily British English, similar to \"show around\").","example":"The real estate agent showed us over the new office space.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Real estate agent showing clients over a new office space"}]},{"particle":"through","storageKeyPrefix":"showThrough","meanings":[{"definition":"To be visible under or through a layer of something else (like cloth or paper).","example":"You need to apply another coat of paint; the old dark color is showing through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old dark paint color showing through a new coat of paint on a wall"},{"definition":"To become obvious or visible, referring to an emotion or quality someone is trying to hide.","example":"She tried to stay calm, but her frustration showed through when the software crashed again.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer''s frustration showing through when the software crashed again"}]},{"particle":"to","storageKeyPrefix":"showTo","meanings":[{"definition":"To escort or lead someone to a specific location or seat.","example":"The host showed us to our table.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Restaurant host showing guests to their table"}]},{"particle":"up","storageKeyPrefix":"showUp","meanings":[{"definition":"To arrive or appear at a place, especially when expected or late.","example":"We waited for an hour, but the client never showed up for the meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team waiting for a client who never showed up for the meeting"},{"definition":"To be clearly visible.","example":"The coffee stain won\\''t show up on a dark carpet.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Coffee stain that does not show up on a dark carpet"},{"definition":"To reveal someone''s faults or make them feel embarrassed, usually by doing something better than them.","example":"The junior developer''s clean, efficient code showed up the senior developer''s messy work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Junior developer''s clean code showing up the senior developer''s messy work"},{"definition":"To test positive for something (e.g., in a medical or drug test).","example":"The virus did not show up in his blood test.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Medical professional reviewing blood test results where a virus did not show up"}]}]'::jsonb),
  ('shut', 'Shut', '["away","down","in","off","out","up"]'::jsonb, '[{"particle":"away","storageKeyPrefix":"shutAway","meanings":[{"definition":"To isolate someone or something in a place where they cannot be seen or disturbed.","example":"Before the exams, she shut herself away in the library for a week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student shutting herself away in the library before exams"}]},{"particle":"down","storageKeyPrefix":"shutDown","meanings":[{"definition":"To turn off a computer, machine, or system completely.","example":"Always remember to shut down your laptop before putting it in your bag.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shutting down laptop before putting it in bag"},{"definition":"To close a business or factory permanently or for a long time.","example":"During the economic crisis, many local shops had to shut down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Local shops shutting down during economic crisis"},{"definition":"To stop an opponent from playing well or succeeding (often used in sports or business).","example":"Our defense managed to shut down their best player.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Defense shutting down the best player on the opposing team"}]},{"particle":"in","storageKeyPrefix":"shutIn","meanings":[{"definition":"To prevent someone or an animal from leaving a room or building by closing the door.","example":"It''s raining heavily, so the cat has been shut in all day.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cat shut in the house all day due to heavy rain"},{"definition":"To accidentally catch a body part or clothing in a closing door.","example":"I accidentally shut my coat in the car door.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person accidentally shutting coat in car door"}]},{"particle":"off","storageKeyPrefix":"shutOff","meanings":[{"definition":"To stop the supply of something (like water, gas, or electricity).","example":"The plumber had to shut off the water before fixing the pipe.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Plumber shutting off water before fixing the pipe"},{"definition":"To turn off a machine or engine.","example":"Please shut off the engine when you park the car.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driver shutting off engine when parking the car"},{"definition":"To isolate or separate a place from other areas.","example":"The new wall shuts off the garden from the busy street.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New wall shutting off the garden from the busy street"}]},{"particle":"out","storageKeyPrefix":"shutOut","meanings":[{"definition":"To prevent something from entering a place (like light or noise).","example":"We use heavy curtains to shut out the street lights at night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Heavy curtains shutting out street lights at night"},{"definition":"To exclude someone from an activity, or from your thoughts and feelings.","example":"When he gets stressed, he stops talking and shuts everyone out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shutting everyone out when stressed"},{"definition":"To prevent an opposing team from scoring any points in a game (mainly used in sports).","example":"The goalkeeper played perfectly and shut out the other team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Goalkeeper shutting out the other team with a perfect performance"}]},{"particle":"up","storageKeyPrefix":"shutUp","meanings":[{"definition":"To stop talking or making a noise (informal, considered rude).","example":"I wish the dog next door would shut up; I''m trying to sleep.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person wishing the dog next door would shut up while trying to sleep"},{"definition":"To close and lock a building completely (often for the night or for a long time).","example":"The manager shuts up the shop at 8:00 PM every evening.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager shutting up the shop at 8:00 PM every evening"},{"definition":"To keep someone or an animal securely in a room or place.","example":"I was shut up in the meeting room for three hours today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person shut up in the meeting room for three hours"}]}]'::jsonb),
  ('sit', 'Sit', '["about / around / round","back","by","down","for","in","on","out","over","through","up","with"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"sitAbout","meanings":[{"definition":"To spend time doing nothing productive or useful.","example":"Instead of looking for a new job, he just sits around the house all day.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting around the house instead of looking for a new job"}]},{"particle":"back","storageKeyPrefix":"sitBack","meanings":[{"definition":"To relax in a chair.","example":"Now that the software release is finished, we can sit back and relax.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team sitting back and relaxing after finishing a software release"},{"definition":"To intentionally take no action when you should probably do something.","example":"A good manager doesn''t just sit back while the team struggles with a project.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager not sitting back while the team struggles with a project"}]},{"particle":"by","storageKeyPrefix":"sitBy","meanings":[{"definition":"To fail to take action to stop something bad from happening.","example":"I cannot sit by and let them make this terrible business decision.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person refusing to sit by and let a terrible business decision be made"}]},{"particle":"down","storageKeyPrefix":"sitDown","meanings":[{"definition":"To take a seat (literal).","example":"Please sit down, the meeting will begin shortly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting down as the meeting is about to begin"},{"definition":"To have a serious conversation or a formal meeting with someone (sit down with).","example":"We need to sit down with the client and discuss the new Java requirements.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team sitting down with the client to discuss Java requirements"}]},{"particle":"for","storageKeyPrefix":"sitFor","meanings":[{"definition":"To take an official exam.","example":"She is going to sit for her project management certification next month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting for a project management certification exam"},{"definition":"To pose for an artist or photographer.","example":"The CEO sat for a professional portrait for the company website.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO sitting for a professional portrait for the company website"},{"definition":"To take care of children while their parents are out (babysit).","example":"My sister is sitting for my children tonight.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sister sitting for children tonight while parents are out"}]},{"particle":"in","storageKeyPrefix":"sitIn","meanings":[{"definition":"To attend a meeting or class as an observer, rather than an active participant (sit in on).","example":"As a junior developer, can I sit in on the architecture meeting to learn how it works?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Junior developer sitting in on an architecture meeting to learn"},{"definition":"To temporarily replace someone and do their job (sit in for).","example":"I will sit in for the team leader while she is on holiday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting in for the team leader while she is on holiday"},{"definition":"To occupy a building as a form of protest.","example":"The workers decided to sit in at the factory until their demands were met.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Workers sitting in at the factory until their demands were met"}]},{"particle":"on","storageKeyPrefix":"sitOn","meanings":[{"definition":"To be an official member of a board or committee.","example":"He sits on the board of directors for three different tech companies.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting on the board of directors for three tech companies"},{"definition":"To delay making a decision or taking action on something.","example":"The HR department has been sitting on my promotion request for weeks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"HR department sitting on a promotion request for weeks"}]},{"particle":"out","storageKeyPrefix":"sitOut","meanings":[{"definition":"To choose not to participate in an activity.","example":"I don''t know much about this part of the project, so I will sit this discussion out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting out a project discussion they know little about"},{"definition":"To wait patiently until a difficult or unpleasant situation finishes.","example":"We just have to sit out the economic crisis and hope the market improves soon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People sitting out the economic crisis and hoping the market improves"}]},{"particle":"over","storageKeyPrefix":"sitOver","meanings":[{"definition":"To spend a long time doing something, usually eating or drinking, while having a conversation.","example":"We sat over coffee for hours discussing the new business strategy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People sitting over coffee for hours discussing a business strategy"}]},{"particle":"through","storageKeyPrefix":"sitThrough","meanings":[{"definition":"To stay until the end of an event that is long, boring, or difficult.","example":"I had to sit through a three-hour presentation on software compliance.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting through a three-hour software compliance presentation"}]},{"particle":"up","storageKeyPrefix":"sitUp","meanings":[{"definition":"To move from a lying down position to a sitting position, or to sit straight.","example":"You should sit up straight during your job interview.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting up straight during a job interview"},{"definition":"To stay awake late into the night.","example":"The developers sat up until 2 AM fixing bugs in the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers sitting up until 2 AM fixing bugs in the code"},{"definition":"To suddenly pay attention to something because it is surprising or important (sit up and take notice).","example":"When sales dropped by 20%, the leadership team finally sat up and took notice.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leadership team sitting up and taking notice after sales dropped by 20%"}]},{"particle":"with","storageKeyPrefix":"sitWith","meanings":[{"definition":"To be acceptable to someone, or to cause a certain feeling.","example":"The new remote work policy does not sit well with the development team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New remote work policy not sitting well with the development team"},{"definition":"To spend time with someone who is upset or sick to give them support.","example":"I sat with him after he heard that his project was canceled.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sitting with a colleague after his project was canceled"}]}]'::jsonb),
  ('stand', 'Stand', '["about / around","against","apart","away","back","behind","by","down","for","in","into","off","on","out","over","to","together","up","with"]'::jsonb, '[{"particle":"about / around","storageKeyPrefix":"standAbout","meanings":[{"definition":"To spend time in a place doing nothing or waiting.","example":"We were just standing around waiting for the meeting to start.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People standing around waiting for the meeting to start"}]},{"particle":"against","storageKeyPrefix":"standAgainst","meanings":[{"definition":"To oppose or fight against someone or something.","example":"The team leader stood against the new policy because it was bad for productivity.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team leader standing against a new policy that was bad for productivity"}]},{"particle":"apart","storageKeyPrefix":"standApart","meanings":[{"definition":"To be separate or isolated from others.","example":"The two servers stand apart in the data center for security reasons.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two servers standing apart in a data center for security reasons"},{"definition":"To be noticeably different or better than others.","example":"Her excellent management skills make her stand apart from the other candidates.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person standing apart from other candidates due to excellent management skills"}]},{"particle":"away","storageKeyPrefix":"standAway","meanings":[{"definition":"To move backwards or keep a distance from something (mostly literal).","example":"Please stand away from the servers while they are restarting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person standing away from servers while they are restarting"}]},{"particle":"back","storageKeyPrefix":"standBack","meanings":[{"definition":"To move a short distance away or backwards.","example":"The firefighters told everyone to stand back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Firefighters telling everyone to stand back"},{"definition":"To view a situation objectively, from a wider perspective.","example":"Sometimes a manager needs to stand back and look at the whole project before making a decision.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager standing back to look at the whole project before making a decision"}]},{"particle":"behind","storageKeyPrefix":"standBehind","meanings":[{"definition":"To support someone or guarantee the quality of something.","example":"We stand behind the quality of our Java software products.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team standing behind the quality of their Java software products"}]},{"particle":"by","storageKeyPrefix":"standBy","meanings":[{"definition":"To be ready for action.","example":"The IT support team is standing by to fix the network issue.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"IT support team standing by to fix a network issue"},{"definition":"To remain loyal to someone in a difficult situation.","example":"A good leader stands by their team during a crisis.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A good leader standing by their team during a crisis"},{"definition":"To adhere to a promise, decision, or belief.","example":"I stand by my decision to hire him for the development team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person standing by their decision to hire someone for the development team"},{"definition":"To watch something bad happen without trying to help.","example":"I cannot simply stand by while the project fails.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person refusing to stand by while the project fails"}]},{"particle":"down","storageKeyPrefix":"standDown","meanings":[{"definition":"To resign or leave a position of leadership.","example":"The CEO agreed to stand down after ten years in charge.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO standing down after ten years in charge"},{"definition":"To relax from a state of military or security readiness.","example":"The security team was told to stand down after the false alarm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Security team standing down after a false alarm"}]},{"particle":"for","storageKeyPrefix":"standFor","meanings":[{"definition":"To represent a word or idea (for abbreviations).","example":"In software development, API stands for Application Programming Interface.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"API standing for Application Programming Interface in software development"},{"definition":"To tolerate or accept (usually used in the negative).","example":"The boss will not stand for poor communication.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Boss not standing for poor communication"},{"definition":"To support a cause or principle.","example":"Our company stands for equality and respect.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company standing for equality and respect"}]},{"particle":"in","storageKeyPrefix":"standIn","meanings":[{"definition":"To temporarily replace or substitute for someone who is absent (often \"stand in for\").","example":"I will stand in for the manager while she is on a business trip.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person standing in for the manager while she is on a business trip"}]},{"particle":"into","storageKeyPrefix":"standInto","meanings":[{"definition":"To sail or move toward danger (rare, old nautical term).","example":"The ship was standing into the storm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Ship standing into a storm"}]},{"particle":"off","storageKeyPrefix":"standOff","meanings":[{"definition":"To keep at a distance, or to keep someone away.","example":"The police managed to stand off the angry crowd.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Police managing to stand off an angry crowd"}]},{"particle":"on","storageKeyPrefix":"standOn","meanings":[{"definition":"To insist on strict rules or formalities.","example":"We don''t need to stand on ceremony; just call me by my first name.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person saying we do not need to stand on ceremony"},{"definition":"To rely on or be based on.","example":"My argument stands on solid financial data.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Argument standing on solid financial data"}]},{"particle":"out","storageKeyPrefix":"standOut","meanings":[{"definition":"To be very easy to see or notice.","example":"The red button stands out against the dark background of the app.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Red button standing out against the dark background of the app"},{"definition":"To be much better than others.","example":"As a Java developer, his coding skills really stand out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Java developer whose coding skills really stand out"},{"definition":"To stubbornly resist or hold out for a better offer.","example":"The union is standing out for a higher salary.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Union standing out for a higher salary"}]},{"particle":"over","storageKeyPrefix":"standOver","meanings":[{"definition":"To watch someone closely, often in an intimidating or annoying way.","example":"I can''t write code well if the boss is standing over me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Boss standing over a developer who cannot write code well"},{"definition":"To be postponed or delayed to a later time.","example":"This agenda item can stand over until our next meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Agenda item standing over until the next meeting"}]},{"particle":"to","storageKeyPrefix":"standTo","meanings":[{"definition":"To take up defensive positions (military).","example":"The soldiers were ordered to stand to.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldiers ordered to stand to at their defensive positions"},{"definition":"To be in a position where you are likely to gain or lose something.","example":"The company stands to gain a lot of money from this new software contract.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company standing to gain a lot of money from a new software contract"}]},{"particle":"together","storageKeyPrefix":"standTogether","meanings":[{"definition":"To remain united and support each other.","example":"The team must stand together during this difficult transition period.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team standing together during a difficult transition period"}]},{"particle":"up","storageKeyPrefix":"standUp","meanings":[{"definition":"To rise to your feet.","example":"Please stand up when the clients enter the room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person standing up when clients enter the room"},{"definition":"To remain valid, true, or strong when tested.","example":"This new software architecture will stand up to heavy user traffic.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"New software architecture standing up to heavy user traffic"},{"definition":"To fail to keep an appointment or date with someone.","example":"The contractor stood me up for our 10:00 AM meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Contractor standing someone up for a 10 AM meeting"}]},{"particle":"with","storageKeyPrefix":"standWith","meanings":[{"definition":"To express solidarity or support for someone.","example":"We stand with our colleagues in the overseas office during their difficult time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team standing with overseas colleagues during a difficult time"}]}]'::jsonb),
  ('stick', 'Stick', '["about / around","away","by","down","for","in","out","to","together","up","with"]'::jsonb, '[{"particle":"about / around","storageKeyPrefix":"stickAbout","meanings":[{"definition":"To stay in a place for a little while, often waiting for something to happen.","example":"Stick around after the sprint review; we need to discuss the Java 21 migration.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sticking around after sprint review to discuss Java 21 migration"}]},{"particle":"away","storageKeyPrefix":"stickAway","meanings":[{"definition":"To store or put something in a safe or hidden place.","example":"I stuck the old project contracts away in the archive cabinet.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sticking old project contracts away in an archive cabinet"}]},{"particle":"by","storageKeyPrefix":"stickBy","meanings":[{"definition":"To remain loyal to someone during difficult times.","example":"The founders stuck by each other when the company almost went bankrupt.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Founders sticking by each other when the company almost went bankrupt"},{"definition":"To keep a promise or remain committed to a decision.","example":"Management decided to stick by their decision to invest heavily in cloud infrastructure.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Management sticking by their decision to invest heavily in cloud infrastructure"}]},{"particle":"down","storageKeyPrefix":"stickDown","meanings":[{"definition":"To attach something to a surface using glue or tape.","example":"Stick down the network cables so nobody trips in the server room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sticking down network cables in the server room"},{"definition":"To write something quickly (informal).","example":"Let me stick down these API endpoints before I forget them.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer sticking down API endpoints before forgetting them"}]},{"particle":"for","storageKeyPrefix":"stickFor","meanings":[{"definition":"To lack something necessary (used in the passive form \"be stuck for\").","example":"We are stuck for ideas on how to improve the application''s performance.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team stuck for ideas on how to improve application performance"}]},{"particle":"in","storageKeyPrefix":"stickIn","meanings":[{"definition":"To remain strongly in someone\\''s memory (often used as \"stick in your mind\").","example":"The CEO''s speech on agile leadership really stuck in my mind.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO speech on agile leadership sticking in someone''s mind"}]},{"particle":"out","storageKeyPrefix":"stickOut","meanings":[{"definition":"To be very easy to see or notice because of being different.","example":"The memory leak in the backend logic really sticks out when you look at the server logs.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Memory leak sticking out in server logs"},{"definition":"To continue to the end of a difficult situation (used as \"stick it out\").","example":"The first year of running a business is hard, but you have to stick it out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sticking it out through the first year of running a business"}]},{"particle":"to","storageKeyPrefix":"stickTo","meanings":[{"definition":"To continue doing or following a specific plan, rule, or subject without changing.","example":"Let''s stick to the meeting agenda so we finish on time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team sticking to meeting agenda to finish on time"},{"definition":"To keep a promise or agreement.","example":"The vendor stuck to the original budget despite the extra development work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Vendor sticking to original budget despite extra development work"}]},{"particle":"together","storageKeyPrefix":"stickTogether","meanings":[{"definition":"To support each other as a group, especially in hard times.","example":"A successful development team sticks together during a stressful product release.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Development team sticking together during a stressful product release"}]},{"particle":"up","storageKeyPrefix":"stickUp","meanings":[{"definition":"To point upwards or stand above a surface.","example":"The cooling fan on the new server model sticks up higher than the old one.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cooling fan on new server model sticking up higher than the old one"},{"definition":"To defend or support someone or an idea (used as \"stick up for\").","example":"A good manager will always stick up for their team when other departments criticize them.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager sticking up for their team when other departments criticize them"}]},{"particle":"with","storageKeyPrefix":"stickWith","meanings":[{"definition":"To continue using or doing something, rather than changing it.","example":"We decided to stick with the Spring Boot framework instead of learning a new ecosystem.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team sticking with the Spring Boot framework instead of learning a new ecosystem"},{"definition":"To stay close to someone for guidance or safety.","example":"Stick with the senior architect today, and she will show you how the deployment pipeline works.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer sticking with senior architect to learn deployment pipeline"}]}]'::jsonb),
  ('take', 'Take', '["off","on","up","down","in","into","out","away","cross / across","forward","back","for","by","together","with","without","apart","over","ahead","after","behind","through","about","around / round","to","against"]'::jsonb, '[{"particle":"off","storageKeyPrefix":"takeOff","meanings":[{"definition":"To remove clothing or accessories","example":"Please take off your shoes inside the house.","imageSrc":"images/phrasal_verbs/list/take/off/clothing.png","imageAlt":"A person removing their shoes at the door"},{"definition":"To leave the ground and begin flying","example":"The flight will take off in ten minutes.","imageSrc":"images/phrasal_verbs/list/take/off/planes.png","imageAlt":"An aeroplane taking off from a runway"},{"definition":"To become very successful very quickly (business or ideas)","example":"Her new software company really took off this year.","imageSrc":"images/phrasal_verbs/list/take/off/business.png","imageAlt":"A fast-growing software company"},{"definition":"To leave quickly or without warning (informal)","example":"He took off before the meeting ended.","imageSrc":"images/phrasal_verbs/list/take/off/leave_suddenly.png","imageAlt":"A person leaving a meeting early without warning"},{"definition":"To have time away from work","example":"I need to take a few days off to rest.","imageSrc":"images/phrasal_verbs/list/take/off/days_off.png","imageAlt":"A person resting at home on days off work"}]},{"particle":"on","storageKeyPrefix":"takeOn","meanings":[{"definition":"To accept or take responsibility for work or a task","example":"I cannot take on any new projects right now.","imageSrc":"images/phrasal_verbs/list/take/on/accept_work.png","imageAlt":"A person declining extra project responsibilities"},{"definition":"To employ or hire someone","example":"The company is taking on fifty new developers.","imageSrc":"images/phrasal_verbs/list/take/on/hire_someone.png","imageAlt":"A company hiring new developers"},{"definition":"To compete or fight against someone","example":"Our team will take on the market leader next year.","imageSrc":"images/phrasal_verbs/list/take/on/compete_against.png","imageAlt":"Two teams competing in a business challenge"}]},{"particle":"up","storageKeyPrefix":"takeUp","meanings":[{"definition":"To start a new activity or hobby","example":"He took up golf to relax after work.","imageSrc":"images/phrasal_verbs/list/take/up/start_hobby.png","imageAlt":"A person starting to play golf"},{"definition":"To use or fill an amount of time or space","example":"These large files take up too much space on the server.","imageSrc":"images/phrasal_verbs/list/take/up/occupy_space.png","imageAlt":"Large files filling up server storage space"},{"definition":"To accept an offer that has been made (often ''take someone up on'')","example":"I will take you up on that job offer.","imageSrc":"images/phrasal_verbs/list/take/up/accept_offer.png","imageAlt":"A person accepting a job offer"},{"definition":"To shorten a piece of clothing","example":"I need to take up these trousers; they are too long.","imageSrc":"images/phrasal_verbs/list/take/up/shorten_clothes.png","imageAlt":"A tailor shortening a pair of trousers"}]},{"particle":"down","storageKeyPrefix":"takeDown","meanings":[{"definition":"To write down information","example":"Please take down the main points of the presentation.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person writing notes during a presentation"},{"definition":"To remove from a high place or to dismantle something","example":"We need to take down the old website.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A developer removing an old website"},{"definition":"To defeat or humiliate someone","example":"The journalist''s report took down the corrupt manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A journalist exposing a corrupt manager"}]},{"particle":"in","storageKeyPrefix":"takeIn","meanings":[{"definition":"To absorb and understand information","example":"The technical manual was very hard to take in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person struggling to understand a complex manual"},{"definition":"To allow someone or something to stay in your home","example":"She took in a dog from the street.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person taking in a stray dog from the street"},{"definition":"To deceive or trick someone (often passive)","example":"Many people were taken in by the email scam.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People being deceived by an email scam"},{"definition":"To make a piece of clothing narrower or smaller","example":"I lost weight, so I had to take in my suits.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A tailor making a suit smaller"}]},{"particle":"into","storageKeyPrefix":"takeInto","meanings":[{"definition":"To consider something when making a decision (mainly ''take into account / consideration'')","example":"We must take the budget into account before making a decision.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team considering the budget before making a decision"}]},{"particle":"out","storageKeyPrefix":"takeOut","meanings":[{"definition":"To remove something from a place or container","example":"Please take the trash out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person taking out the rubbish"},{"definition":"To invite someone to go somewhere and pay for them","example":"I would like to take you out for dinner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people having dinner at a restaurant"},{"definition":"To obtain an official service such as a loan or insurance","example":"The business took out a large bank loan.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A business manager signing a bank loan agreement"},{"definition":"To destroy or eliminate something (informal)","example":"The virus took out the entire IT system.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A computer virus destroying an IT system"},{"definition":"To direct negative feelings at someone who is not responsible (phrase ''take it out on'')","example":"I know you are stressed, but do not take it out on your team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A stressed manager unfairly venting on team members"}]},{"particle":"away","storageKeyPrefix":"takeAway","meanings":[{"definition":"To remove or subtract something","example":"If you take away the marketing costs, the profit is high.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person subtracting costs from a profit calculation"},{"definition":"To confiscate something without permission","example":"The teacher took away his mobile phone.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A teacher confiscating a student\\''s mobile phone"},{"definition":"To buy food from a restaurant to eat elsewhere","example":"We bought a pizza to take away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person buying a takeaway pizza"},{"definition":"To learn or receive a main lesson or message (noun: a takeaway)","example":"What did you take away from that leadership seminar?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person reflecting on the key lessons from a seminar"}]},{"particle":"cross / across","storageKeyPrefix":"takeCrossAcross","meanings":[{"definition":"Literal use: to physically guide or lead someone across a space (no common figurative meaning)","example":"She took the blind man across the street.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person helping a blind man cross the street"}]},{"particle":"forward","storageKeyPrefix":"takeForward","meanings":[{"definition":"To develop, promote, or make progress with a plan or idea","example":"We need a new manager to take this project forward.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A manager moving a project forward"}]},{"particle":"back","storageKeyPrefix":"takeBack","meanings":[{"definition":"To return something to the place where it was bought","example":"The laptop was broken, so I took it back to the store.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person returning a broken laptop to a store"},{"definition":"To admit that something you said was wrong","example":"I take back what I said; you were right.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person admitting they were wrong in a conversation"},{"definition":"To remind someone of an earlier time in their life","example":"Hearing that old song takes me back to my university days.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person feeling nostalgic after hearing an old song"},{"definition":"To accept someone back into a relationship or job","example":"The company took him back after he finished his studies.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A company welcoming an employee back after their studies"}]},{"particle":"for","storageKeyPrefix":"takeFor","meanings":[{"definition":"To mistake someone''s identity or character","example":"Do you take me for a fool?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person challenging someone who has misjudged them"},{"definition":"To fail to appreciate something or someone (phrase ''take for granted'')","example":"A good leader never takes their employees for granted.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A leader showing appreciation for their team"}]},{"particle":"by","storageKeyPrefix":"takeBy","meanings":[{"definition":"To happen unexpectedly (phrase ''take by surprise'')","example":"The sudden market crash took us by surprise.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business people shocked by a sudden market crash"},{"definition":"To rapidly become very popular or widely admired (phrase ''take by storm'')","example":"The new app took the world by storm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A new app becoming wildly popular worldwide"}]},{"particle":"together","storageKeyPrefix":"takeTogether","meanings":[{"definition":"To consider a group of things or facts as a whole","example":"Taken together, these three software modules form a powerful system.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Three software modules considered as one system"}]},{"particle":"with","storageKeyPrefix":"takeWith","meanings":[{"definition":"To be attracted to or impressed by someone or something (usually passive)","example":"I was very taken with his presentation on Agile management.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person impressed by a presentation on Agile management"}]},{"particle":"without","storageKeyPrefix":"takeWithout","meanings":[{"definition":"Literal use: to take an item without something else (no common figurative meaning)","example":"I will take the coffee without sugar.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person ordering coffee without sugar"}]},{"particle":"apart","storageKeyPrefix":"takeApart","meanings":[{"definition":"To separate something into its component pieces","example":"The engineer took the machine apart to fix it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"An engineer dismantling a machine for repairs"},{"definition":"To criticize someone or something very heavily, or to defeat easily","example":"The director took my business plan apart.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A director heavily criticising a business plan"}]},{"particle":"over","storageKeyPrefix":"takeOver","meanings":[{"definition":"To gain control of a company, organization, or situation","example":"A larger corporation wants to take over our business.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A large corporation taking over a smaller business"},{"definition":"To replace someone in doing a task or job","example":"I am tired. Can you take over driving?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A passenger taking over the driving from a tired driver"}]},{"particle":"ahead","storageKeyPrefix":"takeAhead","meanings":[{"definition":"Literal use: to carry or move something to the front (no standard figurative meaning)","example":"Could you take this report ahead and put it on the meeting table?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person carrying a report to the front of a meeting room"}]},{"particle":"after","storageKeyPrefix":"takeAfter","meanings":[{"definition":"To look or behave like an older family member","example":"She takes after her father; they both love mathematics.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A daughter who resembles her father in personality"}]},{"particle":"behind","storageKeyPrefix":"takeBehind","meanings":[{"definition":"Literal use: to physically move someone or something to the back (no standard figurative meaning)","example":"Take the new equipment behind the stage before the show starts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Stage crew moving equipment behind the stage"}]},{"particle":"through","storageKeyPrefix":"takeThrough","meanings":[{"definition":"To explain or describe a process step by step","example":"Let me take you through the new software setup.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A trainer explaining a software setup step by step"}]},{"particle":"about","storageKeyPrefix":"takeAbout","meanings":[{"definition":"Literal use: to express an approximate amount of time, distance, or effort (no standard phrasal verb)","example":"It will take about two hours to finish the report.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person estimating how long a task will take"}]},{"particle":"around / round","storageKeyPrefix":"takeAroundRound","meanings":[{"definition":"To show someone around a place (also: take round)","example":"Welcome to the headquarters. I will take you around.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person giving a tour of company headquarters"}]},{"particle":"to","storageKeyPrefix":"takeTo","meanings":[{"definition":"To start liking someone or something quickly and naturally","example":"The team took to the new manager immediately.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A team warming to a new manager straight away"},{"definition":"To start a new habit, often as a response to stress or difficulty","example":"Because of stress, he took to drinking coffee late at night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person developing a late-night coffee habit due to stress"}]},{"particle":"against","storageKeyPrefix":"takeAgainst","meanings":[{"definition":"To start to dislike someone for no clear or obvious reason","example":"I do not know why, but she took against me from my first day in the office.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A person who dislikes a colleague for no clear reason"}]}]'::jsonb),
  ('talk', 'Talk', '["about","across","against","around / round","away","back","down","for","into","on","out","over","through","to","together","up","with"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"talkAbout","meanings":[{"definition":"To discuss a specific topic, person, or idea.","example":"We need to talk about the new software update.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team talking about the new software update"}]},{"particle":"across","storageKeyPrefix":"talkAcross","meanings":[{"definition":"To speak at the same time as someone else, often in a confusing way where people are not listening to each other.","example":"The meeting was a mess because everyone was talking across each other.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People talking across each other in a chaotic meeting"}]},{"particle":"against","storageKeyPrefix":"talkAgainst","meanings":[{"definition":"To speak in opposition to an idea, plan, or person.","example":"Several managers talked against the proposed budget cuts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Managers talking against the proposed budget cuts"}]},{"particle":"around / round","storageKeyPrefix":"talkAround","meanings":[{"definition":"To avoid speaking directly about the main issue.","example":"Stop talking around the problem and tell me what is wrong.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person talking around the problem instead of addressing it directly"},{"definition":"To persuade someone to agree with you or change their mind.","example":"He didn''t want to join the project, but I finally talked him round.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person talking someone round to join the project"}]},{"particle":"away","storageKeyPrefix":"talkAway","meanings":[{"definition":"To continue talking for a long time, often in a relaxed manner.","example":"We sat in the cafe, talking away for hours.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people talking away in a cafe for hours"}]},{"particle":"back","storageKeyPrefix":"talkBack","meanings":[{"definition":"To reply rudely to someone in a position of authority (like a parent, teacher, or boss).","example":"The student was sent to the principal for talking back to his teacher.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student talking back to a teacher and being sent to the principal"}]},{"particle":"down","storageKeyPrefix":"talkDown","meanings":[{"definition":"To speak to someone as if they are less intelligent or less important than you (talk down to).","example":"A good leader never talks down to their team members.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leader avoiding talking down to team members"},{"definition":"To negotiate a lower price for something.","example":"The car was $5,000, but I talked the seller down to $4,500.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person talking the seller down on a car price"},{"definition":"To guide an aircraft to a safe landing using radio instructions.","example":"The air traffic controller talked the pilot down safely.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Air traffic controller talking the pilot down to a safe landing"}]},{"particle":"for","storageKeyPrefix":"talkFor","meanings":[{"definition":"To speak on behalf of someone else or a group.","example":"I can only talk for myself, not the whole department.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person talking for themselves, not the whole department"}]},{"particle":"into","storageKeyPrefix":"talkInto","meanings":[{"definition":"To persuade someone to do something they initially did not want to do.","example":"She talked me into taking the management course.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being talked into taking a management course"}]},{"particle":"on","storageKeyPrefix":"talkOn","meanings":[{"definition":"To continue talking, often for a long time or in a boring way.","example":"He talked on and on about his holiday.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person talking on and on about their holiday"}]},{"particle":"out","storageKeyPrefix":"talkOut","meanings":[{"definition":"To discuss a problem thoroughly until it is completely resolved.","example":"We had a disagreement, but we sat down and talked it out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people sitting down and talking out a disagreement"},{"definition":"To persuade someone not to do something (talk out of).","example":"I talked him out of quitting his job.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being talked out of quitting their job"}]},{"particle":"over","storageKeyPrefix":"talkOver","meanings":[{"definition":"To discuss a plan or problem carefully before making a decision.","example":"Let''s talk over the contract before we sign it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team talking over the contract before signing"},{"definition":"To speak louder than someone else to interrupt them.","example":"Please don\\''t talk over me while I am presenting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being talked over during a presentation"}]},{"particle":"through","storageKeyPrefix":"talkThrough","meanings":[{"definition":"To explain a process or idea to someone step by step.","example":"Can you talk me through how to use this Java framework?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer being talked through how to use a Java framework"},{"definition":"To discuss a problem in detail to find a solution.","example":"We need to talk through these errors in the code.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team talking through errors in the code to find a solution"}]},{"particle":"to","storageKeyPrefix":"talkTo","meanings":[{"definition":"To have a conversation with someone.","example":"I need to talk to the client tomorrow.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person needing to talk to a client tomorrow"},{"definition":"To reprimand or scold someone for doing something wrong.","example":"The manager had to talk to him about arriving late.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager talking to an employee about arriving late"}]},{"particle":"together","storageKeyPrefix":"talkTogether","meanings":[{"definition":"To converse with one another (literal meaning).","example":"The two developers talked together quietly in the corner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two developers talking together quietly in the corner"}]},{"particle":"up","storageKeyPrefix":"talkUp","meanings":[{"definition":"To praise or promote something to make it sound very good or exciting.","example":"They are really talking up the new product launch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team talking up the new product launch"}]},{"particle":"with","storageKeyPrefix":"talkWith","meanings":[{"definition":"To have a discussion with someone, often implying a more equal, two-way conversation.","example":"I enjoyed talking with you at the conference.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two people enjoying talking with each other at a conference"}]}]'::jsonb),
  ('think', 'Think', '["about","ahead","around / round","back","for","on","out","over","through","to","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"thinkAbout","meanings":[{"definition":"To consider a person, thing, or idea — to spend time examining an idea or focusing your mind on someone or something.","example":"Give me a few days to think about your proposal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person taking time to think about a proposal"},{"definition":"To hold a specific view or belief regarding a topic.","example":"What do you think about the new company policy?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person sharing their view about the new company policy"},{"definition":"To recall a memory or picture something in your mind.","example":"It makes me sad to think about how much time we wasted.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person feeling sad while thinking about wasted time"}]},{"particle":"ahead","storageKeyPrefix":"thinkAhead","meanings":[{"definition":"To consider what might happen in the future so that you are prepared.","example":"Good managers always think ahead to avoid potential problems.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager thinking ahead to avoid potential problems"}]},{"particle":"around / round","storageKeyPrefix":"thinkAround","meanings":[{"definition":"To consider a situation or problem from every possible perspective in order to find a solution.","example":"The team needs to think around this issue to find a creative fix.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team thinking around an issue to find a creative solution"}]},{"particle":"back","storageKeyPrefix":"thinkBack","meanings":[{"definition":"To focus your mind on events that have already happened.","example":"When I think back to my first job, I realize how much I have learned.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person thinking back to their first job and reflecting on growth"}]},{"particle":"for","storageKeyPrefix":"thinkFor","meanings":[{"definition":"To form your own opinions and make your own choices, rather than letting others decide for you (think for yourself).","example":"A good leader encourages their team to think for themselves.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Leader encouraging team to think for themselves"}]},{"particle":"on","storageKeyPrefix":"thinkOn","meanings":[{"definition":"To spend time considering something — similar to \"think about,\" meaning to reflect on a decision or idea.","example":"It is a strong offer, but I need to think on it for a few days.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person thinking on a strong job offer for a few days"},{"definition":"To keep in mind or remember (mainly British/informal).","example":"You should think on what I told you before you make a mistake.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being reminded to think on advice before making a mistake"}]},{"particle":"out","storageKeyPrefix":"thinkOut","meanings":[{"definition":"To plan something completely and carefully from start to finish.","example":"We need to think out our strategy before the client meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team thinking out their strategy before a client meeting"}]},{"particle":"over","storageKeyPrefix":"thinkOver","meanings":[{"definition":"To take time to reflect on a suggestion, offer, or problem before making a final decision.","example":"Take the weekend to think over the job offer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person taking time to think over a job offer"}]},{"particle":"through","storageKeyPrefix":"thinkThrough","meanings":[{"definition":"To carefully consider every step, detail, and possible result of a plan or action before doing it.","example":"You should think through the consequences before you quit your job.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person thinking through the consequences before quitting their job"}]},{"particle":"to","storageKeyPrefix":"thinkTo","meanings":[{"definition":"To remember to do something (usually used in the negative).","example":"I was so busy that I didn''t think to call my clients to update them.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Busy person who didn''t think to call clients"},{"definition":"To expect or imagine that a specific situation is possible.","example":"Who would have thought to see you here today?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Surprised person at an unexpected meeting"}]},{"particle":"up","storageKeyPrefix":"thinkUp","meanings":[{"definition":"To use your imagination to create a plan, an idea, or an excuse.","example":"The developers thought up a brilliant solution to the software bug.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developers thinking up a brilliant solution to a software bug"}]}]'::jsonb),
  ('throw', 'Throw', '["about / around / round","away","back","down","in","into","off","on","out","over","together","up"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"throwAbout","meanings":[{"definition":"To scatter things untidily.","example":"Clothes and books were thrown about the messy room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Clothes and books scattered untidily around a room"},{"definition":"To discuss ideas or suggestions casually.","example":"We spent the afternoon throwing around some concepts for the new ad campaign.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team casually discussing concepts for an ad campaign"},{"definition":"To use power, money, or authority aggressively or recklessly (often \"throw one\\''s weight around\").","example":"As soon as he got promoted, he started throwing his weight around and demanding respect.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Newly promoted person throwing their weight around and demanding respect"}]},{"particle":"away","storageKeyPrefix":"throwAway","meanings":[{"definition":"To discard as trash.","example":"Don''t throw away that receipt; you might need it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person keeping a receipt instead of throwing it away"},{"definition":"To waste or fail to make use of an opportunity or advantage.","example":"He had a great talent but threw it away by not practicing.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person wasting a great talent by not practicing"},{"definition":"To speak casually or unintentionally (a \"throwaway\" comment).","example":"He threw away a comment about retiring next year, but nobody noticed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person making a casual throwaway comment that nobody noticed"}]},{"particle":"back","storageKeyPrefix":"throwBack","meanings":[{"definition":"To drink something quickly (usually alcohol).","example":"He threw back a shot of whiskey and left the bar.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly throwing back a shot of whiskey at a bar"},{"definition":"To revert to or resemble an earlier time or type (often a noun: \"throwback\").","example":"Her fashion style throws back to the 1980s.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person whose fashion style throws back to the 1980s"},{"definition":"To delay or impede progress.","example":"The bad weather threw back their construction schedule by two weeks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bad weather throwing back a construction schedule by two weeks"},{"definition":"To be forced to rely on something (often \"throw back on\").","example":"When his business failed, he was thrown back on his savings.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person forced to rely on savings after business failure"}]},{"particle":"down","storageKeyPrefix":"throwDown","meanings":[{"definition":"To drop or push someone or something to the ground violently or abruptly.","example":"He threw down his pen in frustration and walked out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing down their pen in frustration and walking out"},{"definition":"To issue a challenge (often \"throw down the gauntlet\").","example":"The opposing team threw down a challenge we couldn''t ignore.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Opposing team throwing down a challenge that cannot be ignored"}]},{"particle":"in","storageKeyPrefix":"throwIn","meanings":[{"definition":"To include something extra for free with a purchase.","example":"If you buy the laptop today, we''ll throw in a carrying case.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Salesperson throwing in a carrying case with a laptop purchase"},{"definition":"To interject or add a remark to a conversation.","example":"He threw in a joke to lighten the mood.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing in a joke to lighten the mood"},{"definition":"To surrender or give up (often \"throw in the towel\").","example":"After three failed attempts to fix the engine, he finally threw in the towel.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person finally throwing in the towel after three failed attempts to fix the engine"}]},{"particle":"into","storageKeyPrefix":"throwInto","meanings":[{"definition":"To force a person, group, or place into a specific, usually negative, condition.","example":"The sudden power outage threw the entire city into chaos.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sudden power outage throwing an entire city into chaos"},{"definition":"To engage enthusiastically in a task (usually \"throw oneself into\").","example":"After the breakup, she threw herself into her work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing herself into work after a breakup"}]},{"particle":"off","storageKeyPrefix":"throwOff","meanings":[{"definition":"To remove quickly or carelessly (clothing).","example":"She threw off her heavy winter coat as soon as she entered the house.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing off their heavy winter coat upon entering the house"},{"definition":"To free oneself from something negative (illness, trouble, restraint).","example":"I can''t seem to throw off this cold; I''ve had it for weeks.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person unable to throw off a lingering cold"},{"definition":"To confuse, distract, or mislead someone.","example":"The unexpected question during the interview really threw me off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Candidate thrown off by an unexpected interview question"},{"definition":"To emit or radiate (heat, light, smell).","example":"That old radiator throws off a surprising amount of heat.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Old radiator throwing off a surprising amount of heat"}]},{"particle":"on","storageKeyPrefix":"throwOn","meanings":[{"definition":"To put on quickly or hastily (clothing).","example":"I just threw on a pair of jeans and ran to the grocery store.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly throwing on jeans and running to the grocery store"}]},{"particle":"out","storageKeyPrefix":"throwOut","meanings":[{"definition":"To discard or dispose of something as trash.","example":"It''s time to throw out all these old magazines.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing out a collection of old magazines"},{"definition":"To evict or expel someone from a place.","example":"The bouncer threw them out of the club for fighting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bouncer throwing troublemakers out of a club"},{"definition":"To reject or dismiss (a plan, idea, or legal case).","example":"The judge threw out the lawsuit due to a lack of evidence.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Judge throwing out a lawsuit due to a lack of evidence"},{"definition":"To emit or radiate (light, heat, smoke).","example":"The fireplace throws out a lot of warmth.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Fireplace throwing out a lot of warmth"},{"definition":"To offer an idea or suggestion for consideration.","example":"Let me just throw this idea out and see what you think.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing out an idea for the team to consider"},{"definition":"To confuse someone or cause them to make a mistake (chiefly British).","example":"The loud music threw me out while I was trying to count the money.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person thrown out by loud music while trying to count money"}]},{"particle":"over","storageKeyPrefix":"throwOver","meanings":[{"definition":"To abandon, reject, or leave someone (especially a romantic partner).","example":"She threw him over for a wealthy businessman.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being thrown over for a wealthy businessman"},{"definition":"To abandon a plan or idea.","example":"We had to throw over our original strategy when the budget was cut.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team throwing over their original strategy after budget cuts"}]},{"particle":"together","storageKeyPrefix":"throwTogether","meanings":[{"definition":"To make, prepare, or assemble something quickly or hastily.","example":"I didn''t have much time, so I just threw together a quick salad.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly throwing together a salad with limited time"},{"definition":"To force people to associate with each other due to circumstances.","example":"The blizzard threw the stranded passengers together for the night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Blizzard throwing stranded passengers together for the night"}]},{"particle":"up","storageKeyPrefix":"throwUp","meanings":[{"definition":"To vomit.","example":"The turbulent flight made him throw up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person feeling sick from a turbulent flight"},{"definition":"To produce, reveal, or bring to light (ideas, problems, results).","example":"The data analysis threw up some very interesting anomalies.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Data analysis throwing up interesting anomalies"},{"definition":"To build or construct something hastily.","example":"They threw up a temporary fence to keep the dogs out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"People hastily throwing up a temporary fence to keep dogs out"},{"definition":"To quit or abandon (a job or position) suddenly.","example":"She threw up her corporate career to travel the world.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person throwing up their corporate career to travel the world"},{"definition":"To cause something (like dust or water) to rise into the air.","example":"The speeding truck threw up a massive cloud of dust.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Speeding truck throwing up a massive cloud of dust"}]}]'::jsonb),
  ('try', 'Try', '["back","for","on","out","out for","over"]'::jsonb, '[{"particle":"back","storageKeyPrefix":"tryBack","meanings":[{"definition":"To make another attempt to contact someone or return to a place at a later time because the first attempt was unsuccessful.","example":"The hiring manager is currently stuck in a meeting; I''ll try back in an hour.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person trying to contact someone again after an unsuccessful first attempt"}]},{"particle":"for","storageKeyPrefix":"tryFor","meanings":[{"definition":"To make a concerted effort to achieve, win, or obtain something, often when success is not guaranteed.","example":"After updating his professional profile, Sam decided to try for the Senior Recruitment Coordinator position.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person making a concerted effort to achieve a goal"}]},{"particle":"on","storageKeyPrefix":"tryOn","meanings":[{"definition":"To put on an item of clothing or accessories to see if it fits or looks good before buying or wearing it.","example":"I need to try on this blazer to make sure it looks professional for the client meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person trying on a blazer in a shop before buying it"},{"definition":"To attempt to deceive someone or test someone\\''s boundaries to see what you can get away with (primarily British/Australian English, \"try it on\").","example":"The candidate knew the salary cap was strict, but he still tried it on during negotiations by asking for an extra 20%.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Candidate trying it on during salary negotiations by pushing beyond the cap"}]},{"particle":"out","storageKeyPrefix":"tryOut","meanings":[{"definition":"To test something (such as a new system, tool, or method) in a practical setting to evaluate its effectiveness or performance.","example":"We decided to try out a new GitHub sourcing extension to see if it helps us find specialized DevOps talent faster.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team trying out a new GitHub sourcing extension to evaluate its performance"},{"definition":"To test an idea, pitch, or product on someone to get their reaction (try out on).","example":"Can I try out my new interview script on you before I call the first applicant?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person trying out a new interview script on a colleague for feedback"}]},{"particle":"out for","storageKeyPrefix":"tryOutFor","meanings":[{"definition":"To undergo a competitive evaluation, audition, or test to earn a position on a team, in a play, or in a company.","example":"Several junior developers are going to try out for the lead engineering vacancy by submitting technical assessments.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Junior developers trying out for a lead engineering position"}]},{"particle":"over","storageKeyPrefix":"tryOver","meanings":[{"definition":"To practice, rehearse, or run through something from beginning to end to check for flaws (slightly dated, most commonly used with music or speeches).","example":"Let''s try over the presentation one more time before the stakeholders arrive.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team trying over a presentation one more time before stakeholders arrive"}]}]'::jsonb),
  ('turn', 'Turn', '["about","against","around / round","away","back","down","in","into","off","on","out","over","to","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"turnAbout","meanings":[{"definition":"To physically turn to face the opposite direction.","example":"The soldier turned about and marched away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Soldier turning to face the opposite direction"}]},{"particle":"against","storageKeyPrefix":"turnAgainst","meanings":[{"definition":"To suddenly become hostile toward someone or something.","example":"The public turned against the mayor after the scandal broke.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Public becoming hostile toward the mayor after a scandal"},{"definition":"To cause someone to be hostile toward another person.","example":"She tried to turn the team against their new manager.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person trying to turn a team against their new manager"}]},{"particle":"around / round","storageKeyPrefix":"turnAround","meanings":[{"definition":"To change direction and face the opposite way.","example":"Turn around and look at the camera.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning around to face the camera"},{"definition":"To dramatically improve a bad situation or make a failing business successful.","example":"The new CEO managed to turn the struggling company around in just two years.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"CEO turning around a struggling company in two years"},{"definition":"To complete a piece of work or fulfill a request within a specific timeframe.","example":"We can turn this project around by Friday afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team completing a project turnaround by Friday"}]},{"particle":"away","storageKeyPrefix":"turnAway","meanings":[{"definition":"To refuse someone entry or admittance.","example":"The bouncer turned us away because the club was at full capacity.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bouncer turning people away from a full club"},{"definition":"To look in a different direction, often out of disgust, shame, or lack of interest.","example":"The movie scene was so gruesome that I had to turn away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning away from a gruesome movie scene"}]},{"particle":"back","storageKeyPrefix":"turnBack","meanings":[{"definition":"To return the way you came, usually because of a problem.","example":"The snowstorm was so heavy that we had to turn back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Travellers turning back due to a heavy snowstorm"},{"definition":"To reverse a process or return to a previous state.","example":"We''ve come too far to turn back the clock now.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person unable to turn back the clock on progress"},{"definition":"To fold back a cover or page.","example":"Turn back the first page to see the dedication.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person folding back the first page of a book"}]},{"particle":"down","storageKeyPrefix":"turnDown","meanings":[{"definition":"To decrease the volume, heat, or power of a device.","example":"Please turn down the music; it''s too loud.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning down loud music"},{"definition":"To reject or refuse an offer, request, or person.","example":"She turned down the job offer because the salary was too low.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning down a job offer due to low salary"},{"definition":"To fold down the covers of a bed in preparation for sleep.","example":"The hotel staff turned down the bed while we were at dinner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hotel staff turning down the bed covers"}]},{"particle":"in","storageKeyPrefix":"turnIn","meanings":[{"definition":"To submit an assignment, report, or document.","example":"Don''t forget to turn in your paperwork by the end of the day.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning in paperwork by end of day"},{"definition":"To go to bed (informal).","example":"I''m exhausted; I think I''ll turn in early tonight.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Tired person turning in early for the night"},{"definition":"To surrender to the authorities or police.","example":"The fugitive finally turned himself in after a week on the run.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Fugitive turning himself in to the police"},{"definition":"To produce a particular amount or degree of something (like a performance).","example":"The team turned in an outstanding performance during the final match.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team turning in an outstanding performance in the final"}]},{"particle":"into","storageKeyPrefix":"turnInto","meanings":[{"definition":"To transform or change into something completely different.","example":"The caterpillar turned into a beautiful butterfly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Caterpillar transforming into a butterfly"},{"definition":"To direct a vehicle into a specific space or road.","example":"He turned into the driveway and parked the car.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driver turning into a driveway to park"}]},{"particle":"off","storageKeyPrefix":"turnOff","meanings":[{"definition":"To stop a machine, device, or flow of power.","example":"Remember to turn off the lights when you leave the room.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning off the lights when leaving a room"},{"definition":"To cause someone to lose interest, enthusiasm, or sexual arousal.","example":"His arrogance is a massive turn-off for me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turned off by someone else\\''s arrogance"},{"definition":"To leave a road or path to go onto another.","example":"We need to turn off the highway at the next exit.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Driver turning off the highway at an exit"}]},{"particle":"on","storageKeyPrefix":"turnOn","meanings":[{"definition":"To start a machine, device, or flow of power.","example":"Can you turn on the air conditioning?","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning on the air conditioning"},{"definition":"To suddenly and unexpectedly attack someone, physically or verbally.","example":"The previously friendly dog suddenly turned on the stranger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dog suddenly turning on a stranger"},{"definition":"To cause someone to feel excited or sexually aroused.","example":"Confidence is a trait that really turns people on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Confident person attracting others"},{"definition":"To depend or hinge entirely on a specific detail.","example":"The entire legal case turns on the forensic evidence.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Legal case hinging on forensic evidence"}]},{"particle":"out","storageKeyPrefix":"turnOut","meanings":[{"definition":"To end up or result in a particular way.","example":"Despite the rain, the outdoor party turned out to be a great success.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Outdoor party turning out to be a success despite rain"},{"definition":"To attend an event or gather as a crowd.","example":"A massive crowd turned out for the free concert in the park.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Massive crowd turning out for a free concert"},{"definition":"To extinguish a light.","example":"Turn out the lights before you go to sleep.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning out the lights before sleeping"},{"definition":"To produce or manufacture something.","example":"That factory turns out over five hundred cars a day.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Factory turning out five hundred cars a day"},{"definition":"To empty one''s pockets or a receptacle.","example":"The security guard asked him to turn out his pockets.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Security guard asking someone to turn out their pockets"}]},{"particle":"over","storageKeyPrefix":"turnOver","meanings":[{"definition":"To flip something so the other side faces up.","example":"If your pancakes are bubbling, it''s time to turn them over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person flipping pancakes when they start bubbling"},{"definition":"To transfer control, responsibility, or possession to someone else.","example":"He turned the business over to his daughter when he retired.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Business owner transferring control to his daughter"},{"definition":"To start an engine (referring to the mechanical rotation).","example":"The battery was dead, so the engine wouldn''t even turn over.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dead car battery preventing the engine from turning over"},{"definition":"To generate a specific amount of revenue in a business.","example":"The retail store turns over a million dollars annually.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Retail store generating a million dollars in annual turnover"},{"definition":"To think about a concept or idea carefully.","example":"She turned the idea over in her mind before giving an answer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person carefully turning an idea over in their mind"}]},{"particle":"to","storageKeyPrefix":"turnTo","meanings":[{"definition":"To go to someone or something for help, advice, or comfort.","example":"When I have a problem, I always turn to my best friend.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning to their best friend for help"},{"definition":"To start doing a particular activity or habit, often a negative one, to cope with stress.","example":"He turned to drinking after he lost his job.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning to drinking after losing their job"},{"definition":"To direct your attention to a new topic or to a specific page.","example":"Let''s turn to page 42 in the textbook.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Students turning to a specific page in the textbook"}]},{"particle":"up","storageKeyPrefix":"turnUp","meanings":[{"definition":"To increase the volume, heat, or power of a device.","example":"Can you turn up the radio? I love this song.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning up the radio volume"},{"definition":"To appear unexpectedly or arrive, sometimes late.","example":"He turned up at the party completely uninvited.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person turning up uninvited at a party"},{"definition":"To be found, usually by accident, after being lost.","example":"Don''t worry, your missing keys will turn up eventually.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Missing keys turning up after being lost"},{"definition":"To shorten a garment by folding the hem upward.","example":"I bought these trousers, but they are too long and need to be turned up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Tailor turning up the hem of trousers"}]}]'::jsonb),
  ('use', 'Use', '["against","to / used to","up"]'::jsonb, '[{"particle":"against","storageKeyPrefix":"useAgainst","meanings":[{"definition":"To utilize information, evidence, or a person\\''s trait to harm, manipulate, or gain an advantage over them.","example":"You have the right to remain silent; anything you say can and will be used against you in a court of law.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Right to remain silent; anything said can be used against you in a court of law"}]},{"particle":"to / used to","storageKeyPrefix":"useTo","meanings":[{"definition":"Indicates an action done regularly in the past but no longer done, or a past state that no longer exists.","example":"I used to play the piano every day when I was a child.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child who used to play piano every day"},{"definition":"To be familiar with something so it no longer seems new, strange, or difficult (be/get used to).","example":"It took me a few months, but I am finally used to waking up at 5:00 AM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person finally used to waking up at 5:00 AM after a few months"}]},{"particle":"up","storageKeyPrefix":"useUp","meanings":[{"definition":"To consume entirely, expending the entirety of a supply, resource, or material so that nothing is left.","example":"We need to use up all the fresh vegetables in the fridge before they spoil.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Using up all fresh vegetables in the fridge before they spoil"},{"definition":"To drain someone of their energy, strength, or usefulness (often passive).","example":"After working three double shifts in a row, he felt completely used up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person feeling completely used up after working three double shifts in a row"}]}]'::jsonb),
  ('wake', 'Wake', '["to","up","up to"]'::jsonb, '[{"particle":"to","storageKeyPrefix":"wakeTo","meanings":[{"definition":"To stop sleeping and immediately find a specific condition, sound, or situation greeting you.","example":"We woke to the sound of birds singing outside the window.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Waking to the sound of birds singing outside the window"},{"definition":"To become aware of a fact or responsibility (literary).","example":"Society is slowly waking to the severe impacts of climate change.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Society slowly waking to the severe impacts of climate change"}]},{"particle":"up","storageKeyPrefix":"wakeUp","meanings":[{"definition":"To transition naturally from sleep to an awake state.","example":"I usually wake up at 6:30 AM without an alarm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person waking up at 6:30 AM without an alarm"},{"definition":"To rouse another person, animal, or system from sleep.","example":"Please wake me up when the train gets to London.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Asking someone to wake you up when the train gets to London"},{"definition":"To stop being inattentive or oblivious and start paying attention to responsibilities.","example":"The team was playing terribly, but they finally woke up in the second half and won the game.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team finally waking up in the second half and winning the game"},{"definition":"To inject energy, excitement, or activity into a dull environment or event.","example":"We need to hire a better DJ to wake this party up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hiring a better DJ to wake the party up"}]},{"particle":"up to","storageKeyPrefix":"wakeUpTo","meanings":[{"definition":"To finally realize or understand a fact, condition, or danger that one was previously ignoring or failing to notice.","example":"The company''s board needs to wake up to the fact that their competitors are innovating faster.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Company''s board needing to wake up to the fact that competitors are innovating faster"}]}]'::jsonb),
  ('warm', 'Warm', '["down","over","through","to","up"]'::jsonb, '[{"particle":"down","storageKeyPrefix":"warmDown","meanings":[{"definition":"To perform gentle exercises or stretches after vigorous physical activity to help the body recover (British English).","example":"After testing out the new 20-inch bike on the trail, make sure to walk for a bit to warm down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warming down after exercise by walking"}]},{"particle":"over","storageKeyPrefix":"warmOver","meanings":[{"definition":"To reheat cooked food (North American English, synonymous with warm up).","example":"We can just warm over last night''s dinner.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warming over last night''s dinner"},{"definition":"To present an old idea or strategy as if it were new or original, usually with a negative connotation (as the adjective warmed-over).","example":"The agency pitched us a new sourcing strategy, but it was just a warmed-over version of what we did in 2024.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Agency pitching a warmed-over strategy as new"}]},{"particle":"through","storageKeyPrefix":"warmThrough","meanings":[{"definition":"To heat food gently until it is warm right to the middle without cooking it further or changing its texture.","example":"Just put the tortillas in the oven for a few minutes to warm through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warming tortillas through in the oven"}]},{"particle":"to","storageKeyPrefix":"warmTo","meanings":[{"definition":"To begin to like someone or something after initial hesitation or doubt (often warm up to).","example":"I wasn''t sure about the Adizes PAEI management model at first, but I''m really warming to it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warming to the Adizes PAEI management model"},{"definition":"To become interested in or enthusiastic about an idea or topic.","example":"The executive team is finally warming to the idea of reopening the individual entrepreneurship structure.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Executive team warming to the idea of reopening entrepreneurship structure"}]},{"particle":"up","storageKeyPrefix":"warmUp","meanings":[{"definition":"To increase in temperature or make someone or something warmer.","example":"Let''s step inside the cafe to warm up; the wind is freezing today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Stepping inside the cafe to warm up from the freezing wind"},{"definition":"To prepare for an activity, event, or performance by practicing or doing gentle exercises.","example":"I usually warm up with some simple coding exercises before jumping into heavy software development.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warming up with coding exercises before heavy software development"},{"definition":"To become more animated, relaxed, or friendly in a social or professional setting.","example":"The candidate was nervous at first, but she warmed up after we started discussing her GitHub projects.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Candidate warming up during discussion of GitHub projects"},{"definition":"To reheat food that has already been cooked.","example":"I''ll warm up the leftover pierogi for lunch.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warming up leftover pierogi for lunch"},{"definition":"To leave a machine running for a short time until it reaches its optimal operating temperature.","example":"Give the car a minute to warm up before we drive off.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Giving the car a minute to warm up before driving off"}]}]'::jsonb),
  ('watch', 'Watch', '["back","for","on","out","out for","over","through"]'::jsonb, '[{"particle":"back","storageKeyPrefix":"watchBack","meanings":[{"definition":"To view a video, film, or recording of a previous event, often for review or analysis.","example":"We recorded the interview so we could watch it back later and take notes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Watching back a recorded interview for review"}]},{"particle":"for","storageKeyPrefix":"watchFor","meanings":[{"definition":"To look actively for a sign, event, or specific thing to happen.","example":"Keep driving, and watch for the exit sign just past the bridge.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Watching for an exit sign while driving"}]},{"particle":"on","storageKeyPrefix":"watchOn","meanings":[{"definition":"To observe something happening, often dramatic or serious, without becoming actively involved.","example":"A large crowd gathered and watched on in shock as the building burned.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Crowd watching on in shock as a building burns"}]},{"particle":"out","storageKeyPrefix":"watchOut","meanings":[{"definition":"To be careful and pay attention to immediate danger (usually used as an exclamation or warning).","example":"Watch out! There is a car coming right at us.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Warning to watch out for an oncoming car"}]},{"particle":"out for","storageKeyPrefix":"watchOutFor","meanings":[{"definition":"To be alert to the danger or presence of something or someone.","example":"If you go hiking in those woods, watch out for bears.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Watching out for bears while hiking in the woods"},{"definition":"To protect someone or look after their best interests.","example":"Older siblings usually watch out for the younger ones at school.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Older siblings watching out for younger ones at school"},{"definition":"To wait expectantly for something to arrive or appear.","example":"Watch out for the postman; I am expecting an important package today.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Watching out for the postman while expecting a package"}]},{"particle":"over","storageKeyPrefix":"watchOver","meanings":[{"definition":"To protect, guard, or care for someone or something.","example":"The shepherd watched over his flock of sheep through the night.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Shepherd watching over his flock of sheep through the night"},{"definition":"To strictly supervise someone or an activity to ensure it is done correctly.","example":"The manager stood at the back of the room and watched over the new employees as they worked.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager watching over new employees as they work"}]},{"particle":"through","storageKeyPrefix":"watchThrough","meanings":[{"definition":"To watch a program, movie, or series entirely from beginning to end.","example":"It took me a whole weekend, but I finally watched the series through.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Watching a series through over a whole weekend"}]}]'::jsonb),
  ('wear', 'Wear', '["away","down","in","off","on","out","through"]'::jsonb, '[{"particle":"away","storageKeyPrefix":"wearAway","meanings":[{"definition":"To erode or cause something to gradually disappear, thin, or become smooth through continuous friction, use, or weather.","example":"Years of salty sea breezes have worn away the bright paint on the older coastal buildings.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Coastal buildings with paint worn away by salty sea breezes"}]},{"particle":"down","storageKeyPrefix":"wearDown","meanings":[{"definition":"To overcome someone\\''s resistance, opposition, or reluctance through persistent pressure.","example":"The developer initially wanted a much higher salary, but the long negotiation process eventually wore them down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer worn down during a long salary negotiation"},{"definition":"To reduce the size, thickness, or effectiveness of something by continuous friction or prolonged use.","example":"The treads on the 20-inch bicycle tires were completely worn down from a summer of heavy riding.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bicycle tires worn down from heavy summer riding"}]},{"particle":"in","storageKeyPrefix":"wearIn","meanings":[{"definition":"To wear new clothing, especially stiff shoes or boots, until they conform to your body and become comfortable to use.","example":"I need to walk around the apartment for a few days to wear in these new shoes before we do any serious walking.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Wearing in new shoes by walking around the apartment"}]},{"particle":"off","storageKeyPrefix":"wearOff","meanings":[{"definition":"To gradually disappear, fade, or stop having an effect, usually referring to a feeling, a drug\\''s effect, or a novelty.","example":"The excitement of moving to a new country can start to wear off once the heavy paperwork begins.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Excitement of moving to a new country wearing off with paperwork"}]},{"particle":"on","storageKeyPrefix":"wearOn","meanings":[{"definition":"Of time or an event: to pass, especially when it feels slow, tedious, or prolonged.","example":"As the technical interview wore on, it became clear the applicant didn\\''t actually have the required Java experience.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"A technical interview wearing on as the applicant struggles"},{"definition":"To gradually annoy, irritate, or exhaust someone\\''s patience over time.","example":"The constant noise from the street below started to wear on Sam as the afternoon progressed.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Constant street noise wearing on someone\\''s patience"}]},{"particle":"out","storageKeyPrefix":"wearOut","meanings":[{"definition":"To use something until it is damaged, broken, or completely useless.","example":"I\\''ve practically worn out my laptop\\''s keyboard from typing so many outreach messages.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Laptop keyboard worn out from heavy typing"},{"definition":"To make someone extremely physically or mentally tired; to exhaust.","example":"Coordinating two young children\\''s daily schedules while managing full-time work can really wear you out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Parent worn out from managing children and full-time work"}]},{"particle":"through","storageKeyPrefix":"wearThrough","meanings":[{"definition":"To create a hole in something as a result of continuous use, friction, or rubbing.","example":"She leaned on her desk so much that she completely wore through the elbows of her favourite sweater.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sweater with elbows worn through from leaning on a desk"}]}]'::jsonb),
  ('work', 'Work', '["against","ahead","around / round","away","back","down","for","in","into","off","on","out","over","through","to","together","up","with"]'::jsonb, '[{"particle":"against","storageKeyPrefix":"workAgainst","meanings":[{"definition":"To make it harder for someone to succeed; to act as a disadvantage.","example":"His lack of formal experience might work against him in the interview.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person facing disadvantage during a job interview due to lack of experience"}]},{"particle":"ahead","storageKeyPrefix":"workAhead","meanings":[{"definition":"To complete tasks before they are due or scheduled.","example":"Whenever I have free time, I try to work ahead on my assignments.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student working ahead on assignments during free time"}]},{"particle":"around / round","storageKeyPrefix":"workAround","meanings":[{"definition":"To find a way to bypass or overcome an obstacle without actually fixing the core issue (giving the noun: workaround).","example":"The software has a bug, but we found a way to work around it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Developer finding a workaround for a software bug"},{"definition":"To schedule or arrange plans to accommodate someone else''s constraints.","example":"Tell me when you are free, and I will work around your schedule.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Calendar arranged to accommodate someone else''s schedule"}]},{"particle":"away","storageKeyPrefix":"workAway","meanings":[{"definition":"To continue working hard and diligently for a sustained period.","example":"She was happily working away at her desk all afternoon.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee working away diligently at a desk all afternoon"}]},{"particle":"back","storageKeyPrefix":"workBack","meanings":[{"definition":"To start from an end result or deadline and calculate backwards to determine when to begin.","example":"If the project is due on Friday, we need to work back to see when we must start.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Timeline worked back from a Friday project deadline"}]},{"particle":"down","storageKeyPrefix":"workDown","meanings":[{"definition":"To gradually reduce something or progress downwards systematically, often through a list or pile.","example":"I have a huge stack of files; I''m just going to start at the top and work down.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person working down through a large stack of files"}]},{"particle":"for","storageKeyPrefix":"workFor","meanings":[{"definition":"To be employed by a person or organization.","example":"I work for an IT consultancy firm.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee working for an IT consultancy firm"},{"definition":"To be suitable, convenient, or effective for someone''s needs.","example":"Meeting at 10 AM doesn''t work for me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person indicating a meeting time doesn''t work for their schedule"}]},{"particle":"in","storageKeyPrefix":"workIn","meanings":[{"definition":"To make time or space for something or someone in a busy schedule.","example":"My schedule is packed, but I can work a quick meeting in at 3:00 PM.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Busy calendar with a quick meeting worked in at 3:00 PM"},{"definition":"To mix a substance into another substance thoroughly.","example":"Gently work in the butter until the dough is crumbly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Butter being worked into dough until crumbly"}]},{"particle":"into","storageKeyPrefix":"workInto","meanings":[{"definition":"To successfully fit someone or something into a busy schedule.","example":"The dentist was able to work me into her schedule.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Dentist working a patient into a busy schedule"},{"definition":"To blend or push one material into another.","example":"Work the lotion into your skin.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lotion being worked into skin"},{"definition":"To gradually reach a certain emotional state, usually negative.","example":"He managed to work himself into a frenzy.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person working themselves into a frenzy"}]},{"particle":"off","storageKeyPrefix":"workOff","meanings":[{"definition":"To eliminate something like stress, anger, or calories through physical activity.","example":"After a frustrating meeting, I went to the gym to work off my anger.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person going to the gym to work off anger after a frustrating meeting"},{"definition":"To repay a debt by providing labor or services instead of money.","example":"He couldn''t afford the repairs, so he offered to work off the debt by painting the mechanic''s house.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person painting a mechanic''s house to work off a repair debt"}]},{"particle":"on","storageKeyPrefix":"workOn","meanings":[{"definition":"To spend time repairing, improving, or developing something.","example":"She is working on her pronunciation to sound more fluent.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student working on pronunciation to sound more fluent"},{"definition":"To try to persuade or influence someone to do something.","example":"My manager doesn''t want to approve the budget, but I''ll work on him.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee trying to work on manager to approve a budget"}]},{"particle":"out","storageKeyPrefix":"workOut","meanings":[{"definition":"To exercise to improve physical fitness.","example":"I try to work out at the gym three times a week.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person working out at the gym three times a week"},{"definition":"To solve a problem or calculate an answer.","example":"Let me just work out the total cost with taxes included.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person working out the total cost with taxes on a calculator"},{"definition":"To happen or develop in a particular, usually successful, way.","example":"I was worried about the relocation, but everything worked out perfectly.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Relocation that worked out perfectly in the end"},{"definition":"To understand someone''s character or a confusing situation.","example":"He is so mysterious; I just can''t work him out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person puzzled trying to work out a mysterious person''s character"}]},{"particle":"over","storageKeyPrefix":"workOver","meanings":[{"definition":"To physically assault or beat someone up severely (informal).","example":"The gang threatened to work him over if he didn''t pay.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Gang threatening to work someone over if they do not pay"},{"definition":"To examine, treat, or revise something very thoroughly.","example":"The editors will work over the manuscript before publishing it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Editors working over a manuscript before publishing"}]},{"particle":"through","storageKeyPrefix":"workThrough","meanings":[{"definition":"To deal with, resolve, or overcome a complex problem or difficult emotion step by step.","example":"Couples counseling helped them work through their trust issues.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Couple working through trust issues in counseling"},{"definition":"To read, process, or complete a large amount of material from beginning to end.","example":"It took me three hours to work through all the emails in my inbox.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person working through a large inbox full of emails"}]},{"particle":"to","storageKeyPrefix":"workTo","meanings":[{"definition":"To operate according to a specific schedule, rule, or constraint.","example":"We are working to a very tight deadline.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team working to a very tight deadline"}]},{"particle":"together","storageKeyPrefix":"workTogether","meanings":[{"definition":"To collaborate or cooperate as a team.","example":"If we work together, we can finish this much faster.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team working together to finish a project much faster"}]},{"particle":"up","storageKeyPrefix":"workUp","meanings":[{"definition":"To gradually develop or build something, often a feeling like an appetite, courage, or sweat.","example":"We went for a long hike and worked up a huge appetite.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Hikers working up a huge appetite on a long hike"},{"definition":"To make oneself or someone else feel upset, excited, or anxious (often used in the passive: worked up).","example":"Don''t get yourself all worked up over a minor mistake.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person getting worked up over a minor mistake"},{"definition":"To gradually progress to something more advanced or demanding.","example":"Start with lighter weights and work up to the heavy ones.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Gym-goer working up from lighter weights to heavier ones"}]},{"particle":"with","storageKeyPrefix":"workWith","meanings":[{"definition":"To collaborate alongside someone.","example":"I love working with my new team.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Employee working with a new team collaboratively"},{"definition":"To use something as a tool, material, or basis for a project.","example":"Wood is a beautiful material to work with.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Craftsperson working with wood as a beautiful material"},{"definition":"To accommodate or adapt to a situation or constraint.","example":"We have a very tight budget, but we''ll try to work with it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Team trying to work with a very tight budget"}]}]'::jsonb),
  ('write', 'Write', '["about","against","around / round","away","back","down","for","in","into","off","on","out","over","through","to","up"]'::jsonb, '[{"particle":"about","storageKeyPrefix":"writeAbout","meanings":[{"definition":"To discuss a particular subject in writing.","example":"I want to write about the impact of artificial intelligence on the job market.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person writing about artificial intelligence and job market"}]},{"particle":"against","storageKeyPrefix":"writeAgainst","meanings":[{"definition":"To write essays, articles, or books opposing a specific idea, policy, or person.","example":"He spent his later years writing against the dangers of censorship.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Author writing essays opposing censorship"},{"definition":"To deduct an expense from a specific account or budget (finance).","example":"We will write the cost of the software against this quarter\\''s IT budget.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accountant deducting software cost from IT budget"}]},{"particle":"around / round","storageKeyPrefix":"writeAround","meanings":[{"definition":"To intentionally avoid addressing the main point or a difficult topic in a text.","example":"The biography is frustrating because the author writes around the politician\\''s well-known scandals.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Author avoiding difficult topics in a biography"},{"definition":"To circulate a memo or letter to a group of people (British: write round).","example":"I\\''ll write round to the committee members to see who is available.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person circulating a memo to committee members"}]},{"particle":"away","storageKeyPrefix":"writeAway","meanings":[{"definition":"To send a letter requesting something (synonymous with write off for).","example":"When I was a kid, I used to write away for x-ray glasses I saw in comic books.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Child writing away to request a toy seen in a comic book"},{"definition":"To write continuously and diligently.","example":"I left her at her desk, just writing away at her novel.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Writer working diligently at a desk on a novel"}]},{"particle":"back","storageKeyPrefix":"writeBack","meanings":[{"definition":"To reply to someone\\''s letter, email, or message.","example":"I sent him an email last week, but he still hasn\\''t written back.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person waiting for a reply to an email they sent"}]},{"particle":"down","storageKeyPrefix":"writeDown","meanings":[{"definition":"To record something on paper so it is not forgotten.","example":"Please write down my phone number before you lose it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person writing down a phone number to remember it"},{"definition":"To reduce the estimated or nominal value of an asset (finance).","example":"The company had to write down its inventory due to the sudden drop in market prices.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Accountant writing down inventory value due to market price drop"},{"definition":"To write in a condescendingly simple way (usually write down to).","example":"A good children\\''s author never writes down to their audience.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Children\\''s author writing respectfully for young readers"}]},{"particle":"for","storageKeyPrefix":"writeFor","meanings":[{"definition":"To be employed by or submit writing to a specific publication.","example":"She writes for several major technology magazines.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Journalist writing articles for technology magazines"},{"definition":"To request something by mail.","example":"You can write for a free copy of the catalog.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person writing to request a free catalog by mail"}]},{"particle":"in","storageKeyPrefix":"writeIn","meanings":[{"definition":"To send a letter or email to an organization or television station to express an opinion.","example":"Hundreds of viewers wrote in to complain about the controversial episode.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Viewers writing in to a TV station to complain"},{"definition":"To cast a vote for a candidate whose name is not on the official ballot by writing their name.","example":"Because she missed the deadline to get on the ballot, her supporters had to write her in.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Voter writing in a candidate\\''s name on a ballot"},{"definition":"To insert text into a document or form.","example":"Please write in your name and address at the top of the page.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person filling in name and address on a form"}]},{"particle":"into","storageKeyPrefix":"writeInto","meanings":[{"definition":"To formally include a specific clause, rule, or condition in a contract or script.","example":"We made sure to write a penalty clause into the agreement to protect our investment.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Lawyer writing a penalty clause into a contract"}]},{"particle":"off","storageKeyPrefix":"writeOff","meanings":[{"definition":"To cancel a bad debt or accept a financial loss.","example":"The bank decided to write off the unpaid loan.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Bank official writing off an unpaid loan"},{"definition":"To decide that someone or something is useless, unimportant, or a failure.","example":"He had a bad first semester, but don\\''t write him off just yet; he is improving.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Teacher encouraging a struggling student not to be written off"},{"definition":"To damage a vehicle so badly that it cannot be repaired (British/Commonwealth).","example":"She lost control on the ice and completely wrote off her car.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Damaged car after an accident on icy road"},{"definition":"To deduct an expense to reduce taxable income.","example":"You can write off the cost of your home office on your taxes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person deducting home office expenses on tax return"},{"definition":"To send a letter requesting something (often write off for).","example":"I wrote off for a free sample of the new moisturizer.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person writing off for a free product sample"}]},{"particle":"on","storageKeyPrefix":"writeOn","meanings":[{"definition":"To write about a specific topic or subject (formal/academic).","example":"Professor Smith writes primarily on medieval European history.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Professor writing academic works on medieval European history"},{"definition":"To continue writing despite distractions or obstacles.","example":"Despite the noise in the cafe, she just put her headphones in and wrote on.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Writer with headphones continuing to write in a noisy cafe"}]},{"particle":"out","storageKeyPrefix":"writeOut","meanings":[{"definition":"To write something completely in full rather than using abbreviations or numbers.","example":"You need to write out the numbers one through ten, but you can use digits for 11 and up.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student writing numbers out in full on a worksheet"},{"definition":"To remove a character from a television series by not including them in future scripts.","example":"When the actor decided to leave the show, the writers wrote him out by having his character move to Paris.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"TV writers discussing how to write out a departing character"},{"definition":"To fill in all the necessary details on a document such as a check or prescription.","example":"The doctor wrote out a prescription for antibiotics.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Doctor writing out a prescription for a patient"}]},{"particle":"over","storageKeyPrefix":"writeOver","meanings":[{"definition":"To replace old computer data with new data; to overwrite.","example":"Be careful when saving the document, or you might write over yesterday\\''s work.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person carefully saving a document to avoid overwriting old work"}]},{"particle":"through","storageKeyPrefix":"writeThrough","meanings":[{"definition":"To revise a piece of writing completely from beginning to end (journalism/editing).","example":"The editor told the reporter to write through the draft to make the narrative flow better.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Editor reviewing a draft and asking the reporter to revise it fully"}]},{"particle":"to","storageKeyPrefix":"writeTo","meanings":[{"definition":"To send a written message or letter to a specific person or entity.","example":"I write to my grandmother at least once a month.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person writing a letter to their grandmother each month"},{"definition":"To target a piece of writing toward a specific demographic.","example":"It\\''s hard to write to a teenage audience without sounding inauthentic.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Author trying to write authentically for a teenage audience"}]},{"particle":"up","storageKeyPrefix":"writeUp","meanings":[{"definition":"To produce a formal, complete written document based on notes or a draft.","example":"Give me an hour to write up the minutes from our meeting.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person writing up meeting minutes from notes"},{"definition":"To officially record someone\\''s poor performance or rule violation in a disciplinary file.","example":"The manager wrote him up for arriving late three days in a row.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Manager recording an employee\\''s repeated tardiness in a disciplinary file"},{"definition":"To publish a review or article praising someone or something.","example":"The local newspaper wrote up the new restaurant in their weekend edition.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Journalist writing a positive review of a new restaurant"},{"definition":"To artificially increase the recorded, nominal value of an asset (finance).","example":"The corporation wrote up the value of its real estate portfolio.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Financial analyst writing up the value of a real estate portfolio"}]}]'::jsonb),
  ('zip', 'Zip', '["about / around / round","across","ahead","apart","away","back","by","down","in","into","off","on","out","over","through","to","together","up"]'::jsonb, '[{"particle":"about / around / round","storageKeyPrefix":"zipAbout","meanings":[{"definition":"To move quickly and energetically from one place to another within an area.","example":"She spent the entire Saturday zipping around town running errands.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person moving quickly around town running errands"}]},{"particle":"across","storageKeyPrefix":"zipAcross","meanings":[{"definition":"To travel very rapidly from one side of a space, surface, or area to the other.","example":"The speedboat zipped across the lake in under a minute.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Speedboat zipping rapidly across a lake"}]},{"particle":"ahead","storageKeyPrefix":"zipAhead","meanings":[{"definition":"To advance quickly, often leaving others behind or moving to the front of a line or progression.","example":"He zipped ahead of the rest of the runners in the final lap.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Runner zipping ahead of others in the final lap"}]},{"particle":"apart","storageKeyPrefix":"zipApart","meanings":[{"definition":"To separate two pieces of fabric or material by opening a zipper that connects them.","example":"These convertible hiking pants zip apart at the knee to become shorts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Convertible hiking pants zipping apart at the knee"}]},{"particle":"away","storageKeyPrefix":"zipAway","meanings":[{"definition":"To depart or move away very rapidly.","example":"As soon as the light turned green, the sports car zipped away.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Sports car zipping away as traffic light turns green"}]},{"particle":"back","storageKeyPrefix":"zipBack","meanings":[{"definition":"To return to a place very quickly for a short duration.","example":"I just need to zip back to the office to grab my laptop.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly returning to the office to grab a laptop"}]},{"particle":"by","storageKeyPrefix":"zipBy","meanings":[{"definition":"To physically pass someone or something very quickly.","example":"A cyclist zipped by me on the trail and nearly startled me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Cyclist zipping by a pedestrian on a trail"},{"definition":"Of time: to pass very quickly.","example":"The summer holidays just seemed to zip by this year.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Calendar pages flying by representing summer holidays passing quickly"}]},{"particle":"down","storageKeyPrefix":"zipDown","meanings":[{"definition":"To unfasten a zipper by moving it in a downward direction.","example":"He zipped down his jacket because the sun came out.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person unzipping their jacket downward as the sun comes out"},{"definition":"To travel quickly down a path, road, or digital page.","example":"Let me just zip down to the bottom of this document to check the signature line.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly scrolling to the bottom of a document"}]},{"particle":"in","storageKeyPrefix":"zipIn","meanings":[{"definition":"To arrive or enter a place very quickly.","example":"I''ll zip in and grab a coffee before the meeting starts.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly entering a coffee shop before a meeting"},{"definition":"To attach an inner lining to a larger garment using a zipper.","example":"You can zip in the fleece lining to make the raincoat suitable for winter.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person zipping a fleece lining into a raincoat for winter"}]},{"particle":"into","storageKeyPrefix":"zipInto","meanings":[{"definition":"To put on a piece of clothing rapidly.","example":"She zipped into her wetsuit and ran toward the ocean.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Swimmer quickly putting on a wetsuit and running toward the ocean"},{"definition":"To maneuver a vehicle or oneself into a space quickly.","example":"He zipped into the parking spot right before the other driver could take it.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Car quickly maneuvering into a parking spot"}]},{"particle":"off","storageKeyPrefix":"zipOff","meanings":[{"definition":"To leave or depart quickly in a hurry.","example":"I have to zip off to a dentist appointment now, but I\\''ll call you later.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person rushing off to a dentist appointment"},{"definition":"To detach a removable part of a garment using a zipper.","example":"He zipped off the sleeves of his jacket when it got too hot.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person detaching jacket sleeves using a zipper in hot weather"}]},{"particle":"on","storageKeyPrefix":"zipOn","meanings":[{"definition":"To attach a piece of fabric or a removable garment part using a zipper.","example":"If it starts raining, you can just zip on the hood.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person attaching a hood to a jacket using a zipper"}]},{"particle":"out","storageKeyPrefix":"zipOut","meanings":[{"definition":"To go outside or leave a place for a very brief, quick errand.","example":"I''m going to zip out to the grocery store for some milk; I''ll be back in ten minutes.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly heading out to the grocery store for milk"},{"definition":"To remove an inner lining from a garment by unzipping it.","example":"Make sure you zip out the thermal layer before you put the coat in the washing machine.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person removing a thermal lining from a coat before washing"}]},{"particle":"over","storageKeyPrefix":"zipOver","meanings":[{"definition":"To travel quickly to a nearby location, often someone\\''s home or office.","example":"I''ll zip over to your place after work to drop off the tools you lent me.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person quickly travelling to a friend\\''s place to return tools"}]},{"particle":"through","storageKeyPrefix":"zipThrough","meanings":[{"definition":"To do, read, or complete a task very quickly and with ease.","example":"She zipped through the exam in half the allotted time.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Student completing an exam quickly in half the allotted time"},{"definition":"To travel through a place without stopping, or to navigate a physical space rapidly.","example":"We bypassed the traffic and zipped through the city centre.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Car navigating rapidly through the city centre avoiding traffic"}]},{"particle":"to","storageKeyPrefix":"zipTo","meanings":[{"definition":"To move rapidly to a specific destination or state.","example":"Zip to the end of the video to see the surprise reveal.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person skipping to the end of a video to see the surprise reveal"}]},{"particle":"together","storageKeyPrefix":"zipTogether","meanings":[{"definition":"To connect two separate items using their interlocking zippers.","example":"We zipped together our two sleeping bags to make one large bed for the camping trip.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Two sleeping bags being zipped together for a camping trip"}]},{"particle":"up","storageKeyPrefix":"zipUp","meanings":[{"definition":"To close a garment, bag, or tent completely by fastening its zipper.","example":"Make sure you zip up your coat; it''s freezing outside!","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person zipping up their coat in cold weather"},{"definition":"To be quiet or stop talking (slang/idiomatic, often commanded as zip it).","example":"I told him to zip up before his complaining got us into more trouble.","imageSrc":"images/phrasal_verbs/list/default.png","imageAlt":"Person being told to zip up and stop complaining"}]}]'::jsonb);
